private func boundedFailureLogToken(_ rawValue: String) -> String {
    let trimmed = rawValue.trimmingCharacters(in: .whitespacesAndNewlines)
    let allowed = CharacterSet(charactersIn: "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789._-")
    let scalars = trimmed.unicodeScalars.filter { allowed.contains($0) }
    let sanitized = String(String.UnicodeScalarView(scalars))
    guard !sanitized.isEmpty else {
        return "redacted"
    }

    return String(sanitized.prefix(64))
}

private func desktopSessionSHA256Hex(_ data: Data) -> String {
    SHA256.hash(data: data).map { String(format: "%02x", $0) }.joined()
}

private enum DesktopRealtimeTranscriptionFeatureFlag {
    static let name = "SELENE_DESKTOP_OPENAI_REALTIME_TRANSCRIPTION_ENABLED"

    static var isEnabled: Bool {
        let rawValue = ProcessInfo.processInfo.environment[name]?
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .lowercased()
        return matchesEnabled(rawValue, defaultValue: true)
    }

    private static func matchesEnabled(_ rawValue: String?, defaultValue: Bool) -> Bool {
        switch rawValue {
        case "1", "true", "yes", "on", "enabled":
            return true
        case "0", "false", "no", "off", "disabled":
            return false
        default:
            return defaultValue
        }
    }
}

private enum DesktopOpenAITtsFeatureFlag {
    static let name = "SELENE_DESKTOP_OPENAI_TTS_ENABLED"

    static var isEnabled: Bool {
        let rawValue = ProcessInfo.processInfo.environment[name]?
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .lowercased()
        switch rawValue {
        case "1", "true", "yes", "on", "enabled":
            return true
        case "0", "false", "no", "off", "disabled":
            return false
        default:
            return true
        }
    }
}

