private enum DesktopAvailabilityStatusKind: String, Equatable {
    case idleAvailable = "idle_available"
    case wakeListening = "wake_listening"
    case activeListening = "active_listening"
    case thinkingProcessing = "thinking_processing"
    case ttsPreparing = "tts_preparing"
    case speaking = "speaking"
    case sessionSleeping = "session_sleeping"
    case mutedNotListening = "muted_not_listening"
    case errorDegraded = "error_degraded"
    case hiddenAvailable = "hidden_available"
    case unavailableFailClosed = "unavailable_fail_closed"
}

private enum DesktopDockIconWord: String, Equatable {
    case ready = "Ready"
    case live = "Live"
    case open = "Open"
    case hidden = "Hidden"
    case sleep = "Sleep"

    var accentColor: NSColor {
        switch self {
        case .ready:
            return NSColor(calibratedRed: 0.10, green: 0.72, blue: 0.38, alpha: 1.0)
        case .live:
            return NSColor(calibratedRed: 0.96, green: 0.12, blue: 0.10, alpha: 1.0)
        case .open:
            return NSColor(calibratedRed: 0.11, green: 0.42, blue: 0.96, alpha: 1.0)
        case .hidden:
            return NSColor(calibratedRed: 0.05, green: 0.70, blue: 0.60, alpha: 1.0)
        case .sleep:
            return NSColor(calibratedRed: 0.43, green: 0.32, blue: 0.95, alpha: 1.0)
        }
    }
}

private struct DesktopAvailabilityEvidenceRow: Identifiable, Equatable {
    let label: String
    let value: String

    var id: String {
        "\(label)=\(value)"
    }
}

private struct DesktopAvailabilityStatusSnapshot: Equatable {
    let kind: DesktopAvailabilityStatusKind
    let detail: String
    let evidenceRows: [DesktopAvailabilityEvidenceRow]

    var id: String {
        ([kind.rawValue, detail] + evidenceRows.flatMap { [$0.label, $0.value] })
            .joined(separator: "|")
    }

    var dockIconWord: DesktopDockIconWord {
        switch kind {
        case .activeListening, .thinkingProcessing, .ttsPreparing, .speaking:
            return .live
        case .sessionSleeping:
            return .sleep
        case .hiddenAvailable:
            return .hidden
        case .idleAvailable, .wakeListening, .mutedNotListening, .errorDegraded, .unavailableFailClosed:
            break
        }

        let evidence = Dictionary(uniqueKeysWithValues: evidenceRows.map { ($0.label, $0.value) })
        if evidence["window"] == "hidden_or_minimized" {
            return .hidden
        }

        if evidence["app"] == "active" && evidence["window"] == "visible" {
            return .open
        }

        return .ready
    }
}

@MainActor
private final class DesktopDockIconPulseController: ObservableObject {
    private var originalIcon: NSImage?
    private var frames: [NSImage] = []
    private var frameIndex = 0
    private var timer: Timer?
    private var appliedAvailabilityStatusID: String?
    private var appliedDockIconWord: DesktopDockIconWord?

    func applyAvailabilityStatus(_ snapshot: DesktopAvailabilityStatusSnapshot) {
        let dockIconWord = snapshot.dockIconWord

        if appliedDockIconWord != dockIconWord || timer == nil {
            stopPulsing()
            appliedDockIconWord = dockIconWord
            startPulsing(dockIconWord)
        }

        if appliedAvailabilityStatusID != snapshot.id {
            appliedAvailabilityStatusID = snapshot.id
            desktopAppendRuntimeBridgeDebugLog(
                "desktop availability status kind=\(snapshot.kind.rawValue) dock_word=\(dockIconWord.rawValue) detail=\(boundedFailureLogToken(snapshot.detail))"
            )
        }
    }

    func clearAvailabilityStatus() {
        appliedAvailabilityStatusID = nil
        appliedDockIconWord = nil
        stopPulsing()
        NSApplication.shared.applicationIconImage = appDockIconImage() ?? originalIcon
    }

    func startPulsing(_ word: DesktopDockIconWord) {
        guard timer == nil else {
            return
        }
        originalIcon = NSApplication.shared.applicationIconImage?.copy() as? NSImage
        let baseIcon = appDockIconImage()
            ?? originalIcon
            ?? fallbackDockIconImage()
        let frameCount = 48
        frames = (0..<frameCount).map {
            renderDockIconPulseFrame(index: $0, frameCount: frameCount, baseIcon: baseIcon, word: word)
        }
        frameIndex = 0
        NSApplication.shared.applicationIconImage = frames.first
        let timer = Timer.scheduledTimer(withTimeInterval: 1.0 / 18.0, repeats: true) { [weak self] _ in
            Task { @MainActor in
                self?.advanceFrame()
            }
        }
        RunLoop.main.add(timer, forMode: .common)
        self.timer = timer
    }

    func stopPulsing() {
        timer?.invalidate()
        timer = nil
        frameIndex = 0
        NSApplication.shared.applicationIconImage = appDockIconImage() ?? originalIcon
        originalIcon = nil
        frames.removeAll()
    }

    private func advanceFrame() {
        guard !frames.isEmpty else {
            return
        }
        frameIndex = (frameIndex + 1) % frames.count
        NSApplication.shared.applicationIconImage = frames[frameIndex]
    }

    private func renderDockIconPulseFrame(
        index: Int,
        frameCount: Int,
        baseIcon: NSImage,
        word: DesktopDockIconWord
    ) -> NSImage {
        let size: CGFloat = 512
        let image = NSImage(size: NSSize(width: size, height: size))
        image.lockFocus()
        NSGraphicsContext.current?.imageInterpolation = .high

        let rect = NSRect(x: 0, y: 0, width: size, height: size)
        let iconShape = NSBezierPath(roundedRect: rect, xRadius: size * 0.22, yRadius: size * 0.22)
        NSColor.white.setFill()
        iconShape.fill()

        NSGraphicsContext.saveGraphicsState()
        iconShape.addClip()
        let loweredBaseRect = NSRect(x: 0, y: -size * 0.18, width: size, height: size)
        baseIcon.draw(
            in: loweredBaseRect,
            from: NSRect(origin: .zero, size: baseIcon.size),
            operation: .sourceOver,
            fraction: 1.0
        )
        NSGraphicsContext.restoreGraphicsState()

        let phase = Double(index) / Double(frameCount)
        let pulse = (sin(phase * Double.pi * 4.0 - Double.pi / 2.0) + 1.0) / 2.0
        let accent = word.accentColor
        let wordRect = NSRect(
            x: size * 0.035,
            y: size * 0.675,
            width: size * 0.93,
            height: size * 0.315
        )
        let wordPath = NSBezierPath(
            roundedRect: wordRect,
            xRadius: wordRect.height * 0.48,
            yRadius: wordRect.height * 0.48
        )

        NSGraphicsContext.saveGraphicsState()
        accent.withAlphaComponent(CGFloat(0.88 + 0.12 * pulse)).setFill()
        wordPath.fill()
        NSColor.white.withAlphaComponent(CGFloat(0.90 + 0.10 * pulse)).setStroke()
        wordPath.lineWidth = 7
        wordPath.stroke()

        let shadow = NSShadow()
        shadow.shadowColor = accent.withAlphaComponent(CGFloat(0.50 + 0.34 * pulse))
        shadow.shadowBlurRadius = CGFloat(24 + 12 * pulse)
        shadow.shadowOffset = .zero
        shadow.set()
        wordPath.stroke()
        NSGraphicsContext.restoreGraphicsState()

        let paragraphStyle = NSMutableParagraphStyle()
        paragraphStyle.alignment = .center
        let attributes: [NSAttributedString.Key: Any] = [
            .font: NSFont.systemFont(ofSize: 96, weight: .heavy),
            .foregroundColor: NSColor.white,
            .strokeColor: NSColor.black.withAlphaComponent(0.36),
            .strokeWidth: -3.0,
            .paragraphStyle: paragraphStyle,
            .kern: -1.0,
        ]
        let attributedWord = NSAttributedString(string: word.rawValue, attributes: attributes)
        let textSize = attributedWord.size()
        let textRect = NSRect(
            x: wordRect.minX + 8,
            y: wordRect.midY - textSize.height * 0.52,
            width: wordRect.width - 16,
            height: textSize.height + 4
        )
        attributedWord.draw(in: textRect)

        let dotSize = size * CGFloat(0.052 + 0.010 * pulse)
        let dotRect = NSRect(
            x: size * 0.5 - dotSize * 0.5,
            y: size * 0.035,
            width: dotSize,
            height: dotSize
        )
        accent.withAlphaComponent(CGFloat(0.70 + 0.25 * pulse)).setFill()
        NSBezierPath(ovalIn: dotRect).fill()

        image.unlockFocus()
        return image
    }

    private func appDockIconImage() -> NSImage? {
        guard let iconURL = Bundle.main.url(forResource: "AppIcon", withExtension: "icns") else {
            return nil
        }
        return NSImage(contentsOf: iconURL)
    }

    private func fallbackDockIconImage() -> NSImage {
        let size: CGFloat = 512
        let image = NSImage(size: NSSize(width: size, height: size))
        image.lockFocus()
        NSColor.white.setFill()
        NSBezierPath(
            roundedRect: NSRect(x: 0, y: 0, width: size, height: size),
            xRadius: size * 0.20,
            yRadius: size * 0.20
        ).fill()
        NSColor.black.withAlphaComponent(0.86).setStroke()
        let word = "Selene" as NSString
        word.draw(
            in: NSRect(x: size * 0.16, y: size * 0.42, width: size * 0.68, height: size * 0.20),
            withAttributes: [
                .font: NSFont.systemFont(ofSize: 58, weight: .medium),
                .foregroundColor: NSColor.black,
            ]
        )
        image.unlockFocus()
        return image
    }
}

private func boundedAudioCaptureToken(
    _ rawValue: String?,
    fallback: String,
    limit: Int = 96
) -> String {
    let trimmed = rawValue?
        .replacingOccurrences(of: "\n", with: " ")
        .replacingOccurrences(of: "\r", with: " ")
        .trimmingCharacters(in: .whitespacesAndNewlines)

    guard let trimmed, !trimmed.isEmpty else {
        return fallback
    }

    if trimmed.count <= limit {
        return trimmed
    }

    return String(trimmed.prefix(limit))
}

private func boundedAudioCaptureLocaleTag(_ rawValue: String?) -> String {
    let fallback = "en-US"
    let trimmed = rawValue?.trimmingCharacters(in: .whitespacesAndNewlines)

    guard let trimmed, !trimmed.isEmpty else {
        return fallback
    }

    if trimmed.count <= 32 {
        return trimmed
    }

    return String(trimmed.prefix(32))
}

private func resolvedDesktopAudioDeviceRouteLabel(
    selectedMic: String,
    selectedSpeaker: String
) -> String {
    let routeEvidence = "\(selectedMic) \(selectedSpeaker)".lowercased()

    if routeEvidence.contains("airpods")
        || routeEvidence.contains("bluetooth")
        || routeEvidence.contains("beats") {
        return "BLUETOOTH"
    }

    if routeEvidence.contains("usb")
        || routeEvidence.contains("dock")
        || routeEvidence.contains("external") {
        return "USB"
    }

    return "BUILT_IN"
}

private struct WakePrefixMatch {
    let detectionText: String
    let transcriptRemainder: String
}

private func normalizedWakeRecognitionToken(_ rawValue: String) -> String {
    let foldedValue = rawValue
        .folding(options: [.caseInsensitive, .diacriticInsensitive], locale: Locale(identifier: "en_US_POSIX"))
        .lowercased()
    var normalizedValue = ""
    for scalar in foldedValue.unicodeScalars {
        if CharacterSet.letters.contains(scalar) {
            normalizedValue.unicodeScalars.append(scalar)
        }
    }
    return normalizedValue
}

private func wakeRecognitionPhoneticToken(_ normalizedToken: String) -> String {
    guard let firstScalar = normalizedToken.unicodeScalars.first else {
        return normalizedToken
    }
    var phoneticToken = normalizedToken
    if firstScalar == UnicodeScalar("c") {
        phoneticToken.removeFirst()
        phoneticToken = "s" + phoneticToken
    }
    return phoneticToken
}

private func wakeRecognitionConsonantSkeleton(_ normalizedToken: String) -> String {
    let phoneticToken = wakeRecognitionPhoneticToken(normalizedToken)
    let vowelScalars = Set("aeiouy".unicodeScalars)
    var skeleton = ""
    for scalar in phoneticToken.unicodeScalars {
        if !vowelScalars.contains(scalar) {
            skeleton.unicodeScalars.append(scalar)
        }
    }
    return skeleton
}

private func boundedWakeRecognitionEditDistance(
    _ lhs: String,
    _ rhs: String,
    maxDistance: Int
) -> Int {
    let lhsScalars = Array(lhs.unicodeScalars)
    let rhsScalars = Array(rhs.unicodeScalars)
    if abs(lhsScalars.count - rhsScalars.count) > maxDistance {
        return maxDistance + 1
    }

    var previousRow = Array(0...rhsScalars.count)
    for (lhsIndex, lhsScalar) in lhsScalars.enumerated() {
        var currentRow = [lhsIndex + 1]
        var rowMinimum = lhsIndex + 1
        for (rhsIndex, rhsScalar) in rhsScalars.enumerated() {
            let substitutionCost = lhsScalar == rhsScalar ? 0 : 1
            let insertion = currentRow[rhsIndex] + 1
            let deletion = previousRow[rhsIndex + 1] + 1
            let substitution = previousRow[rhsIndex] + substitutionCost
            let value = min(insertion, deletion, substitution)
            currentRow.append(value)
            rowMinimum = min(rowMinimum, value)
        }
        if rowMinimum > maxDistance {
            return maxDistance + 1
        }
        previousRow = currentRow
    }
    return previousRow.last ?? maxDistance + 1
}

private func boundedWakeRecognitionTokenMatches(_ normalizedToken: String, wakeTriggerPhrase: String) -> Bool {
    let canonicalWakeToken = normalizedWakeRecognitionToken(wakeTriggerPhrase)
    guard !canonicalWakeToken.isEmpty else {
        return false
    }
    let candidateToken = wakeRecognitionPhoneticToken(normalizedToken)
    let canonicalToken = wakeRecognitionPhoneticToken(canonicalWakeToken)
    if candidateToken == canonicalToken {
        return true
    }
    guard candidateToken.count >= Swift.max(4, canonicalToken.count - 2),
          candidateToken.count <= canonicalToken.count + 2,
          candidateToken.first == canonicalToken.first else {
        return false
    }

    let candidateSkeleton = wakeRecognitionConsonantSkeleton(candidateToken)
    let canonicalSkeleton = wakeRecognitionConsonantSkeleton(canonicalToken)
    let skeletonMatches = candidateSkeleton == canonicalSkeleton
        || (
            candidateToken.count >= 5
            && candidateSkeleton.count >= 2
            && canonicalSkeleton.hasPrefix(candidateSkeleton)
        )
    guard skeletonMatches else {
        return false
    }

    return boundedWakeRecognitionEditDistance(
        candidateToken,
        canonicalToken,
        maxDistance: 3
    ) <= 3
}

private func boundedWakePrefixMatch(
    in rawTranscript: String,
    wakeTriggerPhrase: String = "Selene"
) -> WakePrefixMatch? {
    let trimmedTranscript = rawTranscript.trimmingCharacters(in: .whitespacesAndNewlines)
    guard !trimmedTranscript.isEmpty else {
        return nil
    }

    let normalizedWakeTriggerPhrase = wakeTriggerPhrase.trimmingCharacters(in: .whitespacesAndNewlines)
    guard !normalizedWakeTriggerPhrase.isEmpty else {
        return nil
    }

    let candidateTokenEndIndex = trimmedTranscript.firstIndex { character in
        !character.unicodeScalars.allSatisfy { scalar in
            CharacterSet.letters.contains(scalar)
        }
    } ?? trimmedTranscript.endIndex
    let candidateToken = String(trimmedTranscript[..<candidateTokenEndIndex])
    let normalizedCandidateToken = normalizedWakeRecognitionToken(candidateToken)
    guard !normalizedCandidateToken.isEmpty,
          boundedWakeRecognitionTokenMatches(
            normalizedCandidateToken,
            wakeTriggerPhrase: normalizedWakeTriggerPhrase
          ) else {
        return nil
    }

    let suffix = String(trimmedTranscript[candidateTokenEndIndex...])
    guard let firstScalar = suffix.unicodeScalars.first else {
        return WakePrefixMatch(
            detectionText: normalizedWakeTriggerPhrase,
            transcriptRemainder: ""
        )
    }

    let separatorCharacterSet = CharacterSet.whitespacesAndNewlines
        .union(.punctuationCharacters)
        .union(.symbols)
    let alphanumericCharacterSet = CharacterSet.alphanumerics

    guard !alphanumericCharacterSet.contains(firstScalar) else {
        return nil
    }

    let remainderStartIndex = suffix.unicodeScalars.firstIndex(where: { scalar in
        !separatorCharacterSet.contains(scalar)
    }) ?? suffix.endIndex
    let transcriptRemainder = suffix[remainderStartIndex...]
        .trimmingCharacters(in: .whitespacesAndNewlines)

    return WakePrefixMatch(
        detectionText: normalizedWakeTriggerPhrase,
        transcriptRemainder: transcriptRemainder
    )
}

private func boundedClarifyQuestion(_ rawValue: String?) -> String? {
    guard let rawValue else {
        return nil
