private enum DesktopAudioEvidenceClass: String, Equatable {
    case safeUserSpeech = "safe_user_speech"
    case likelyUserSpeech = "likely_user_speech"
    case likelyTtsEcho = "likely_tts_echo"
    case doubleTalkUncertain = "double_talk_uncertain"
    case noiseRejected = "noise_rejected"
    case unsafeUncertain = "unsafe_uncertain"
}

private struct DesktopAudioEvidenceContext: Equatable {
    private static let postTtsEchoTailPreviewGuardNS: UInt64 = 900_000_000

    let ttsPlaybackActiveAtCaptureStart: Bool
    let ttsPlaybackStartedNS: UInt64?
    let lastTtsPlaybackEndedNS: UInt64?
    let ttsPlaybackReferenceText: String?

    func ttsActiveDuringCapture(startNS: UInt64, endNS: UInt64) -> Bool {
        guard let ttsPlaybackStartedNS else {
            return ttsPlaybackActiveAtCaptureStart
        }

        let playbackEndNS = lastTtsPlaybackEndedNS ?? endNS
        return ttsPlaybackStartedNS <= endNS && playbackEndNS >= startNS
    }

    func ttsEchoRiskForSpeech(speechStartNS: UInt64?, captureStartNS: UInt64, captureEndNS: UInt64) -> Bool {
        let observedSpeechStartNS = speechStartNS ?? captureStartNS
        if ttsPlaybackActiveAtCaptureStart {
            guard let lastTtsPlaybackEndedNS else {
                return true
            }

            let postPlaybackEchoGuardNS: UInt64 = 150_000_000
            return observedSpeechStartNS <= lastTtsPlaybackEndedNS
                || observedSpeechStartNS.saturatingSubtract(lastTtsPlaybackEndedNS) < postPlaybackEchoGuardNS
        }

        guard ttsActiveDuringCapture(startNS: captureStartNS, endNS: captureEndNS) else {
            return false
        }

        guard let lastTtsPlaybackEndedNS else {
            return true
        }

        let postPlaybackEchoGuardNS: UInt64 = 150_000_000
        return observedSpeechStartNS <= lastTtsPlaybackEndedNS
            || observedSpeechStartNS.saturatingSubtract(lastTtsPlaybackEndedNS) < postPlaybackEchoGuardNS
    }

    func suppressesUnacceptedPreview(
        observedNS: UInt64,
        captureStartNS: UInt64,
        speechStartNS: UInt64?
    ) -> Bool {
        if ttsPlaybackActiveAtCaptureStart {
            return true
        }

        if ttsActiveDuringCapture(startNS: captureStartNS, endNS: observedNS) {
            return true
        }

        guard let lastTtsPlaybackEndedNS else {
            return false
        }

        let observedSpeechStartNS = speechStartNS ?? observedNS
        return observedSpeechStartNS <= lastTtsPlaybackEndedNS
            || observedSpeechStartNS.saturatingSubtract(lastTtsPlaybackEndedNS)
                < Self.postTtsEchoTailPreviewGuardNS
    }

    func transcriptMatchesTtsReference(_ transcript: String?) -> Bool {
        guard let transcript,
              let ttsPlaybackReferenceText else {
            return false
        }

        let transcriptTokens = DesktopAudioEvidenceContext.normalizedTokens(transcript)
        let ttsTokens = DesktopAudioEvidenceContext.normalizedTokens(ttsPlaybackReferenceText)
        guard !transcriptTokens.isEmpty,
              !ttsTokens.isEmpty else {
            return false
        }

        let transcriptJoined = transcriptTokens.joined()
        let ttsJoined = ttsTokens.joined()
        if transcriptJoined.count >= 6,
           (ttsJoined.contains(transcriptJoined) || transcriptJoined.contains(ttsJoined)) {
            return true
        }

        let overlap = Set(transcriptTokens).intersection(Set(ttsTokens)).count
        let overlapBP = (overlap * 10_000) / Swift.max(transcriptTokens.count, 1)
        if transcriptTokens.count <= 3 {
            return overlapBP >= 5_000
        }

        return overlapBP >= 6_500
    }

    private static func normalizedTokens(_ text: String) -> [String] {
        text
            .lowercased()
            .split { character in
                !character.isLetter && !character.isNumber
            }
            .map(String.init)
            .filter { !$0.isEmpty }
    }
}

private struct DesktopAudioEvidenceAccumulator {
    private(set) var captureStartNS: UInt64?
    private(set) var lastAudioBufferNS: UInt64?
    private(set) var maxInterBufferGapNS: UInt64 = 0
    private(set) var audioBufferCount: UInt64 = 0
    private(set) var audibleAudioDurationNS: UInt64 = 0
    private(set) var speechLikeAudioDurationNS: UInt64 = 0
    private(set) var speechLikeBufferCount: UInt64 = 0
    private(set) var impulsiveNoiseBufferCount: UInt64 = 0
    private(set) var appendedAudioBytes: UInt64 = 0
    private(set) var peakSampleMagnitude: Int32 = 0
    private(set) var accumulatedMeanSquare: Double = 0

    mutating func reset(captureStartNS: UInt64) {
        self.captureStartNS = captureStartNS
        lastAudioBufferNS = nil
        maxInterBufferGapNS = 0
        audioBufferCount = 0
        audibleAudioDurationNS = 0
        speechLikeAudioDurationNS = 0
        speechLikeBufferCount = 0
        impulsiveNoiseBufferCount = 0
        appendedAudioBytes = 0
        peakSampleMagnitude = 0
        accumulatedMeanSquare = 0
    }

    mutating func recordInt16AudioBuffer(_ buffer: AVAudioPCMBuffer, byteCount: Int, observedNS: UInt64) {
        if let lastAudioBufferNS {
            maxInterBufferGapNS = Swift.max(maxInterBufferGapNS, observedNS.saturatingSubtract(lastAudioBufferNS))
        }
        lastAudioBufferNS = observedNS
        audioBufferCount &+= 1
        appendedAudioBytes &+= UInt64(Swift.max(byteCount, 0))

        guard let channelData = buffer.int16ChannelData,
              buffer.frameLength > 0 else {
            return
        }

        let samples = UnsafeBufferPointer(start: channelData[0], count: Int(buffer.frameLength))
        var localPeak: Int32 = 0
        var localSquareSum = 0.0
        var localZeroCrossings = 0
        var previousNonZeroSign: Int?
        for sample in samples {
            let sampleValue = Int(sample)
            let magnitude = Int32(abs(sampleValue))
            localPeak = Swift.max(localPeak, magnitude)
            let normalized = Double(sample) / 32_768.0
            localSquareSum += normalized * normalized
            let sign = sampleValue > 0 ? 1 : (sampleValue < 0 ? -1 : 0)
            if sign != 0 {
                if let previousNonZeroSign, previousNonZeroSign != sign {
                    localZeroCrossings += 1
                }
                previousNonZeroSign = sign
            }
        }

        peakSampleMagnitude = Swift.max(peakSampleMagnitude, localPeak)
        accumulatedMeanSquare += localSquareSum

        let sampleCount = Swift.max(samples.count, 1)
        let localRMS = sqrt(localSquareSum / Double(sampleCount))
        let localPeakRatio = Double(localPeak) / 32_768.0
        let zeroCrossingRate = Double(localZeroCrossings) / Double(sampleCount)
        let crestFactor = localPeakRatio / Swift.max(localRMS, 0.000_001)
        let frameDurationNS = UInt64(
            (Double(buffer.frameLength) / Swift.max(buffer.format.sampleRate, 1)) * 1_000_000_000
        )
        let audibleFrame = localPeakRatio >= 0.015 || localRMS >= 0.006
        if audibleFrame {
            audibleAudioDurationNS = audibleAudioDurationNS.saturatingAdd(frameDurationNS)
        }

        let speechLikeFrame = audibleFrame
            && localRMS >= 0.0045
            && zeroCrossingRate >= 0.004
            && zeroCrossingRate <= 0.40
            && crestFactor <= 32.0
        if speechLikeFrame {
            speechLikeAudioDurationNS = speechLikeAudioDurationNS.saturatingAdd(frameDurationNS)
            speechLikeBufferCount &+= 1
        } else if audibleFrame
                    && (zeroCrossingRate < 0.004 || zeroCrossingRate > 0.45 || crestFactor > 40.0) {
            impulsiveNoiseBufferCount &+= 1
        }
    }

    func snapshot(
        captureStartNS: UInt64,
        captureEndNS: UInt64,
        finalTranscript: String?,
        finalTranscriptPresent: Bool,
        partialTranscriptPresent: Bool,
        speechStartNS: UInt64?,
        evidenceContext: DesktopAudioEvidenceContext
    ) -> DesktopAudioEvidenceSnapshot {
        let ttsPlaybackActive = evidenceContext.ttsActiveDuringCapture(
            startNS: captureStartNS,
            endNS: captureEndNS
        )
        let ttsEchoRiskForSpeech = evidenceContext.ttsEchoRiskForSpeech(
            speechStartNS: speechStartNS,
            captureStartNS: captureStartNS,
            captureEndNS: captureEndNS
        )
        let finalTranscriptMatchesTtsEcho =
            ttsEchoRiskForSpeech && evidenceContext.transcriptMatchesTtsReference(finalTranscript)
        let streamGapDetected = maxInterBufferGapNS > 750_000_000 || audioBufferCount == 0
        let rms = appendedAudioBytes == 0 ? 0 : sqrt(accumulatedMeanSquare / Double(Swift.max(appendedAudioBytes / 2, 1)))
        let peakRatio = Double(peakSampleMagnitude) / 32_768.0
        let audibleEnergy = peakRatio >= 0.015 || rms >= 0.006
        let transcriptTokenCount = Self.transcriptSpeechTokenCount(finalTranscript)
        let requiredSpeechLikeDurationNS = Self.requiredSpeechLikeDurationNS(
            transcriptTokenCount: transcriptTokenCount
        )
        let requiredSpeechLikeBuffers = Self.requiredSpeechLikeBufferCount(
            transcriptTokenCount: transcriptTokenCount
        )
        let localSpeechEvidenceIsStrong = speechLikeAudioDurationNS >= requiredSpeechLikeDurationNS
            && speechLikeBufferCount >= requiredSpeechLikeBuffers
        let localSpeechEvidenceIsWeak = finalTranscriptPresent && !localSpeechEvidenceIsStrong
        let impulsiveNoiseDominates = audibleAudioDurationNS > 0
            && speechLikeAudioDurationNS.saturatingMultiply(2) < audibleAudioDurationNS
            && impulsiveNoiseBufferCount > speechLikeBufferCount

        let evidenceClass: DesktopAudioEvidenceClass
        if finalTranscriptMatchesTtsEcho {
            evidenceClass = .likelyTtsEcho
        } else if ttsEchoRiskForSpeech && (finalTranscriptPresent || partialTranscriptPresent || audibleEnergy) {
            evidenceClass = .doubleTalkUncertain
        } else if ttsPlaybackActive && !finalTranscriptPresent {
            evidenceClass = .likelyTtsEcho
        } else if streamGapDetected {
            evidenceClass = .unsafeUncertain
        } else if !finalTranscriptPresent && audibleEnergy {
            evidenceClass = .noiseRejected
        } else if localSpeechEvidenceIsWeak {
            evidenceClass = .noiseRejected
        } else if finalTranscriptPresent && transcriptTokenCount > 1 && impulsiveNoiseDominates {
            evidenceClass = .noiseRejected
        } else if finalTranscriptPresent && audibleEnergy {
            evidenceClass = .safeUserSpeech
        } else if finalTranscriptPresent {
            evidenceClass = .likelyUserSpeech
        } else {
            evidenceClass = .unsafeUncertain
        }

        return DesktopAudioEvidenceSnapshot(
            evidenceClass: evidenceClass,
            ttsPlaybackActive: ttsPlaybackActive,
            streamGapDetected: streamGapDetected,
            // Peak clipping is carried as PH1.K evidence; it must not poison otherwise valid wake speech.
            captureDegraded: streamGapDetected || matchesUnsafeEvidence(evidenceClass),
            aecUnstable: ttsEchoRiskForSpeech,
            audibleEnergyDetected: audibleEnergy,
            peakRatio: peakRatio,
            rmsRatio: rms,
            audioBufferCount: audioBufferCount,
            audibleAudioDurationNS: audibleAudioDurationNS,
            speechLikeAudioDurationNS: speechLikeAudioDurationNS,
            speechLikeBufferCount: speechLikeBufferCount,
            impulsiveNoiseBufferCount: impulsiveNoiseBufferCount,
            appendedAudioBytes: appendedAudioBytes,
            maxInterBufferGapNS: maxInterBufferGapNS
        )
    }

    private static func transcriptSpeechTokenCount(_ text: String?) -> Int {
        (text ?? "")
            .split { character in
                !character.isLetter && !character.isNumber
            }
            .filter { !$0.isEmpty }
            .count
    }

    private static func requiredSpeechLikeDurationNS(transcriptTokenCount: Int) -> UInt64 {
        switch transcriptTokenCount {
        case 0:
            return 240_000_000
        case 1:
            return 160_000_000
        case 2...3:
            return 320_000_000
        case 4...6:
            return 650_000_000
        default:
            return 900_000_000
        }
    }

    private static func requiredSpeechLikeBufferCount(transcriptTokenCount: Int) -> UInt64 {
        switch transcriptTokenCount {
        case 0...1:
            return 2
        case 2...3:
            return 3
        case 4...6:
            return 5
        default:
            return 7
        }
    }

    private func matchesUnsafeEvidence(_ evidenceClass: DesktopAudioEvidenceClass) -> Bool {
        switch evidenceClass {
        case .likelyTtsEcho, .doubleTalkUncertain, .noiseRejected, .unsafeUncertain:
            return true
        case .safeUserSpeech, .likelyUserSpeech:
            return false
        }
    }
}

private struct DesktopAudioEvidenceSnapshot: Equatable {
    let evidenceClass: DesktopAudioEvidenceClass
    let ttsPlaybackActive: Bool
    let streamGapDetected: Bool
    let captureDegraded: Bool
    let aecUnstable: Bool
    let audibleEnergyDetected: Bool
    let peakRatio: Double
    let rmsRatio: Double
    let audioBufferCount: UInt64
    let audibleAudioDurationNS: UInt64
    let speechLikeAudioDurationNS: UInt64
    let speechLikeBufferCount: UInt64
    let impulsiveNoiseBufferCount: UInt64
    let appendedAudioBytes: UInt64
    let maxInterBufferGapNS: UInt64

    var audibleAudioDurationMS: UInt64 {
        audibleAudioDurationNS / 1_000_000
    }

    var speechLikeAudioDurationMS: UInt64 {
        speechLikeAudioDurationNS / 1_000_000
    }

    var vadConfidenceBP: UInt16 {
        switch evidenceClass {
        case .safeUserSpeech:
            return 8_800
        case .likelyUserSpeech:
            return 7_200
        case .doubleTalkUncertain:
            return 5_400
        case .likelyTtsEcho, .noiseRejected, .unsafeUncertain:
            return 2_500
        }
    }

    var acousticConfidenceBP: UInt16 {
        switch evidenceClass {
        case .safeUserSpeech:
            return 8_500
        case .likelyUserSpeech:
            return 6_800
        case .doubleTalkUncertain:
            return 5_000
        case .likelyTtsEcho, .noiseRejected, .unsafeUncertain:
            return 2_400
        }
    }

    var prosodyConfidenceBP: UInt16 {
        switch evidenceClass {
        case .safeUserSpeech:
            return 8_100
        case .likelyUserSpeech:
            return 6_000
        case .doubleTalkUncertain:
            return 4_500
        case .likelyTtsEcho, .noiseRejected, .unsafeUncertain:
            return 2_000
        }
    }

    var speechLikenessBP: UInt16 {
        switch evidenceClass {
        case .safeUserSpeech:
            return 8_700
        case .likelyUserSpeech:
            return 6_900
        case .doubleTalkUncertain:
            return 5_600
        case .likelyTtsEcho:
            return 3_200
        case .noiseRejected, .unsafeUncertain:
            return 1_800
        }
    }

    var echoSafeConfidenceBP: UInt16 {
        switch evidenceClass {
        case .safeUserSpeech:
            return 9_200
        case .likelyUserSpeech:
            return 6_400
        case .doubleTalkUncertain:
            return 2_800
        case .likelyTtsEcho:
            return 1_200
        case .noiseRejected, .unsafeUncertain:
            return 2_000
        }
    }

    var nearfieldConfidenceBP: UInt16? {
        switch evidenceClass {
        case .safeUserSpeech:
            return 8_300
        case .likelyUserSpeech:
            return 5_200
        case .likelyTtsEcho, .doubleTalkUncertain, .noiseRejected, .unsafeUncertain:
            return nil
        }
    }

    var doubleTalkBP: UInt16 {
        switch evidenceClass {
        case .doubleTalkUncertain:
            return 7_500
        case .likelyTtsEcho:
            return 5_500
        case .safeUserSpeech, .likelyUserSpeech:
            return 600
        case .noiseRejected, .unsafeUncertain:
            return 2_500
        }
    }

    var snrDBMilli: Int32 {
        switch evidenceClass {
        case .safeUserSpeech:
            return 21_000
        case .likelyUserSpeech:
            return 12_000
        case .doubleTalkUncertain:
            return 6_000
        case .likelyTtsEcho, .noiseRejected, .unsafeUncertain:
            return 3_000
        }
    }

    var clippingRatioBP: UInt16 {
        UInt16(Swift.min(10_000, Swift.max(0, Int((peakRatio >= 0.98 ? 1_000 : peakRatio * 150).rounded()))))
    }

    var echoDelayMSMilli: UInt32 {
        ttsPlaybackActive ? 160_000 : 0
    }

    var erleDBMilli: Int32 {
        ttsPlaybackActive ? 0 : 12_000
    }

    var timingJitterMSMilli: UInt32 {
        UInt32(Swift.min(60_000, maxInterBufferGapNS / 1_000))
    }
}

private extension UInt64 {
    func saturatingSubtract(_ other: UInt64) -> UInt64 {
        self >= other ? self - other : 0
    }

    func saturatingAdd(_ other: UInt64) -> UInt64 {
        let (result, overflow) = self.addingReportingOverflow(other)
        return overflow ? UInt64.max : result
    }

    func saturatingMultiply(_ other: UInt64) -> UInt64 {
        let (result, overflow) = self.multipliedReportingOverflow(by: other)
        return overflow ? UInt64.max : result
    }
}

struct ExplicitVoiceTurnRequestState: Identifiable {
    let id: String
    let deviceTurnSequence: UInt64
    let transcript: String
    let partialTranscript: String?
    let byteCount: Int
    let audioCaptureRefState: DesktopVoiceTurnAudioCaptureRefState

    var boundedPreview: String {
        if transcript.count <= 96 {
            return transcript
        }

        return "\(transcript.prefix(93))..."
    }
}

struct DesktopTypedTurnRequestState: Identifiable {
    let id: String
    let origin: DesktopTypedTurnRequestOrigin
    let deviceTurnSequence: UInt64
    let text: String
    let byteCount: Int

    var boundedPreview: String {
        if text.count <= 96 {
            return text
        }

        return "\(text.prefix(93))..."
    }
}

enum DesktopTypedTurnRequestOrigin: String, Equatable {
    case keyboardComposer = "KEYBOARD_TYPED_TURN"
    case searchRequestCard = "SEARCH_REQUEST"
    case toolRequestCard = "TOOL_REQUEST"
    case newConversationControl = "NEW_CONVERSATION_CONTROL"

    var requestIDPrefix: String {
        switch self {
        case .keyboardComposer:
            return "desktop_typed_turn_request"
        case .searchRequestCard:
            return "desktop_search_request"
        case .toolRequestCard:
            return "desktop_tool_request"
        case .newConversationControl:
            return "desktop_new_conversation_request"
        }
    }

    var pendingSourceSurface: String {
        switch self {
        case .keyboardComposer:
            return "KEYBOARD_TYPED_TURN_PENDING"
        case .searchRequestCard:
            return "SEARCH_REQUEST_PENDING"
        case .toolRequestCard:
            return "TOOL_REQUEST_PENDING"
        case .newConversationControl:
            return "NEW_CONVERSATION_PENDING"
        }
    }

    var failedSourceSurface: String {
        switch self {
        case .keyboardComposer:
            return "KEYBOARD_TYPED_TURN_FAILED_REQUEST"
        case .searchRequestCard:
            return "SEARCH_REQUEST_FAILED_REQUEST"
        case .toolRequestCard:
            return "TOOL_REQUEST_FAILED_REQUEST"
        case .newConversationControl:
            return "NEW_CONVERSATION_FAILED_REQUEST"
        }
    }

    var timelinePendingPosture: String {
        switch self {
        case .keyboardComposer:
            return "typed_turn_pending_preview"
        case .searchRequestCard:
            return "search_request_pending_preview"
        case .toolRequestCard:
            return "tool_request_pending_preview"
        case .newConversationControl:
            return "new_conversation_pending_preview"
        }
    }

    var timelineFailedPosture: String {
        switch self {
        case .keyboardComposer:
            return "typed_turn_failed_request_preview"
        case .searchRequestCard:
            return "search_request_failed_request_preview"
        case .toolRequestCard:
            return "tool_request_failed_request_preview"
        case .newConversationControl:
            return "new_conversation_failed_request_preview"
        }
    }

    var cardTitle: String {
        switch self {
        case .keyboardComposer:
            return "Typed Turn Request"
        case .searchRequestCard:
            return "Search Request"
        case .toolRequestCard:
            return "Tool Request"
        case .newConversationControl:
            return "New Conversation Request"
        }
    }

    var pendingSummary: String {
        switch self {
        case .keyboardComposer:
            return "This path preserves one bounded typed preview only while canonical runtime dispatch resolves. The shell does not fabricate local assistant output, local transcript authority, or local tool/search execution."
        case .searchRequestCard:
            return "This path preserves one bounded search-request preview only while canonical runtime dispatch resolves. Canonical runtime still retains search routing, provider choice, retrieval, and source authority, and the shell does not fabricate local search execution."
        case .toolRequestCard:
            return "This path preserves one bounded tool-request preview only while canonical runtime dispatch resolves. Canonical runtime still retains tool-routing authority, and the shell does not fabricate direct tool-name authority, local provider selection, or local search execution."
        case .newConversationControl:
            return "This path asks the canonical runtime to create a logical new-session boundary. The shell does not decide session meaning or create a new app or adapter."
        }
    }

    var timelinePendingDetail: String {
        switch self {
        case .keyboardComposer:
            return "Bounded typed-turn pending preview only. Canonical runtime acceptance and later cloud-visible response remain authoritative."
        case .searchRequestCard:
            return "Bounded search-request pending preview only. Canonical runtime acceptance, search routing, and later cloud-visible response remain authoritative."
        case .toolRequestCard:
            return "Bounded tool-request pending preview only. Canonical runtime acceptance, tool routing, and later cloud-visible response remain authoritative."
        case .newConversationControl:
            return "Bounded new-conversation control pending preview only. Canonical runtime session lifecycle acceptance remains authoritative."
        }
    }

    var timelineFailedDetail: String {
        switch self {
        case .keyboardComposer:
            return "Bounded typed-turn failure visibility only. Canonical runtime acceptance, transcript authority, and later cloud-visible response remain authoritative."
        case .searchRequestCard:
            return "Bounded search-request failure visibility only. Canonical runtime acceptance, search routing, and later cloud-visible response remain authoritative."
        case .toolRequestCard:
            return "Bounded tool-request failure visibility only. Canonical runtime acceptance, tool routing, and later cloud-visible response remain authoritative."
        case .newConversationControl:
            return "Bounded new-conversation control failure visibility only. Canonical runtime session lifecycle acceptance remains authoritative."
        }
    }
}

