private struct DesktopAuthoritativeReplyPlaybackState: Equatable {
    enum Phase: String, Equatable {
        case idle = "idle"
        case requesting = "requesting"
        case speaking = "speaking"
        case failed = "failed"
    }

    let phase: Phase
    let title: String
    let summary: String
    let detail: String

    static let idle = DesktopAuthoritativeReplyPlaybackState(
        phase: .idle,
        title: "Authoritative reply playback idle",
        summary: "Playback remains available only for cloud-authored reply text that is already visible in the bounded reply surface.",
        detail: "OpenAI TTS is the only approved audible Selene voice path. If OpenAI TTS is unavailable, the visible runtime answer remains, voice playback fails closed, and this shell does not use native macOS speech."
    )

    static func speaking(authoritativeResponseText: String) -> DesktopAuthoritativeReplyPlaybackState {
        let boundedPreview = boundedSummary(authoritativeResponseText) ?? "Cloud-authored reply playback is active."
        return DesktopAuthoritativeReplyPlaybackState(
            phase: .speaking,
            title: "Authoritative reply playback active",
            summary: boundedPreview,
            detail: "This shell is speaking only the already-rendered cloud-authored authoritative reply text. No local reply synthesis, transcript mutation, wake behavior, or autonomous-unlock capability is introduced here."
        )
    }

    static func requestingOpenAITTS(answerTextSHA256: String) -> DesktopAuthoritativeReplyPlaybackState {
        DesktopAuthoritativeReplyPlaybackState(
            phase: .requesting,
            title: "OpenAI TTS reply playback requesting",
            summary: "Requesting AI-generated speech for the already-rendered Selene runtime answer.",
            detail: "OpenAI TTS receives only the final Selene answer text for speech synthesis. The transcript text is already visible and does not depend on TTS success. answer_text_sha256=\(answerTextSHA256)"
        )
    }

    static func playingOpenAITTS(audioSHA256: String, audioByteLen: UInt64, voice: String) -> DesktopAuthoritativeReplyPlaybackState {
        DesktopAuthoritativeReplyPlaybackState(
            phase: .speaking,
            title: "OpenAI TTS reply playback active",
            summary: "Playing AI-generated speech synthesized from the already-rendered Selene runtime answer.",
            detail: "PLAYING_OPENAI tts_provider_id=\(DesktopVoiceProviderLane.ttsProviderID) voice=\(voice) audio_sha256=\(audioSHA256) audio_byte_len=\(audioByteLen) native_macos_tts=false"
        )
    }

    static func ttsUnavailable(reason: String) -> DesktopAuthoritativeReplyPlaybackState {
        DesktopAuthoritativeReplyPlaybackState(
            phase: .failed,
            title: "OpenAI TTS reply playback unavailable",
            summary: "Reply playback is unavailable because OpenAI TTS did not return audio and the runtime path did not allow fallback playback.",
            detail: "OPENAI_TTS_UNAVAILABLE reason=\(boundedFailureLogToken(reason)) native_macos_tts_attempted=false runtime_fallback_allowed=false fallback_counted_as_success=false"
        )
    }

    static func stopped() -> DesktopAuthoritativeReplyPlaybackState {
        DesktopAuthoritativeReplyPlaybackState(
            phase: .idle,
            title: "Authoritative reply playback stopped",
            summary: "Playback has been stopped and the bounded reply surface remains read-only.",
            detail: "Stopping playback does not alter authoritative reply text, transcript preview, or conversation history."
        )
    }

    static func completed() -> DesktopAuthoritativeReplyPlaybackState {
        DesktopAuthoritativeReplyPlaybackState(
            phase: .idle,
            title: "Authoritative reply playback finished",
            summary: "Playback finished for the current cloud-authored authoritative reply.",
            detail: "Completion visibility only. This shell remains non-authoritative and does not mutate transcript preview, reply-surface posture, or wake behavior."
        )
    }

    static func failed(summary: String, detail: String) -> DesktopAuthoritativeReplyPlaybackState {
        DesktopAuthoritativeReplyPlaybackState(
            phase: .failed,
            title: "Authoritative reply playback failed",
            summary: summary,
            detail: detail
        )
    }
}

private struct DesktopOpenAITtsPlaybackToken: Equatable {
    let ttsRequestID: String?
    let sessionID: String?
    let turnID: String?
    let runtimeRequestID: String?
    let answerTextSHA256: String
}

@MainActor
private final class DesktopAuthoritativeReplyPlaybackController: NSObject, ObservableObject, AVAudioPlayerDelegate {
    @Published private(set) var playbackState: DesktopAuthoritativeReplyPlaybackState = .idle

    private var openAIAudioPlayer: AVAudioPlayer?
    private var activeOpenAITtsToken: DesktopOpenAITtsPlaybackToken?
    private var stopWasRequested = false

    @discardableResult
    func play(authoritativeResponseText: String?) -> DesktopAuthoritativeReplyPlaybackState {
        failClosedWithoutNativePlayback(
            authoritativeResponseText: authoritativeResponseText,
            fallbackReason: "manual_play_requires_openai_tts"
        )
    }

    @discardableResult
    func prepareOpenAITTS(
        authoritativeResponseText: String?,
        token: DesktopOpenAITtsPlaybackToken
    ) -> DesktopAuthoritativeReplyPlaybackState {
        guard let authoritativeResponseText else {
            let failedState = DesktopAuthoritativeReplyPlaybackState.failed(
                summary: "Playback is unavailable because no cloud-authored reply text is present.",
                detail: "This shell fails closed when canonical runtime reply text is missing and does not fabricate local speech content."
            )
            playbackState = failedState
            return failedState
        }

        let trimmed = authoritativeResponseText.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else {
            let failedState = DesktopAuthoritativeReplyPlaybackState.failed(
                summary: "Playback is unavailable because the reply text is empty.",
                detail: "This shell fails closed when canonical runtime reply text is empty and does not synthesize substitute content."
            )
            playbackState = failedState
            return failedState
        }

        stopAnyPlayback()
        stopWasRequested = false
        activeOpenAITtsToken = token
        let requestingState = DesktopAuthoritativeReplyPlaybackState
            .requestingOpenAITTS(answerTextSHA256: token.answerTextSHA256)
        playbackState = requestingState
        return requestingState
    }

    @discardableResult
    func playOpenAITTS(
        _ speechState: DesktopOpenAITtsSpeechState,
        expectedToken: DesktopOpenAITtsPlaybackToken
    ) -> DesktopAuthoritativeReplyPlaybackState {
        guard activeOpenAITtsToken == expectedToken,
              speechState.sessionID == expectedToken.sessionID,
              speechState.turnID == expectedToken.turnID,
              speechState.runtimeRequestID == expectedToken.runtimeRequestID,
              speechState.answerTextSHA256 == expectedToken.answerTextSHA256 else {
            let failedState = DesktopAuthoritativeReplyPlaybackState.failed(
                summary: "Stale OpenAI TTS audio was discarded.",
                detail: "stale_audio_rejected=true fallback_counted_as_success=false"
            )
            playbackState = failedState
            return failedState
        }
        if let expectedTtsRequestID = expectedToken.ttsRequestID,
           speechState.requestID != expectedTtsRequestID {
            let failedState = DesktopAuthoritativeReplyPlaybackState.failed(
                summary: "Stale OpenAI TTS audio was discarded.",
                detail: "stale_audio_rejected=true fallback_counted_as_success=false"
            )
            playbackState = failedState
            return failedState
        }

        do {
            stopAnyPlayback()
            stopWasRequested = false
            activeOpenAITtsToken = expectedToken
            let player = try AVAudioPlayer(data: speechState.audioData)
            player.delegate = self
            player.prepareToPlay()
            guard player.play() else {
                let failedState = DesktopAuthoritativeReplyPlaybackState.failed(
                    summary: "OpenAI TTS audio playback could not start.",
                    detail: "PLAYBACK_FAILED fallback_counted_as_success=false"
                )
                playbackState = failedState
                return failedState
            }
            openAIAudioPlayer = player
            let playingState = DesktopAuthoritativeReplyPlaybackState.playingOpenAITTS(
                audioSHA256: speechState.audioSHA256,
                audioByteLen: speechState.audioByteLen,
                voice: speechState.voice
            )
            playbackState = playingState
            return playingState
        } catch {
            let failedState = DesktopAuthoritativeReplyPlaybackState.failed(
                summary: "OpenAI TTS audio playback failed.",
                detail: "PLAYBACK_FAILED fallback_counted_as_success=false"
            )
            playbackState = failedState
            return failedState
        }
    }

    @discardableResult
    func failClosedWithoutNativePlayback(
        authoritativeResponseText: String?,
        fallbackReason: String?
    ) -> DesktopAuthoritativeReplyPlaybackState {
        guard let authoritativeResponseText else {
            let failedState = DesktopAuthoritativeReplyPlaybackState.failed(
                summary: "Playback is unavailable because no cloud-authored reply text is present.",
                detail: "This shell fails closed when canonical runtime reply text is missing and does not fabricate local speech content."
            )
            playbackState = failedState
            return failedState
        }

        let trimmed = authoritativeResponseText.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else {
            let failedState = DesktopAuthoritativeReplyPlaybackState.failed(
                summary: "Playback is unavailable because the reply text is empty.",
                detail: "This shell fails closed when canonical runtime reply text is empty and does not synthesize substitute content."
            )
            playbackState = failedState
            return failedState
        }

        if let openAIAudioPlayer, openAIAudioPlayer.isPlaying {
            openAIAudioPlayer.stop()
        }
        openAIAudioPlayer = nil
        activeOpenAITtsToken = nil

        stopWasRequested = false

        let failedState = DesktopAuthoritativeReplyPlaybackState.ttsUnavailable(
            reason: fallbackReason ?? "openai_tts_required"
        )
        playbackState = failedState
        return failedState
    }

    @discardableResult
    func stop() -> DesktopAuthoritativeReplyPlaybackState {
        stopWasRequested = true
        stopAnyPlayback()
        activeOpenAITtsToken = nil
        let stoppedState = DesktopAuthoritativeReplyPlaybackState.stopped()
        playbackState = stoppedState
        return stoppedState
    }

    func reset() {
        stopWasRequested = false
        stopAnyPlayback()
        activeOpenAITtsToken = nil
        playbackState = .idle
    }

    private func stopAnyPlayback() {
        if let openAIAudioPlayer, openAIAudioPlayer.isPlaying {
            openAIAudioPlayer.stop()
        }
        openAIAudioPlayer = nil
    }

    nonisolated func audioPlayerDidFinishPlaying(_ player: AVAudioPlayer, successfully flag: Bool) {
        Task { @MainActor in
            openAIAudioPlayer = nil
            activeOpenAITtsToken = nil
            if stopWasRequested {
                stopWasRequested = false
                playbackState = .stopped()
            } else if flag {
                playbackState = .completed()
            } else {
                playbackState = .failed(
                    summary: "OpenAI TTS reply playback ended before completion.",
                    detail: "PLAYBACK_FAILED fallback_counted_as_success=false"
                )
            }
        }
    }

    nonisolated func audioPlayerDecodeErrorDidOccur(_ player: AVAudioPlayer, error: Error?) {
        Task { @MainActor in
            openAIAudioPlayer = nil
            activeOpenAITtsToken = nil
            playbackState = .failed(
                summary: "OpenAI TTS reply playback could not decode the returned audio.",
                detail: "PLAYBACK_FAILED fallback_counted_as_success=false"
            )
        }
    }

}

private enum VoicePermissionState: String {
    case notRequested = "not_requested"
    case granted = "granted"
    case denied = "denied"
    case restricted = "restricted"
    case unavailable = "unavailable"

    var detail: String {
        switch self {
        case .notRequested:
            return "Permission has not been requested in this foreground session yet."
        case .granted:
            return "Permission is granted for bounded explicit voice capture only."
        case .denied:
            return "Permission was denied. Explicit voice capture stays blocked until the user re-enables access."
        case .restricted:
            return "Permission is restricted by device policy. This shell remains non-authoritative and does not bypass policy."
        case .unavailable:
            return "Permission or transcription provider availability is unavailable on this device posture."
        }
    }
}

private struct DesktopChatComposerTextView: NSViewRepresentable {
    @Binding var text: String
    @Binding var measuredHeight: CGFloat
    @Binding var isFocused: Bool
    @Binding var focusRequestID: UInt64

    let isEditable: Bool
    let onSubmit: () -> Void

    private let minHeight: CGFloat = 22
    private let maxHeight: CGFloat = 224

    func makeCoordinator() -> Coordinator {
        Coordinator(self)
    }

    func makeNSView(context: Context) -> NSScrollView {
        let scrollView = DesktopChatComposerScrollView()
        scrollView.drawsBackground = false
        scrollView.borderType = .noBorder
        scrollView.hasHorizontalScroller = false
        scrollView.hasVerticalScroller = false
        scrollView.autohidesScrollers = true
        scrollView.scrollerStyle = .overlay

        let textView = DesktopChatComposerNativeTextView()
        textView.delegate = context.coordinator
        textView.onSubmit = onSubmit
        textView.drawsBackground = false
        textView.isRichText = false
        textView.isAutomaticQuoteSubstitutionEnabled = false
        textView.isAutomaticDashSubstitutionEnabled = false
        textView.isAutomaticTextReplacementEnabled = false
        textView.isContinuousSpellCheckingEnabled = false
        textView.isGrammarCheckingEnabled = false
        textView.isHorizontallyResizable = false
        textView.isVerticallyResizable = true
        textView.textContainerInset = NSSize(width: 0, height: 1)
        textView.font = .systemFont(ofSize: 16)
        textView.textContainer?.lineFragmentPadding = 0
        textView.textContainer?.widthTracksTextView = true
        textView.textContainer?.containerSize = NSSize(
            width: 0,
            height: CGFloat.greatestFiniteMagnitude
        )
        textView.minSize = NSSize(width: 0, height: minHeight)
        textView.maxSize = NSSize(
            width: CGFloat.greatestFiniteMagnitude,
            height: CGFloat.greatestFiniteMagnitude
        )
        textView.autoresizingMask = [.width]
        textView.frame = NSRect(
            x: 0,
            y: 0,
            width: max(scrollView.contentSize.width, 1),
            height: minHeight
        )
        textView.string = text
        textView.isEditable = isEditable
        textView.isSelectable = true
        scrollView.documentView = textView
        scrollView.composerTextView = textView

        DispatchQueue.main.async {
            context.coordinator.updateMeasuredHeight(for: textView)
            if isFocused {
                scrollView.focusComposerTextView()
            }
        }

        return scrollView
    }

    func updateNSView(_ scrollView: NSScrollView, context: Context) {
        guard let textView = scrollView.documentView as? DesktopChatComposerNativeTextView else {
            return
        }

        context.coordinator.parent = self
        textView.onSubmit = onSubmit
        textView.isEditable = isEditable
        let focusRequestChanged = context.coordinator.lastAppliedFocusRequestID != focusRequestID
        if focusRequestChanged {
            context.coordinator.lastAppliedFocusRequestID = focusRequestID
        }

        if textView.string != text {
            textView.string = text
        }

        DispatchQueue.main.async {
            context.coordinator.updateMeasuredHeight(for: textView)
            scrollView.hasVerticalScroller = measuredHeight >= maxHeight - 1
            if (isFocused || focusRequestChanged),
               textView.window?.firstResponder !== textView,
               let composerScrollView = scrollView as? DesktopChatComposerScrollView {
                composerScrollView.focusComposerTextView()
            }
        }
    }

    final class Coordinator: NSObject, NSTextViewDelegate {
        var parent: DesktopChatComposerTextView
        var lastAppliedFocusRequestID: UInt64

        init(_ parent: DesktopChatComposerTextView) {
            self.parent = parent
            self.lastAppliedFocusRequestID = parent.focusRequestID
        }

        func textDidChange(_ notification: Notification) {
            guard let textView = notification.object as? NSTextView else {
                return
            }

            parent.text = textView.string
            updateMeasuredHeight(for: textView)
        }

        func textDidBeginEditing(_ notification: Notification) {
            parent.isFocused = true
        }

        func textDidEndEditing(_ notification: Notification) {
            parent.isFocused = false
        }

        func updateMeasuredHeight(for textView: NSTextView) {
            let fittingWidth = max(textView.enclosingScrollView?.contentSize.width ?? textView.bounds.width, 1)
            textView.textContainer?.containerSize = NSSize(
                width: fittingWidth,
                height: CGFloat.greatestFiniteMagnitude
            )
            textView.layoutManager?.ensureLayout(for: textView.textContainer!)
            let fittingSize = textView.layoutManager?.usedRect(for: textView.textContainer!).size ?? .zero
            let clampedHeight = min(
                parent.maxHeight,
                max(parent.minHeight, ceil(fittingSize.height + textView.textContainerInset.height * 2))
            )
            textView.frame.size = NSSize(width: fittingWidth, height: clampedHeight)

            if abs(parent.measuredHeight - clampedHeight) > 0.5 {
                parent.measuredHeight = clampedHeight
            }
        }
    }
}

private final class DesktopChatComposerScrollView: NSScrollView {
    weak var composerTextView: DesktopChatComposerNativeTextView?

    override var acceptsFirstResponder: Bool {
        true
    }

    override func becomeFirstResponder() -> Bool {
        if let composerTextView {
            window?.makeFirstResponder(composerTextView)
            return true
        }

        return super.becomeFirstResponder()
    }

    func focusComposerTextView() {
        if let composerTextView {
            window?.makeFirstResponder(composerTextView)
        }
    }

    override func mouseDown(with event: NSEvent) {
        if let composerTextView {
            window?.makeFirstResponder(composerTextView)
        }
        super.mouseDown(with: event)
        if let composerTextView {
            DispatchQueue.main.async { [weak self, weak composerTextView] in
                guard let self, let composerTextView else {
                    return
                }
                self.window?.makeFirstResponder(composerTextView)
            }
        }
    }
}

private final class DesktopChatComposerNativeTextView: NSTextView {
    var onSubmit: (() -> Void)?

    override var acceptsFirstResponder: Bool {
        true
    }

    override func acceptsFirstMouse(for event: NSEvent?) -> Bool {
        true
    }

    override func keyDown(with event: NSEvent) {
        let isReturnKey = event.keyCode == 36 || event.keyCode == 76
        let modifiers = event.modifierFlags.intersection(.deviceIndependentFlagsMask)

        if isReturnKey,
           !modifiers.contains(.shift),
           !modifiers.contains(.option),
           !modifiers.contains(.control),
           !modifiers.contains(.command) {
            onSubmit?()
            return
        }

        super.keyDown(with: event)
    }
}

private struct DesktopLightScrollBarInstaller: NSViewRepresentable {
    let autohidesScrollers: Bool

    init(autohidesScrollers: Bool = true) {
        self.autohidesScrollers = autohidesScrollers
    }

    func makeNSView(context: Context) -> NSView {
        let view = NSView(frame: .zero)
        DispatchQueue.main.async {
            Self.installLightScrollBar(from: view, autohidesScrollers: autohidesScrollers)
        }
        return view
    }

    func updateNSView(_ view: NSView, context: Context) {
        DispatchQueue.main.async {
            Self.installLightScrollBar(from: view, autohidesScrollers: autohidesScrollers)
        }
    }

    private static func installLightScrollBar(from view: NSView, autohidesScrollers: Bool) {
        guard let scrollView = view.desktopNearestScrollView else {
            return
        }

        scrollView.drawsBackground = true
        scrollView.backgroundColor = .white
        scrollView.contentView.drawsBackground = true
        scrollView.contentView.backgroundColor = .white
        scrollView.wantsLayer = true
        scrollView.layer?.backgroundColor = NSColor.white.cgColor
        scrollView.contentView.wantsLayer = true
        scrollView.contentView.layer?.backgroundColor = NSColor.white.cgColor
        scrollView.scrollerStyle = .overlay
        scrollView.autohidesScrollers = autohidesScrollers
        scrollView.hasVerticalScroller = true
        scrollView.scrollerInsets = NSEdgeInsetsZero

        if scrollView.verticalScroller is DesktopLightVerticalScroller {
            scrollView.verticalScroller = NSScroller()
        }

        scrollView.verticalScroller?.controlSize = .regular
        scrollView.reflectScrolledClipView(scrollView.contentView)
    }
}

private final class DesktopLightVerticalScroller: NSScroller {
    private static let trackColor = NSColor.white

    private static let thumbColor = NSColor(
        calibratedRed: 0.72,
        green: 0.72,
        blue: 0.72,
        alpha: 0.86
    )

    override class func scrollerWidth(
        for controlSize: NSControl.ControlSize,
        scrollerStyle: NSScroller.Style
    ) -> CGFloat {
        8
    }

    override var isOpaque: Bool {
        true
    }

    override func draw(_ dirtyRect: NSRect) {
        Self.trackColor.setFill()
        dirtyRect.fill()
        drawKnob()
    }

    override func drawKnob() {
        let rawKnobRect = rect(for: .knob)
        let knobWidth: CGFloat = 13
        let trailingInset: CGFloat = 0
        let knobRect = NSRect(
            x: bounds.maxX - knobWidth - trailingInset,
            y: rawKnobRect.minY + 1.2,
            width: knobWidth,
            height: max(0, rawKnobRect.height - 2.4)
        )
        guard knobRect.width > 0, knobRect.height > 0 else {
            return
        }

        Self.thumbColor.setFill()
        NSBezierPath(
            roundedRect: knobRect,
            xRadius: knobRect.width / 2,
            yRadius: knobRect.width / 2
        ).fill()
    }

    override func drawKnobSlot(in slotRect: NSRect, highlight flag: Bool) {
        Self.trackColor.setFill()
        slotRect.fill()
    }
}

private extension NSView {
    var desktopNearestScrollView: NSScrollView? {
        var candidate: NSView? = self
        while let current = candidate {
            if let scrollView = current as? NSScrollView {
                return scrollView
            }
            candidate = current.superview
        }
        return nil
    }
}

private final class ExplicitVoiceCaptureController: ObservableObject {
    private struct CaptureSessionTransportContext {
        let streamID: UInt64
        let preRollBufferID: UInt64
        let tStartNS: UInt64
        let localeTag: String
        let deviceRoute: String
        let selectedMic: String
        let selectedSpeaker: String
        var evidenceContext: DesktopAudioEvidenceContext
    }

    @Published private(set) var microphonePermission: VoicePermissionState = .notRequested
    @Published private(set) var transcriptionPermission: VoicePermissionState = .notRequested
    @Published private(set) var isListening = false
    @Published private(set) var transcriptPreview = ""
    @Published private(set) var pendingRequest: ExplicitVoiceTurnRequestState?
    @Published private(set) var failedRequest: InterruptContinuityResponseFailureState?
    @Published private(set) var failedRequestSequence: UInt64 = 0

    private let maxVoiceTurnBytes = 16_384
    private let autoPrepareAfterSilenceDelay: TimeInterval = 1.8
    private let audioEngine = AVAudioEngine()
    private let realtimeAudioQueue = DispatchQueue(label: "selene.desktop.realtime-transcription.audio")
    private let realtimeURLSession = URLSession(configuration: .ephemeral)
    private var hasInputTap = false
    private var lastGeneratedDeviceTurnSequence: UInt64 = 0
    private var activeCaptureContext: CaptureSessionTransportContext?
    private var autoPrepareAfterSilenceWorkItem: DispatchWorkItem?
    private var realtimeSession: DesktopRealtimeTranscriptionSessionState?
    private var realtimeWebSocketTask: URLSessionWebSocketTask?
    private var realtimeOutputFormat: AVAudioFormat?
    private var realtimeAudioConverter: AVAudioConverter?
    private var realtimePartialTranscript = ""
    private var realtimeCommittedTranscript = ""
    private var realtimeCaptureStopNS: UInt64?
    private var realtimeCompletionTimeoutWorkItem: DispatchWorkItem?
    private var realtimeMaxSessionDurationWorkItem: DispatchWorkItem?
    private var realtimeSpeechStartedNS: UInt64?
    private var realtimeFirstDeltaNS: UInt64?
    private var realtimeFirstAudioFrameNS: UInt64?
    private var realtimePreviewSuppressedForEchoTail = false
    private var realtimeAudioEvidenceAccumulator = DesktopAudioEvidenceAccumulator()
    private var realtimeTransportReady = false
    private var realtimeQueuedOutboundMessages: [String] = []
    private let maxRealtimeQueuedOutboundMessages = 256

    init(locale: Locale? = nil) {
        _ = locale
        refreshPermissionState()
    }

    func startRealtimeTranscriptionVoiceTurn(
        session: DesktopRealtimeTranscriptionSessionState,
        evidenceContext: DesktopAudioEvidenceContext
    ) {
        failedRequest = nil

        guard !isListening else {
            return
        }

        guard pendingRequest == nil else {
            recordFailure(
                id: "failed_realtime_transcription_pending_request_active",
                title: "Failed explicit voice request",
                summary: "The realtime transcription path could not start while a prepared explicit voice request is already pending.",
                detail: "Fallback/rollback visibility only; no parallel local answer lane or hidden capture session was created."
            )
            return
        }

        transcriptPreview = ""
        refreshPermissionState()
        requestMicrophonePermissionIfNeeded { [weak self] granted in
            guard let self else {
                return
            }

            DispatchQueue.main.async {
                self.refreshPermissionState()
                guard granted else {
                    self.recordFailure(
                        id: "failed_realtime_transcription_microphone_permission",
                        title: "Failed explicit voice request",
                        summary: "Microphone permission is required before realtime transcription capture can begin.",
                        detail: "Permission visibility only; no wake behavior, background capture, or local transcript authority was introduced."
                    )
                    return
                }

                self.beginRealtimeTranscriptionCapture(session: session, evidenceContext: evidenceContext)
            }
        }
    }

    func prepareRealtimeTranscriptionTransport(
        session: DesktopRealtimeTranscriptionSessionState
    ) {
        failedRequest = nil

        guard !isListening,
              pendingRequest == nil,
              realtimeWebSocketTask == nil else {
            return
        }

        teardownRecognitionSession()
        realtimeSession = session
        realtimePartialTranscript = ""
        realtimeCommittedTranscript = ""
        realtimeCaptureStopNS = nil
        realtimeSpeechStartedNS = nil
        realtimeFirstDeltaNS = nil
        realtimeFirstAudioFrameNS = nil
        realtimePreviewSuppressedForEchoTail = false
        realtimeTransportReady = false
        realtimeQueuedOutboundMessages.removeAll(keepingCapacity: true)
        transcriptPreview = ""

        guard let websocketURL = URL(string: session.websocketURL) else {
            teardownRealtimeTranscriptionSession()
            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) openai realtime transcription prewarm websocket_preconnect_unavailable=true reason=invalid_url request=\(session.requestID)"
            )
            return
        }

        let websocketTask = realtimeURLSession.webSocketTask(
            with: websocketURL,
            protocols: [
                "realtime",
                "openai-insecure-api-key.\(session.clientSecret)",
            ]
        )
        realtimeWebSocketTask = websocketTask
        websocketTask.resume()
        receiveRealtimeTranscriptionEvents()
        desktopAppendRuntimeBridgeDebugLog(
            "\(desktopTraceClockFields()) openai realtime transcription prewarm token_ready=true websocket_preconnect=true request=\(session.requestID)"
        )
    }

    func startExplicitVoiceTurn() {
        failedRequest = nil

        guard !isListening else {
            return
        }

        guard pendingRequest == nil else {
            recordFailure(
                id: "failed_explicit_voice_turn_awaiting_authoritative_response",
                title: "Failed explicit voice request",
                summary: "A later explicit voice-turn request could not be produced while the current bounded explicit voice request is already awaiting authoritative follow-up.",
                detail: "This shell keeps only bounded pending / failed posture. It does not queue another local voice request, repair transport, or fabricate local assistant output."
            )
            return
        }

        transcriptPreview = ""
        refreshPermissionState()
        recordFailure(
            id: "failed_explicit_voice_non_openai_stt_disabled",
            title: "Failed explicit voice request",
            summary: "Explicit voice capture requires OpenAI realtime transcription.",
            detail: "Local platform speech recognition is disabled. No local transcript fallback, hidden retry, or authoritative assistant output was produced."
        )
    }

    func stopCaptureAndPrepareVoiceTurn() {
        if realtimeWebSocketTask != nil {
            stopRealtimeTranscriptionCaptureAndCommit()
            return
        }

        guard isListening else {
            recordFailure(
                id: "failed_explicit_voice_not_listening",
                title: "Failed explicit voice request",
                summary: "The bounded explicit voice surface was not actively listening when request preparation was attempted.",
                detail: "Explicit voice-turn production remains foreground-only and user-visible. Start a new explicit voice turn before preparing another bounded request."
            )
            return
        }

        cancelAutoPrepareAfterSilence()
        let captureStopNS = Swift.max(DispatchTime.now().uptimeNanoseconds, 1)
        endCaptureInput()

        let trimmedTranscript = transcriptPreview.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmedTranscript.isEmpty else {
            completeStoppedCaptureSession()
            recordFailure(
                id: "failed_explicit_voice_empty_transcript",
                title: "Failed explicit voice request",
                summary: "No bounded transcript preview was available when this explicit voice turn stopped, so no voice request was produced.",
                detail: "Failure visibility only; speak again and retry through the canonical explicit voice path. No local assistant output or authoritative transcript mutation was produced."
            )
            return
        }

        if trimmedTranscript.utf8.count > maxVoiceTurnBytes {
            completeStoppedCaptureSession()
            recordFailure(
                id: "failed_explicit_voice_transcript_validation",
                title: "Failed explicit voice request",
                summary: "The bounded explicit voice transcript exceeded 16384 UTF-8 bytes before any authoritative acceptance occurred.",
                detail: "Failure visibility only; retry a shorter utterance through the canonical explicit voice path. No authoritative transcript turn was appended locally."
            )
            return
        }

        guard !shouldIgnoreCommittedVoiceTranscriptArtifact(trimmedTranscript) else {
            ignoreCommittedVoiceTranscriptArtifact(
                trimmedTranscript,
                source: "explicit_voice",
                keepRealtimeTransport: false
            )
            return
        }

        guard let audioCaptureRefState = preparedAudioCaptureRefState(
            captureStopNS: captureStopNS,
            finalTranscript: trimmedTranscript
        ) else {
            completeStoppedCaptureSession()
            recordFailure(
                id: "failed_explicit_voice_audio_capture_ref_unavailable",
                title: "Failed explicit voice request",
                summary: "The bounded explicit voice capture session could not preserve a lawful desktop audio-capture-ref transport bundle for canonical runtime ingress.",
                detail: "Failure visibility only; this shell fails closed when foreground capture state is structurally insufficient to populate the already-live adapter capture bundle requirements."
            )
            return
        }

        guard !shouldRejectCommittedUserTurnEvidence(audioCaptureRefState) else {
            completeStoppedCaptureSession()
            recordFailure(
                id: "failed_explicit_voice_unsafe_audio_evidence",
                title: "Failed explicit voice request",
                summary: "Desktop rejected the bounded voice turn because the audio evidence was echo, noise, degraded, or otherwise unsafe.",
                detail: "Failure visibility only; no runtime dispatch, local answer, provider call, protected execution, memory write, or authority grant was produced."
            )
            return
        }

        let deviceTurnSequence = nextDeviceTurnSequence()
        transcriptPreview = trimmedTranscript
        pendingRequest = ExplicitVoiceTurnRequestState(
            id: "desktop_voice_turn_request_\(deviceTurnSequence)",
            deviceTurnSequence: deviceTurnSequence,
            transcript: trimmedTranscript,
            partialTranscript: trimmedTranscript,
            byteCount: trimmedTranscript.utf8.count,
            audioCaptureRefState: audioCaptureRefState
        )
        completeStoppedCaptureSession()
    }

    func stopCaptureAndKeepTranscriptPreview() {
        guard isListening else {
            return
        }

        cancelAutoPrepareAfterSilence()
        endCaptureInput()
        transcriptPreview = transcriptPreview.trimmingCharacters(in: .whitespacesAndNewlines)
        pendingRequest = nil
        failedRequest = nil
        completeStoppedCaptureSession()
    }

    func haltCaptureSession() {
        cancelAutoPrepareAfterSilence()
        teardownRecognitionSession()
    }

    func updateActiveAudioEvidenceContext(_ evidenceContext: DesktopAudioEvidenceContext) {
        guard var activeCaptureContext else {
            return
        }

        activeCaptureContext.evidenceContext = evidenceContext
        self.activeCaptureContext = activeCaptureContext
    }

    func discardCurrentVoiceTurn() {
        cancelAutoPrepareAfterSilence()
        teardownRecognitionSession()
        pendingRequest = nil
        transcriptPreview = ""
        failedRequest = nil
    }

    func discardPreparedRealtimeTransportIfIdle() {
        guard !isListening,
              pendingRequest == nil,
              realtimeWebSocketTask != nil else {
            return
        }

        teardownRecognitionSession()
    }

    func clearPendingPreparedVoiceTurn() {
        pendingRequest = nil
    }

    private func beginCaptureSession() {
        failedRequest = nil
        teardownRecognitionSession()
        refreshPermissionState()
        recordFailure(
            id: "failed_explicit_voice_non_openai_stt_disabled",
            title: "Failed explicit voice request",
            summary: "Explicit voice capture requires OpenAI realtime transcription.",
            detail: "Local platform speech recognition is disabled. No local transcript fallback, hidden retry, or authoritative assistant output was produced."
        )
    }

    private func beginRealtimeTranscriptionCapture(
        session: DesktopRealtimeTranscriptionSessionState,
        evidenceContext: DesktopAudioEvidenceContext
    ) {
        failedRequest = nil
        let reusePreparedTransport = realtimeWebSocketTask != nil
            && realtimeSession?.requestID == session.requestID
            && !isListening
        if !reusePreparedTransport {
            teardownRecognitionSession()
        }
        refreshPermissionState()
        realtimeSession = session
        realtimePartialTranscript = ""
        realtimeCommittedTranscript = ""
        realtimeCaptureStopNS = nil
        realtimeSpeechStartedNS = nil
        realtimeFirstDeltaNS = nil
        realtimeFirstAudioFrameNS = nil
        realtimePreviewSuppressedForEchoTail = false
        transcriptPreview = ""

        guard let websocketURL = URL(string: session.websocketURL) else {
            teardownRealtimeTranscriptionSession()
            recordFailure(
                id: "failed_realtime_transcription_websocket_url",
                title: "Failed explicit voice request",
                summary: "The realtime transcription WebSocket URL was not valid.",
                detail: "Token/session failure visibility only; the shell did not expose provider payloads, retain audio, or fabricate local output."
            )
            return
        }

        do {
            let captureContext = Self.makeCaptureSessionTransportContext(evidenceContext: evidenceContext)
            realtimeAudioQueue.sync {
                realtimeAudioEvidenceAccumulator.reset(captureStartNS: captureContext.tStartNS)
            }
            let inputNode = audioEngine.inputNode
            let inputFormat = inputNode.outputFormat(forBus: 0)
            guard let outputFormat = AVAudioFormat(
                commonFormat: .pcmFormatInt16,
                sampleRate: 24_000,
                channels: 1,
                interleaved: false
            ),
            let converter = AVAudioConverter(from: inputFormat, to: outputFormat) else {
                teardownRealtimeTranscriptionSession()
                recordFailure(
                    id: "failed_realtime_transcription_audio_format",
                    title: "Failed explicit voice request",
                    summary: "The microphone audio format could not be converted into the required realtime transcription PCM16 stream.",
                    detail: "Failure visibility only; no raw audio was retained and no fallback success is counted as realtime success."
                )
                return
            }

            if realtimeWebSocketTask == nil {
                realtimeTransportReady = false
                realtimeQueuedOutboundMessages.removeAll(keepingCapacity: true)
                let websocketTask = realtimeURLSession.webSocketTask(
                    with: websocketURL,
                    protocols: [
                        "realtime",
                        "openai-insecure-api-key.\(session.clientSecret)",
                    ]
                )
                realtimeWebSocketTask = websocketTask
                websocketTask.resume()
                receiveRealtimeTranscriptionEvents()
            } else {
                desktopAppendRuntimeBridgeDebugLog(
                    "\(desktopTraceClockFields()) openai realtime transcription websocket_preconnect_consumed=true request=\(session.requestID)"
                )
            }
            realtimeOutputFormat = outputFormat
            realtimeAudioConverter = converter
            activeCaptureContext = captureContext

            inputNode.installTap(onBus: 0, bufferSize: 2_048, format: inputFormat) { [weak self] buffer, _ in
                self?.appendRealtimeAudioBuffer(buffer, inputFormat: inputFormat)
            }
            hasInputTap = true

            audioEngine.prepare()
            try audioEngine.start()
            isListening = true
            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) openai realtime transcription capture_ready=true stt_provider_id=\(DesktopVoiceProviderLane.sttProviderID) flag=\(DesktopRealtimeTranscriptionFeatureFlag.name) model=\(session.transcriptionModel) language_hint_policy=\(session.languageHintPolicy) request=\(session.requestID)"
            )
            scheduleRealtimeMaxSessionDuration(session.maxSessionDurationMS)
        } catch {
            teardownRecognitionSession()
            recordFailure(
                id: "failed_realtime_transcription_capture_start",
                title: "Failed explicit voice request",
                summary: "The realtime transcription capture session could not start from this foreground surface.",
                detail: "Capture start failed without exposing provider payloads or retaining audio. Detail: \(error.localizedDescription)"
            )
        }
    }

    private func appendRealtimeAudioBuffer(
        _ buffer: AVAudioPCMBuffer,
        inputFormat: AVAudioFormat
    ) {
        realtimeAudioQueue.async { [weak self] in
            guard let self,
                  let converter = self.realtimeAudioConverter,
                  let outputFormat = self.realtimeOutputFormat,
                  self.realtimeWebSocketTask != nil else {
                return
            }

            let ratio = outputFormat.sampleRate / Swift.max(inputFormat.sampleRate, 1)
            let frameCapacity = AVAudioFrameCount(
                Swift.max(1, Double(buffer.frameLength) * ratio + 128)
            )
            guard let outputBuffer = AVAudioPCMBuffer(
                pcmFormat: outputFormat,
                frameCapacity: frameCapacity
            ) else {
                return
            }

            var conversionError: NSError?
            var suppliedInput = false
            let status = converter.convert(to: outputBuffer, error: &conversionError) { _, outStatus in
                if suppliedInput {
                    outStatus.pointee = .noDataNow
                    return nil
                }

                suppliedInput = true
                outStatus.pointee = .haveData
                return buffer
            }

            guard status != .error,
                  outputBuffer.frameLength > 0,
                  let channelData = outputBuffer.int16ChannelData else {
                return
            }

            let byteCount = Int(outputBuffer.frameLength) * MemoryLayout<Int16>.size
            self.realtimeAudioEvidenceAccumulator.recordInt16AudioBuffer(
                outputBuffer,
                byteCount: byteCount,
                observedNS: Swift.max(DispatchTime.now().uptimeNanoseconds, 1)
            )
            if self.realtimeFirstAudioFrameNS == nil {
                let observedNS = Swift.max(DispatchTime.now().uptimeNanoseconds, 1)
                self.realtimeFirstAudioFrameNS = observedNS
                desktopAppendRuntimeBridgeDebugLog(
                    "\(desktopTraceClockFields()) openai realtime transcription first_audio_frame accepted=true byte_count=\(byteCount)"
                )
            }
            let audioData = Data(bytes: channelData[0], count: byteCount)
            self.sendRealtimeTranscriptionEvent([
                "type": "input_audio_buffer.append",
                "audio": audioData.base64EncodedString()
            ])
        }
    }

    private func sendRealtimeTranscriptionEvent(_ event: [String: Any]) {
        let eventType = (event["type"] as? String) ?? "unknown"
        guard let websocketTask = realtimeWebSocketTask,
              JSONSerialization.isValidJSONObject(event),
              let data = try? JSONSerialization.data(withJSONObject: event),
              let message = String(data: data, encoding: .utf8) else {
            return
        }

        if eventType.hasPrefix("input_audio_buffer."), !realtimeTransportReady {
            guard realtimeQueuedOutboundMessages.count < maxRealtimeQueuedOutboundMessages else {
                desktopAppendRuntimeBridgeDebugLog(
                    "\(desktopTraceClockFields()) openai realtime transcription outbound queue overflow event_type=\(boundedFailureLogToken(eventType)) redacted=true"
                )
                return
            }

            realtimeQueuedOutboundMessages.append(message)
            if realtimeQueuedOutboundMessages.count == 1 {
                desktopAppendRuntimeBridgeDebugLog(
                    "\(desktopTraceClockFields()) openai realtime transcription outbound queued awaiting_session_created=true event_type=\(boundedFailureLogToken(eventType))"
                )
            }
            return
        }

        websocketTask.send(.string(message)) { error in
            if error != nil {
                desktopAppendRuntimeBridgeDebugLog(
                    "openai realtime transcription send failure redacted=true event_type=\(boundedFailureLogToken(eventType))"
                )
            }
        }
    }

    private func markRealtimeTranscriptionTransportReady() {
        realtimeAudioQueue.async { [weak self] in
            guard let self else {
                return
            }

            self.realtimeTransportReady = true
            guard !self.realtimeQueuedOutboundMessages.isEmpty else {
                return
            }

            let messages = self.realtimeQueuedOutboundMessages
            self.realtimeQueuedOutboundMessages.removeAll(keepingCapacity: true)
            guard let websocketTask = self.realtimeWebSocketTask else {
                return
            }

            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) openai realtime transcription outbound flush count=\(messages.count)"
            )
            for message in messages {
                websocketTask.send(.string(message)) { error in
                    if error != nil {
                        desktopAppendRuntimeBridgeDebugLog(
                            "openai realtime transcription send failure redacted=true event_type=queued_input_audio_buffer"
                        )
                    }
                }
            }
        }
    }

    private func receiveRealtimeTranscriptionEvents() {
        guard let websocketTask = realtimeWebSocketTask else {
            return
        }

        websocketTask.receive { [weak self] result in
            guard let self else {
                return
            }

            switch result {
            case .success(let message):
                switch message {
                case .string(let text):
                    self.handleRealtimeTranscriptionEvent(text)
                case .data(let data):
                    if let text = String(data: data, encoding: .utf8) {
                        self.handleRealtimeTranscriptionEvent(text)
                    }
                @unknown default:
                    break
                }
                if self.realtimeWebSocketTask === websocketTask {
                    self.receiveRealtimeTranscriptionEvents()
                }
            case .failure:
                DispatchQueue.main.async {
                    guard self.realtimeWebSocketTask === websocketTask,
                          self.pendingRequest == nil else {
                        return
                    }

                    guard self.isListening || self.activeCaptureContext != nil else {
                        desktopAppendRuntimeBridgeDebugLog(
                            "\(desktopTraceClockFields()) openai realtime transcription prewarm websocket_closed_before_capture redacted=true"
                        )
                        self.teardownRealtimeTranscriptionSession()
                        return
                    }

                    desktopAppendRuntimeBridgeDebugLog(
                        "openai realtime transcription receive failure redacted=true"
                    )
                    self.recordFailure(
                        id: "failed_realtime_transcription_connection",
                        title: "Failed explicit voice request",
                        summary: "Realtime transcription connection failed before a committed transcript was available.",
                        detail: "Failure visibility only; provider internals were redacted and no fallback answer was counted as realtime success."
                    )
                    self.teardownRecognitionSession()
                }
            }
        }
    }

    private func handleRealtimeTranscriptionEvent(_ text: String) {
        guard let data = text.data(using: .utf8),
              let rawObject = try? JSONSerialization.jsonObject(with: data),
              let object = rawObject as? [String: Any],
              let eventType = object["type"] as? String else {
            return
        }

        if eventType == "transcription_session.created" || eventType == "session.created" {
            markRealtimeTranscriptionTransportReady()
            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) openai realtime transcription session created observed=true"
            )
            return
        }

        if eventType == "transcription_session.updated" || eventType == "session.updated" {
            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) openai realtime transcription session updated observed=true"
            )
            return
        }

        if eventType == "input_audio_buffer.speech_started" {
            DispatchQueue.main.async {
                if self.realtimeSpeechStartedNS == nil {
                    self.realtimeSpeechStartedNS = DispatchTime.now().uptimeNanoseconds
                    desktopAppendRuntimeBridgeDebugLog(
                        "\(desktopTraceClockFields()) openai realtime transcription speech_started observed=true"
                    )
                }
            }
            return
        }

        if eventType == "conversation.item.input_audio_transcription.delta",
           let delta = object["delta"] as? String,
           !delta.isEmpty {
            DispatchQueue.main.async {
                let observedNS = Swift.max(DispatchTime.now().uptimeNanoseconds, 1)
                if self.realtimeFirstDeltaNS == nil {
                    self.realtimeFirstDeltaNS = observedNS
                    desktopAppendRuntimeBridgeDebugLog(
                        "\(desktopTraceClockFields()) openai realtime transcription first_delta observed=true"
                    )
                }
                self.realtimePartialTranscript += delta
                self.updateRealtimeTranscriptPreviewIfAllowed(observedNS: observedNS)
            }
            return
        }

        if eventType == "conversation.item.input_audio_transcription.completed",
           let transcript = object["transcript"] as? String {
            DispatchQueue.main.async {
                self.completeRealtimeTranscription(with: transcript)
            }
            return
        }

        if eventType == "conversation.item.input_audio_transcription.failed" {
            let error = object["error"] as? [String: Any]
            let code = (error?["code"] as? String)
                .map { boundedFailureLogToken($0) } ?? "unavailable"
            let param = (error?["param"] as? String)
                .map { boundedFailureLogToken($0) } ?? "unavailable"
            desktopAppendRuntimeBridgeDebugLog(
                "openai realtime transcription failed event observed=true code=\(code) param=\(param) redacted=true"
            )
            DispatchQueue.main.async {
                self.recordFailure(
                    id: "failed_realtime_transcription_provider_transcription",
                    title: "Failed explicit voice request",
                    summary: "Realtime transcription failed closed before a committed transcript was available.",
                    detail: "Transcription failure details were redacted. No runtime execution, local answer, or raw provider payload was exposed."
                )
                self.teardownRecognitionSession()
            }
            return
        }

        if eventType == "error" {
            let error = object["error"] as? [String: Any]
            let code = (error?["code"] as? String)
                .map { boundedFailureLogToken($0) } ?? "unavailable"
            let param = (error?["param"] as? String)
                .map { boundedFailureLogToken($0) } ?? "unavailable"
            desktopAppendRuntimeBridgeDebugLog(
                "openai realtime transcription error event observed=true code=\(code) param=\(param) redacted=true"
            )
            DispatchQueue.main.async {
                self.recordFailure(
                    id: "failed_realtime_transcription_provider_error",
                    title: "Failed explicit voice request",
                    summary: "Realtime transcription failed closed before a committed transcript was available.",
                    detail: "Provider error details were redacted. No raw provider payload, audio archive, or local answer lane was exposed."
                )
                self.teardownRecognitionSession()
            }
            return
        }

        if eventType == "input_audio_buffer.committed" {
            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) openai realtime transcription audio_committed observed=true"
            )
        }
    }

    private func stopRealtimeTranscriptionCaptureAndCommit() {
        guard isListening else {
            recordFailure(
                id: "failed_realtime_transcription_not_listening",
                title: "Failed explicit voice request",
                summary: "Realtime transcription was not actively listening when commit was requested.",
                detail: "Explicit voice-turn production remains foreground-only and user-visible."
            )
            return
        }

        realtimeCaptureStopNS = Swift.max(DispatchTime.now().uptimeNanoseconds, 1)
        endCaptureInput()
        sendRealtimeTranscriptionEvent(["type": "input_audio_buffer.commit"])
        scheduleRealtimeCompletionTimeout()
        desktopAppendRuntimeBridgeDebugLog(
            "\(desktopTraceClockFields()) openai realtime transcription commit sent=true partial_chars=\(realtimePartialTranscript.count)"
        )
    }

    private func completeRealtimeTranscription(with transcript: String) {
        cancelRealtimeCompletionTimeout()
        let trimmedTranscript = transcript.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmedTranscript.isEmpty else {
            clearTransientTranscriptPreview()
            recordFailure(
                id: "failed_realtime_transcription_empty_transcript",
                title: "Failed explicit voice request",
                summary: "OpenAI realtime transcription completed without usable transcript text.",
                detail: "Failure visibility only; no runtime execution, tool call, or local answer was triggered."
            )
            teardownRecognitionSession()
            return
        }

        guard trimmedTranscript.utf8.count <= maxVoiceTurnBytes else {
            clearTransientTranscriptPreview()
            recordFailure(
                id: "failed_realtime_transcription_transcript_validation",
                title: "Failed explicit voice request",
                summary: "The realtime transcription result exceeded the bounded explicit voice transcript limit.",
                detail: "Failure visibility only; retry a shorter utterance. No final runtime dispatch was triggered."
            )
            teardownRecognitionSession()
            return
        }

        let captureStopNS = realtimeCaptureStopNS ?? Swift.max(DispatchTime.now().uptimeNanoseconds, 1)
        realtimeCaptureStopNS = captureStopNS
        endCaptureInput()

        guard !shouldIgnoreCommittedVoiceTranscriptArtifact(trimmedTranscript) else {
            ignoreCommittedVoiceTranscriptArtifact(
                trimmedTranscript,
                source: "realtime",
                keepRealtimeTransport: true
            )
            return
        }

        guard let audioCaptureRefState = preparedAudioCaptureRefState(
            captureStopNS: captureStopNS,
            finalTranscript: trimmedTranscript
        ) else {
            clearTransientTranscriptPreview()
            recordFailure(
                id: "failed_realtime_transcription_audio_capture_ref_unavailable",
                title: "Failed explicit voice request",
                summary: "The realtime transcription session could not preserve the existing explicit voice audio-capture-ref bundle.",
                detail: "Failure visibility only; no final runtime dispatch or local answer was produced."
            )
            teardownRecognitionSession()
            return
        }

        guard !shouldRejectCommittedUserTurnEvidence(audioCaptureRefState) else {
            clearTransientTranscriptPreview()
            recordFailure(
                id: "failed_realtime_transcription_unsafe_audio_evidence",
                title: "Failed explicit voice request",
                summary: "Desktop rejected the committed realtime transcript because the audio evidence was echo, noise, degraded, or otherwise unsafe.",
                detail: "Failure visibility only; no runtime dispatch, local answer, provider call, protected execution, memory write, or authority grant was produced."
            )
            resetRealtimeSegmentAfterRejectedEvidence()
            return
        }

        let deviceTurnSequence = nextDeviceTurnSequence()
        realtimeCommittedTranscript = trimmedTranscript
        transcriptPreview = trimmedTranscript
        let trimmedPartialTranscript = realtimePartialTranscript.trimmingCharacters(in: .whitespacesAndNewlines)
        pendingRequest = ExplicitVoiceTurnRequestState(
            id: "desktop_realtime_voice_turn_request_\(deviceTurnSequence)",
            deviceTurnSequence: deviceTurnSequence,
            transcript: trimmedTranscript,
            partialTranscript: trimmedPartialTranscript.isEmpty ? nil : trimmedPartialTranscript,
            byteCount: trimmedTranscript.utf8.count,
            audioCaptureRefState: audioCaptureRefState
        )
        desktopAppendRuntimeBridgeDebugLog(
            "\(desktopTraceClockFields()) openai realtime transcription completed stt_provider_id=\(DesktopVoiceProviderLane.sttProviderID) final_chars=\(trimmedTranscript.count) runtime_handoff=/v1/voice/turn"
        )
        completeStoppedCaptureSession()
    }

    private func shouldRejectCommittedUserTurnEvidence(_ state: DesktopVoiceTurnAudioCaptureRefState) -> Bool {
        if state.captureDegraded || state.streamGapDetected || state.aecUnstable {
            return true
        }

        if state.echoSafeConfidenceBP < 5_000 || state.speechLikenessBP < 5_000 {
            return true
        }

        guard let nearfieldConfidenceBP = state.nearfieldConfidenceBP,
              nearfieldConfidenceBP >= 4_000 else {
            return true
        }

        return false
    }

    private static let committedVoiceTranscriptArtifactTokens: Set<String> = [
        "ah", "eh", "er", "hm", "hmm", "huh", "ok", "okay",
        "so", "sure", "uh", "um", "umm", "yeah", "yep", "yup",
        "coming", "going", "typing", "clicking", "cough", "coughing",
        "breathing", "noise", "background", "waiting", "listening"
    ]

    private func shouldIgnoreCommittedVoiceTranscriptArtifact(_ transcript: String) -> Bool {
        let trimmed = transcript.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else {
            return true
        }

        let compact = trimmed.filter { !$0.isWhitespace }
        guard compact.contains(where: { $0.isLetter || $0.isNumber }) else {
            return true
        }

        let words = trimmed.split { character in
            !(character.isLetter || character.isNumber || character == "'")
        }
        guard words.count == 1 else {
            return false
        }

        let token = words[0].lowercased()
        if token.count == 1,
           token.contains(where: { $0.isLetter || $0.isNumber }) {
            return true
        }

        return Self.committedVoiceTranscriptArtifactTokens.contains(token)
    }

    private func ignoreCommittedVoiceTranscriptArtifact(
        _ transcript: String,
        source: String,
        keepRealtimeTransport: Bool
    ) {
        let finalChars = transcript.trimmingCharacters(in: .whitespacesAndNewlines).count
        clearTransientTranscriptPreview()
        pendingRequest = nil
        failedRequest = nil
        desktopAppendRuntimeBridgeDebugLog(
            "\(desktopTraceClockFields()) desktop committed voice transcript ignored reason=text_artifact source=\(boundedFailureLogToken(source)) final_chars=\(finalChars) rearm=\(keepRealtimeTransport)"
        )

        guard keepRealtimeTransport,
              let session = realtimeSession,
              let evidenceContext = activeCaptureContext?.evidenceContext else {
            completeStoppedCaptureSession()
            return
        }

        resetRealtimeSegmentAfterRejectedEvidence(reason: "text_artifact_keep_transport")
        beginRealtimeTranscriptionCapture(session: session, evidenceContext: evidenceContext)
    }

    private func scheduleRealtimeCompletionTimeout() {
        cancelRealtimeCompletionTimeout()
        let workItem = DispatchWorkItem { [weak self] in
            guard let self,
                  self.pendingRequest == nil,
                  self.realtimeWebSocketTask != nil else {
                return
            }

            self.recordFailure(
                id: "failed_realtime_transcription_timeout",
                title: "Failed explicit voice request",
                summary: "Realtime transcription timed out before a committed transcript was available.",
                detail: "Timeout handling is bounded and deterministic. No raw audio was retained and no local answer lane was used."
            )
            self.teardownRecognitionSession()
        }
        realtimeCompletionTimeoutWorkItem = workItem
        DispatchQueue.main.asyncAfter(deadline: .now() + 6.0, execute: workItem)
    }

    private func cancelRealtimeCompletionTimeout() {
        realtimeCompletionTimeoutWorkItem?.cancel()
        realtimeCompletionTimeoutWorkItem = nil
    }

    private func scheduleRealtimeMaxSessionDuration(_ durationMS: UInt64) {
        realtimeMaxSessionDurationWorkItem?.cancel()
        let boundedDelay = TimeInterval(Swift.max(5_000, Swift.min(durationMS, 300_000))) / 1_000
        let workItem = DispatchWorkItem { [weak self] in
            guard let self,
                  self.isListening,
                  self.realtimeWebSocketTask != nil else {
                return
            }

            self.recordFailure(
                id: "failed_realtime_transcription_session_duration",
                title: "Failed explicit voice request",
                summary: "Realtime transcription reached its bounded session duration before commit.",
                detail: "The session was closed deterministically to prevent runaway cost or stuck capture."
            )
            self.teardownRecognitionSession()
        }
        realtimeMaxSessionDurationWorkItem = workItem
        DispatchQueue.main.asyncAfter(deadline: .now() + boundedDelay, execute: workItem)
    }

    private func endCaptureInput() {
        cancelAutoPrepareAfterSilence()
        if audioEngine.isRunning {
            audioEngine.stop()
        }

        if hasInputTap {
            audioEngine.inputNode.removeTap(onBus: 0)
            hasInputTap = false
        }

        isListening = false
    }

    private func teardownRecognitionSession() {
        cancelAutoPrepareAfterSilence()
        endCaptureInput()
        activeCaptureContext = nil
        teardownRealtimeTranscriptionSession()
    }

    private func completeStoppedCaptureSession() {
        cancelAutoPrepareAfterSilence()
        activeCaptureContext = nil
        teardownRealtimeTranscriptionSession()
    }

    private func teardownRealtimeTranscriptionSession() {
        cancelRealtimeCompletionTimeout()
        realtimeMaxSessionDurationWorkItem?.cancel()
        realtimeMaxSessionDurationWorkItem = nil
        realtimeWebSocketTask?.cancel(with: .normalClosure, reason: nil)
        realtimeWebSocketTask = nil
        realtimeSession = nil
        realtimeAudioConverter = nil
        realtimeOutputFormat = nil
        realtimePartialTranscript = ""
        realtimeCommittedTranscript = ""
        realtimeCaptureStopNS = nil
        realtimeSpeechStartedNS = nil
        realtimeFirstDeltaNS = nil
        realtimeFirstAudioFrameNS = nil
        realtimePreviewSuppressedForEchoTail = false
        realtimeTransportReady = false
        realtimeQueuedOutboundMessages.removeAll(keepingCapacity: true)
        realtimeAudioQueue.sync {
            realtimeAudioEvidenceAccumulator = DesktopAudioEvidenceAccumulator()
        }
    }

    func clearTransientTranscriptPreview() {
        realtimePartialTranscript = ""
        realtimeCommittedTranscript = ""
        transcriptPreview = ""
        realtimePreviewSuppressedForEchoTail = false
    }

    private func resetRealtimeSegmentAfterRejectedEvidence(
        reason: String = "unsafe_evidence_keep_transport"
    ) {
        realtimePartialTranscript = ""
        realtimeCommittedTranscript = ""
        realtimeCaptureStopNS = nil
        realtimeSpeechStartedNS = nil
        realtimeFirstDeltaNS = nil
        realtimeFirstAudioFrameNS = nil
        realtimePreviewSuppressedForEchoTail = false
        transcriptPreview = ""

        if let activeCaptureContext {
            let refreshedContext = Self.makeCaptureSessionTransportContext(
                evidenceContext: activeCaptureContext.evidenceContext
            )
            self.activeCaptureContext = refreshedContext
            realtimeAudioQueue.sync {
                realtimeAudioEvidenceAccumulator.reset(captureStartNS: refreshedContext.tStartNS)
            }
        }

        desktopAppendRuntimeBridgeDebugLog(
            "\(desktopTraceClockFields()) desktop realtime transcription segment reset reason=\(boundedFailureLogToken(reason))"
        )
    }

    private func updateRealtimeTranscriptPreviewIfAllowed(observedNS: UInt64) {
        guard let activeCaptureContext else {
            transcriptPreview = realtimePartialTranscript
            return
        }

        let shouldSuppress = activeCaptureContext.evidenceContext.suppressesUnacceptedPreview(
            observedNS: observedNS,
            captureStartNS: activeCaptureContext.tStartNS,
            speechStartNS: realtimeSpeechStartedNS ?? realtimeFirstDeltaNS
        )
        guard shouldSuppress else {
            transcriptPreview = realtimePartialTranscript
            return
        }

        transcriptPreview = ""
        if !realtimePreviewSuppressedForEchoTail {
            realtimePreviewSuppressedForEchoTail = true
            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) desktop post-tts transcript preview suppressed reason=echo_tail_unaccepted"
            )
        }
    }

    private func scheduleAutoPrepareAfterSilenceIfNeeded(using transcript: String) {
        let trimmedTranscript = transcript.trimmingCharacters(in: .whitespacesAndNewlines)
        guard isListening,
              pendingRequest == nil,
              !trimmedTranscript.isEmpty else {
            cancelAutoPrepareAfterSilence()
            return
        }

        cancelAutoPrepareAfterSilence()
        let workItem = DispatchWorkItem { [weak self] in
            guard let self,
                  self.isListening,
                  self.pendingRequest == nil,
                  self.transcriptPreview.trimmingCharacters(in: .whitespacesAndNewlines) == trimmedTranscript else {
                return
            }

            self.stopCaptureAndPrepareVoiceTurn()
        }
        autoPrepareAfterSilenceWorkItem = workItem
        DispatchQueue.main.asyncAfter(
            deadline: .now() + autoPrepareAfterSilenceDelay,
            execute: workItem
        )
    }

    private func cancelAutoPrepareAfterSilence() {
        autoPrepareAfterSilenceWorkItem?.cancel()
        autoPrepareAfterSilenceWorkItem = nil
    }

    private func nextDeviceTurnSequence() -> UInt64 {
        let epochNowNS = desktopEpochNowNS()
        let nextSequence = Swift.max(epochNowNS, lastGeneratedDeviceTurnSequence &+ 1)
        lastGeneratedDeviceTurnSequence = nextSequence
        return nextSequence
    }

    private func recordFailure(id: String, title: String, summary: String, detail: String) {
        failedRequest = InterruptContinuityResponseFailureState(
            id: id,
            title: title,
            summary: summary,
            detail: detail
        )
        failedRequestSequence &+= 1
    }

    private func refreshPermissionState() {
        microphonePermission = Self.currentMicrophonePermission()
        transcriptionPermission = Self.currentTranscriptionPermission()
    }

    private func requestMicrophonePermissionIfNeeded(completion: @escaping (Bool) -> Void) {
        switch Self.currentMicrophonePermission() {
        case .granted:
            completion(true)
        case .denied, .restricted, .unavailable:
            completion(false)
        case .notRequested:
            AVCaptureDevice.requestAccess(for: .audio) { granted in
                completion(granted)
            }
        }
    }

    private func requestTranscriptionPermissionIfNeeded(completion: @escaping (Bool) -> Void) {
        completion(false)
    }

    private static func currentMicrophonePermission() -> VoicePermissionState {
        switch AVCaptureDevice.authorizationStatus(for: .audio) {
        case .authorized:
            return .granted
        case .denied:
            return .denied
        case .restricted:
            return .restricted
        case .notDetermined:
            return .notRequested
        @unknown default:
            return .unavailable
        }
    }

    private static func currentTranscriptionPermission() -> VoicePermissionState {
        .unavailable
    }

    private static func preferredLocale() -> Locale {
        if let identifier = Locale.preferredLanguages.first {
            return Locale(identifier: identifier)
        }

        return Locale(identifier: "en-US")
    }

    private static func makeCaptureSessionTransportContext(
        evidenceContext: DesktopAudioEvidenceContext
    ) -> CaptureSessionTransportContext {
        let tStartNS = Swift.max(DispatchTime.now().uptimeNanoseconds, 1)
        let selectedMic = boundedAudioCaptureToken(
            AVCaptureDevice.default(for: .audio)?.localizedName,
            fallback: "desktop_mic_default"
        )
        let selectedSpeaker = boundedAudioCaptureToken(
            nil,
            fallback: "desktop_speaker_default"
        )
        let localeTag = boundedAudioCaptureLocaleTag(
            Locale.preferredLanguages.first
        )

        return CaptureSessionTransportContext(
            streamID: tStartNS,
            preRollBufferID: Swift.max(tStartNS / 1_000_000, 1),
            tStartNS: tStartNS,
            localeTag: localeTag,
            deviceRoute: resolvedDesktopAudioDeviceRouteLabel(
                selectedMic: selectedMic,
                selectedSpeaker: selectedSpeaker
            ),
            selectedMic: selectedMic,
            selectedSpeaker: selectedSpeaker,
            evidenceContext: evidenceContext
        )
    }

    private func preparedAudioCaptureRefState(
        captureStopNS: UInt64,
        finalTranscript: String?
    ) -> DesktopVoiceTurnAudioCaptureRefState? {
        guard let activeCaptureContext else {
            return nil
        }

        let tStartNS = Swift.max(activeCaptureContext.tStartNS, 1)
        let tEndNS = Swift.max(captureStopNS, tStartNS &+ 1)
        let tCandidateStartNS = Swift.max(tStartNS, tEndNS &- min(320_000_000, tEndNS &- tStartNS))

        guard tEndNS > tStartNS, tCandidateStartNS >= tStartNS else {
            return nil
        }

        let finalTranscriptPresent = !(finalTranscript ?? "").trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
            || !realtimeCommittedTranscript.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
        let partialTranscriptPresent = !realtimePartialTranscript.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
            || !transcriptPreview.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
        let evidenceSnapshot = realtimeAudioQueue.sync {
            realtimeAudioEvidenceAccumulator.snapshot(
                captureStartNS: tStartNS,
                captureEndNS: tEndNS,
                finalTranscript: finalTranscript,
                finalTranscriptPresent: finalTranscriptPresent,
                partialTranscriptPresent: partialTranscriptPresent,
                speechStartNS: realtimeSpeechStartedNS ?? realtimeFirstDeltaNS,
                evidenceContext: activeCaptureContext.evidenceContext
            )
        }

        desktopAppendRuntimeBridgeDebugLog(
            "\(desktopTraceClockFields()) desktop audio evidence class=\(evidenceSnapshot.evidenceClass.rawValue) tts_active=\(evidenceSnapshot.ttsPlaybackActive) stream_gap=\(evidenceSnapshot.streamGapDetected) capture_degraded=\(evidenceSnapshot.captureDegraded) clipping_ratio_bp=\(evidenceSnapshot.clippingRatioBP) buffers=\(evidenceSnapshot.audioBufferCount) audible_ms=\(evidenceSnapshot.audibleAudioDurationMS) speech_like_ms=\(evidenceSnapshot.speechLikeAudioDurationMS) speech_like_buffers=\(evidenceSnapshot.speechLikeBufferCount) impulsive_noise_buffers=\(evidenceSnapshot.impulsiveNoiseBufferCount)"
        )

        return DesktopVoiceTurnAudioCaptureRefState(
            streamID: activeCaptureContext.streamID,
            preRollBufferID: activeCaptureContext.preRollBufferID,
            tStartNS: tStartNS,
            tEndNS: tEndNS,
            tCandidateStartNS: tCandidateStartNS,
            tConfirmedNS: tEndNS,
            localeTag: activeCaptureContext.localeTag,
            deviceRoute: activeCaptureContext.deviceRoute,
            selectedMic: activeCaptureContext.selectedMic,
            selectedSpeaker: activeCaptureContext.selectedSpeaker,
            ttsPlaybackActive: evidenceSnapshot.ttsPlaybackActive,
            detectionText: nil,
            detectionConfidenceBP: nil,
            vadConfidenceBP: evidenceSnapshot.vadConfidenceBP,
            acousticConfidenceBP: evidenceSnapshot.acousticConfidenceBP,
            prosodyConfidenceBP: evidenceSnapshot.prosodyConfidenceBP,
            speechLikenessBP: evidenceSnapshot.speechLikenessBP,
            echoSafeConfidenceBP: evidenceSnapshot.echoSafeConfidenceBP,
            nearfieldConfidenceBP: evidenceSnapshot.nearfieldConfidenceBP,
            captureDegraded: evidenceSnapshot.captureDegraded,
            streamGapDetected: evidenceSnapshot.streamGapDetected,
            aecUnstable: evidenceSnapshot.aecUnstable,
            deviceChanged: false,
            snrDBMilli: evidenceSnapshot.snrDBMilli,
            clippingRatioBP: evidenceSnapshot.clippingRatioBP,
            echoDelayMSMilli: evidenceSnapshot.echoDelayMSMilli,
            packetLossBP: 0,
            doubleTalkBP: evidenceSnapshot.doubleTalkBP,
            erleDBMilli: evidenceSnapshot.erleDBMilli,
            deviceFailures24H: 0,
            deviceRecoveries24H: 0,
            deviceMeanRecoveryMS: 100,
            deviceReliabilityBP: 9_900,
            timingJitterMSMilli: evidenceSnapshot.timingJitterMSMilli,
            timingDriftPPMMilli: 2_000,
            timingBufferDepthMSMilli: 1_250_000,
            timingUnderruns: 0,
            timingOverruns: 0
        )
    }
}

private final class DesktopWakeListenerController: ObservableObject {
    private struct CaptureSessionTransportContext {
        let streamID: UInt64
        let preRollBufferID: UInt64
        let tStartNS: UInt64
        let localeTag: String
        let deviceRoute: String
        let selectedMic: String
        let selectedSpeaker: String
        var evidenceContext: DesktopAudioEvidenceContext
    }

    @Published private(set) var microphonePermission: VoicePermissionState = .notRequested
    @Published private(set) var transcriptionPermission: VoicePermissionState = .notRequested
    @Published private(set) var listenerState: DesktopWakeListenerState = .idle
    @Published private(set) var transcriptPreview = ""
    @Published private(set) var pendingRequest: WakeTriggeredVoiceTurnRequestState?
    @Published private(set) var failedRequest: InterruptContinuityResponseFailureState?
    @Published private(set) var activePromptStateID: String?

    private let wakeTriggerPhrase = "Selene"
    private let maxVoiceTurnBytes = 16_384
    private let audioEngine = AVAudioEngine()
    private let audioEvidenceQueue = DispatchQueue(label: "selene.desktop.local-wake.audio-evidence")
    private let localWakeRecognizer = SFSpeechRecognizer(locale: Locale(identifier: "en-US"))
    private var hasInputTap = false
    private var lastGeneratedDeviceTurnSequence: UInt64 = 0
    private var activeCaptureContext: CaptureSessionTransportContext?
    private var audioEvidenceAccumulator = DesktopAudioEvidenceAccumulator()
    private var localWakeRecognitionRequest: SFSpeechAudioBufferRecognitionRequest?
    private var localWakeRecognitionTask: SFSpeechRecognitionTask?
    private var localWakeOutputFormat: AVAudioFormat?
    private var localWakeAudioConverter: AVAudioConverter?
    private var localWakePartialTranscript = ""
    private var localWakeCommittedTranscript = ""
    private var localWakeSpeechStartedNS: UInt64?
    private var localWakeFirstDeltaNS: UInt64?
    private var localWakeFirstAudioFrameLogged = false
    private var localWakeCandidateToken: String?
    private var localWakeCandidateFirstNS: UInt64?
    private var localWakeCandidateObservationCount = 0

    init(locale: Locale? = nil) {
        _ = locale
        refreshPermissionState()
    }

    func startListening(
        promptState: DesktopWakeListenerPromptState,
        evidenceContext: DesktopAudioEvidenceContext
    ) {
        failedRequest = nil

        guard !listenerState.isActiveForMicrophone else {
            return
        }

        guard pendingRequest == nil else {
            listenerState = .failed
            recordFailure(
                id: "failed_wake_listener_pending_request",
                title: "Failed wake listener start",
                summary: "A later bounded wake-listener session could not begin while the current wake-triggered voice request is already awaiting canonical handoff.",
                detail: "Foreground wake listening remains bounded and single-request only. This shell does not queue another local wake request, invent local session continuity, or fabricate assistant output."
            )
            return
        }

        transcriptPreview = ""
        activePromptStateID = promptState.id
        refreshPermissionState()
        requestMicrophonePermissionIfNeeded { [weak self] granted in
            guard let self else {
                return
            }

            DispatchQueue.main.async {
                self.refreshPermissionState()
                guard granted else {
                    self.listenerState = .failed
                    self.activePromptStateID = nil
                    self.recordFailure(
                        id: "failed_wake_listener_microphone_permission",
                        title: "Failed wake listener start",
                        summary: "Microphone permission is required before foreground wake listening can begin.",
                        detail: "The Desktop shell did not open the local wake listener, did not send pre-wake audio to a remote provider, and did not fabricate a wake-triggered voice turn."
                    )
                    return
                }

                self.requestTranscriptionPermissionIfNeeded { [weak self] speechGranted in
                    guard let self else {
                        return
                    }

                    DispatchQueue.main.async {
                        self.refreshPermissionState()
                        guard speechGranted else {
                            self.listenerState = .failed
                            self.activePromptStateID = nil
                            self.recordFailure(
                                id: "failed_wake_listener_speech_permission",
                                title: "Failed wake listener start",
                                summary: "Local on-device speech recognition permission is required before pre-wake wake listening can begin.",
                                detail: "The Desktop shell did not open OpenAI realtime, did not stream pre-wake audio remotely, and did not fabricate a wake-triggered voice turn."
                            )
                            return
                        }

                        self.beginLocalWakeCapture(evidenceContext: evidenceContext)
                    }
                }
            }
        }
    }

    func stopListening() {
        haltCaptureSession()
        failedRequest = nil
    }

    func haltCaptureSession() {
        teardownRecognitionSession()
        transcriptPreview = ""
        listenerState = .idle
        activePromptStateID = nil
    }

    func clearPendingPreparedWakeTurn() {
        pendingRequest = nil
        transcriptPreview = ""
        if listenerState != .failed {
            listenerState = .idle
        }
        activePromptStateID = nil
    }

    func markDispatching() {
        listenerState = .dispatching
    }

    func stageWakeTriggeredVoiceTurnFromExplicitCapture(
        transcript: String,
        audioCaptureRefState: DesktopVoiceTurnAudioCaptureRefState
    ) -> Bool {
        guard pendingRequest == nil,
              let prefixMatch = boundedWakePrefixMatch(in: transcript, wakeTriggerPhrase: wakeTriggerPhrase) else {
            return false
        }

        let boundedTranscript = prefixMatch.transcriptRemainder
            .trimmingCharacters(in: .whitespacesAndNewlines)

        guard boundedTranscript.utf8.count <= maxVoiceTurnBytes else {
            listenerState = .failed
            activePromptStateID = nil
            recordFailure(
                id: "failed_wake_listener_transcript_validation",
                title: "Failed wake-triggered voice request",
                summary: "The bounded post-wake transcript exceeded 16384 UTF-8 bytes before any canonical runtime dispatch occurred.",
                detail: "Failure visibility only; retry a shorter foreground wake utterance through the same bounded wake-listener surface. No authoritative transcript turn was appended locally."
            )
            return true
        }

        let deviceTurnSequence = nextDeviceTurnSequence()
        transcriptPreview = boundedTranscript
        pendingRequest = WakeTriggeredVoiceTurnRequestState(
            id: "desktop_wake_turn_request_\(deviceTurnSequence)",
            deviceTurnSequence: deviceTurnSequence,
            transcript: boundedTranscript,
            byteCount: boundedTranscript.utf8.count,
            wakeTriggerPhrase: wakeTriggerPhrase,
            audioCaptureRefState: audioCaptureRefState.withWakeDetectionCarrier(
                detectionText: prefixMatch.detectionText,
                detectionConfidenceBP: 10_000
            )
        )
        listenerState = .wakeRequestStaged
        activePromptStateID = nil
        return true
    }

    func updateActiveAudioEvidenceContext(_ evidenceContext: DesktopAudioEvidenceContext) {
        guard var activeCaptureContext else {
            return
        }

        activeCaptureContext.evidenceContext = evidenceContext
        self.activeCaptureContext = activeCaptureContext
    }

    private func beginLocalWakeCapture(evidenceContext: DesktopAudioEvidenceContext) {
        failedRequest = nil
        teardownRecognitionSession()
        refreshPermissionState()

        guard let recognizer = localWakeRecognizer, recognizer.isAvailable else {
            listenerState = .failed
            activePromptStateID = nil
            recordFailure(
                id: "failed_wake_listener_local_recognizer_unavailable",
                title: "Failed wake listener start",
                summary: "The approved local wake detector is unavailable on this Mac.",
                detail: "Pre-wake OpenAI realtime/STT was not opened, no pre-wake audio was sent remotely, and the shell failed closed before any wake-triggered request was created."
            )
            return
        }

        if #available(macOS 10.15, *) {
            guard recognizer.supportsOnDeviceRecognition else {
                listenerState = .failed
                activePromptStateID = nil
                recordFailure(
                    id: "failed_wake_listener_local_on_device_unavailable",
                    title: "Failed wake listener start",
                    summary: "The approved local wake detector cannot run fully on-device on this Mac.",
                    detail: "Pre-wake OpenAI realtime/STT was not opened, no pre-wake audio was sent remotely, and the shell failed closed rather than using a remote wake provider."
                )
                return
            }
        } else {
            listenerState = .failed
            activePromptStateID = nil
            recordFailure(
                id: "failed_wake_listener_local_on_device_unsupported",
                title: "Failed wake listener start",
                summary: "This macOS version does not expose the required on-device local wake detector.",
                detail: "Pre-wake OpenAI realtime/STT was not opened, no pre-wake audio was sent remotely, and the shell failed closed before any wake-triggered request was created."
            )
            return
        }

        let recognitionRequest = SFSpeechAudioBufferRecognitionRequest()
        recognitionRequest.shouldReportPartialResults = true
        if #available(macOS 10.15, *) {
            recognitionRequest.requiresOnDeviceRecognition = true
        }

        do {
            let captureContext = Self.makeCaptureSessionTransportContext(evidenceContext: evidenceContext)
            audioEvidenceQueue.sync {
                audioEvidenceAccumulator.reset(captureStartNS: captureContext.tStartNS)
            }
            let inputNode = audioEngine.inputNode
            let inputFormat = inputNode.outputFormat(forBus: 0)
            guard let outputFormat = AVAudioFormat(
                commonFormat: .pcmFormatInt16,
                sampleRate: 24_000,
                channels: 1,
                interleaved: false
            ),
            let converter = AVAudioConverter(from: inputFormat, to: outputFormat) else {
                listenerState = .failed
                activePromptStateID = nil
                recordFailure(
                    id: "failed_wake_listener_local_audio_format",
                    title: "Failed wake listener start",
                    summary: "The microphone audio format could not be converted into the local wake evidence stream.",
                    detail: "Pre-wake OpenAI realtime/STT was not opened, no pre-wake audio was sent remotely, and no wake-triggered request was fabricated."
                )
                return
            }

            localWakeRecognitionRequest = recognitionRequest
            localWakeOutputFormat = outputFormat
            localWakeAudioConverter = converter
            localWakePartialTranscript = ""
            localWakeCommittedTranscript = ""
            localWakeSpeechStartedNS = nil
            localWakeFirstDeltaNS = nil
            localWakeFirstAudioFrameLogged = false
            localWakeCandidateToken = nil
            localWakeCandidateFirstNS = nil
            localWakeCandidateObservationCount = 0
            transcriptPreview = ""
            activeCaptureContext = captureContext

            localWakeRecognitionTask = recognizer.recognitionTask(
                with: recognitionRequest
            ) { [weak self] result, error in
                self?.handleLocalWakeRecognitionResult(result, error: error)
            }

            inputNode.installTap(onBus: 0, bufferSize: 2_048, format: inputFormat) { [weak self] buffer, _ in
                recognitionRequest.append(buffer)
                self?.appendLocalWakeAudioEvidenceBuffer(buffer, inputFormat: inputFormat)
            }
            hasInputTap = true

            audioEngine.prepare()
            try audioEngine.start()
            listenerState = .listening
            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) desktop local wake capture_ready=true provider=openai_prewake=false remote_stt=false remote_audio=false ph1w_authority=pending"
            )
        } catch {
            teardownRecognitionSession()
            listenerState = .failed
            activePromptStateID = nil
            recordFailure(
                id: "failed_wake_listener_local_capture_start",
                title: "Failed wake listener start",
                summary: "The local wake capture session could not start from this Desktop surface.",
                detail: "Pre-wake OpenAI realtime/STT was not opened, no pre-wake audio was sent remotely, and no wake-triggered request was fabricated. Detail: \(error.localizedDescription)"
            )
        }
    }

    private func handleLocalWakeRecognitionResult(
        _ result: SFSpeechRecognitionResult?,
        error: Error?
    ) {
        DispatchQueue.main.async { [weak self] in
            guard let self,
                  self.localWakeRecognitionTask != nil,
                  self.listenerState == .listening,
                  self.pendingRequest == nil else {
                return
            }

            if let result {
                let transcript = result.bestTranscription.formattedString
                    .trimmingCharacters(in: .whitespacesAndNewlines)
                guard !transcript.isEmpty else {
                    return
                }

                if self.localWakeFirstDeltaNS == nil {
                    self.localWakeFirstDeltaNS = Swift.max(DispatchTime.now().uptimeNanoseconds, 1)
                }
                self.localWakePartialTranscript = transcript
                self.transcriptPreview = transcript
                desktopAppendRuntimeBridgeDebugLog(
                    "\(desktopTraceClockFields()) desktop local wake transcript partial_chars=\(transcript.count) provider=openai_prewake=false remote_stt=false ph1w_authority=pending"
                )

                guard let prefixMatch = boundedWakePrefixMatch(
                    in: transcript,
                    wakeTriggerPhrase: self.wakeTriggerPhrase
                ) else {
                    self.localWakeCandidateToken = nil
                    self.localWakeCandidateFirstNS = nil
                    self.localWakeCandidateObservationCount = 0
                    return
                }

                let confidenceBP = Self.localWakeRecognitionConfidenceBP(result)
                guard confidenceBP >= 3_500 else {
                    desktopAppendRuntimeBridgeDebugLog(
                        "\(desktopTraceClockFields()) desktop local wake final rejected reason=low_confidence confidence_bp=\(confidenceBP) provider=openai_prewake=false remote_stt=false ph1w_authority=pending"
                    )
                    return
                }

                let candidateToken = [
                    normalizedWakeRecognitionToken(prefixMatch.detectionText),
                    normalizedWakeRecognitionToken(prefixMatch.transcriptRemainder),
                    "\(prefixMatch.transcriptRemainder.utf8.count)",
                ].joined(separator: "|")
                let nowNS = Swift.max(DispatchTime.now().uptimeNanoseconds, 1)
                if self.localWakeCandidateToken == candidateToken {
                    self.localWakeCandidateObservationCount += 1
                } else {
                    self.localWakeCandidateToken = candidateToken
                    self.localWakeCandidateFirstNS = nowNS
                    self.localWakeCandidateObservationCount = 1
                }
                let stableForNS = nowNS.saturatingSubtract(self.localWakeCandidateFirstNS ?? nowNS)
                let hasPostWakeRemainder = !prefixMatch.transcriptRemainder
                    .trimmingCharacters(in: .whitespacesAndNewlines)
                    .isEmpty
                guard result.isFinal
                        || (
                            self.localWakeCandidateObservationCount >= 2
                            && stableForNS >= (hasPostWakeRemainder ? 320_000_000 : 180_000_000)
                        ) else {
                    desktopAppendRuntimeBridgeDebugLog(
                        "\(desktopTraceClockFields()) desktop local wake candidate pending observations=\(self.localWakeCandidateObservationCount) stable_for_ns=\(stableForNS) confidence_bp=\(confidenceBP) remainder_present=\(hasPostWakeRemainder) provider=openai_prewake=false remote_stt=false ph1w_authority=pending"
                    )
                    return
                }

                self.localWakeCommittedTranscript = prefixMatch.detectionText
                desktopAppendRuntimeBridgeDebugLog(
                    "\(desktopTraceClockFields()) desktop local wake detected final=\(result.isFinal) observations=\(self.localWakeCandidateObservationCount) stable_for_ns=\(stableForNS) chars=\(transcript.count) confidence_bp=\(confidenceBP) remainder_present=\(hasPostWakeRemainder) provider=openai_prewake=false remote_audio=false ph1w_authority=pending"
                )
                self.prepareWakeTriggeredVoiceTurnIfDetected(
                    prefixMatch: prefixMatch,
                    confidenceBP: confidenceBP
                )
                return
            }

            if let error {
                self.teardownRecognitionSession()
                self.listenerState = .failed
                self.activePromptStateID = nil
                self.recordFailure(
                    id: "failed_wake_listener_local_recognition_error",
                    title: "Failed wake listener start",
                    summary: "The approved local wake detector returned an error before wake could be accepted.",
                    detail: "Pre-wake OpenAI realtime/STT was not opened and no pre-wake audio was sent remotely. Detail: \(error.localizedDescription)"
                )
            }
        }
    }

    private static func localWakeRecognitionConfidenceBP(_ result: SFSpeechRecognitionResult) -> UInt16 {
        let segmentConfidences = result.bestTranscription.segments
            .map(\.confidence)
            .filter { $0.isFinite && $0 > 0 }
        guard !segmentConfidences.isEmpty else {
            return 7_000
        }

        let meanConfidence = segmentConfidences.reduce(Float(0), +) / Float(segmentConfidences.count)
        let boundedConfidence = Swift.max(Float(0), Swift.min(meanConfidence, Float(1)))
        return UInt16((boundedConfidence * 10_000).rounded())
    }

    private func appendLocalWakeAudioEvidenceBuffer(
        _ buffer: AVAudioPCMBuffer,
        inputFormat: AVAudioFormat
    ) {
        audioEvidenceQueue.async { [weak self] in
            guard let self,
                  let outputFormat = self.localWakeOutputFormat,
                  let converter = self.localWakeAudioConverter else {
                return
            }

            let inputFrameCapacity = AVAudioFrameCount(
                Double(buffer.frameLength) * outputFormat.sampleRate / inputFormat.sampleRate
            ) + 1
            guard let convertedBuffer = AVAudioPCMBuffer(
                pcmFormat: outputFormat,
                frameCapacity: inputFrameCapacity
            ) else {
                return
            }

            var conversionError: NSError?
            var consumed = false
            let status = converter.convert(to: convertedBuffer, error: &conversionError) { _, outStatus in
                if consumed {
                    outStatus.pointee = .noDataNow
                    return nil
                }

                consumed = true
                outStatus.pointee = .haveData
                return buffer
            }

            guard status != .error,
                  conversionError == nil,
                  convertedBuffer.frameLength > 0 else {
                return
            }

            let observedNS = Swift.max(DispatchTime.now().uptimeNanoseconds, 1)
            if self.localWakeSpeechStartedNS == nil {
                self.localWakeSpeechStartedNS = observedNS
            }

            let frameCount = Int(convertedBuffer.frameLength)
            self.audioEvidenceAccumulator.recordInt16AudioBuffer(
                convertedBuffer,
                byteCount: frameCount * MemoryLayout<Int16>.size,
                observedNS: observedNS
            )

            if !self.localWakeFirstAudioFrameLogged {
                self.localWakeFirstAudioFrameLogged = true
                desktopAppendRuntimeBridgeDebugLog(
                    "\(desktopTraceClockFields()) desktop local wake first_audio_frame bytes=\(frameCount * MemoryLayout<Int16>.size) provider=openai_prewake=false remote_audio=false"
                )
            }
        }
    }

    private func prepareWakeTriggeredVoiceTurnIfDetected(
        prefixMatch: WakePrefixMatch,
        confidenceBP: UInt16
    ) {
        guard listenerState == .listening,
              pendingRequest == nil else {
            return
        }

        let boundedTranscript = prefixMatch.transcriptRemainder
            .trimmingCharacters(in: .whitespacesAndNewlines)

        guard boundedTranscript.utf8.count <= maxVoiceTurnBytes else {
            endCaptureInput()
            completeStoppedCaptureSession()
            listenerState = .failed
            activePromptStateID = nil
            recordFailure(
                id: "failed_wake_listener_transcript_validation",
                title: "Failed wake-triggered voice request",
                summary: "The bounded post-wake transcript exceeded 16384 UTF-8 bytes before any canonical runtime dispatch occurred.",
                detail: "Failure visibility only; retry a shorter foreground wake utterance through the same bounded wake-listener surface. No authoritative transcript turn was appended locally."
            )
            return
        }

        let captureStopNS = Swift.max(DispatchTime.now().uptimeNanoseconds, 1)
        endCaptureInput()

        guard let audioCaptureRefState = preparedAudioCaptureRefState(
            captureStopNS: captureStopNS,
            detectionText: prefixMatch.detectionText,
            detectionConfidenceBP: confidenceBP
        ) else {
            completeStoppedCaptureSession()
            listenerState = .failed
            activePromptStateID = nil
            recordFailure(
                id: "failed_wake_listener_audio_capture_ref_unavailable",
                title: "Failed wake-triggered voice request",
                summary: "The bounded wake-listener session could not preserve a lawful desktop audio-capture-ref transport bundle for canonical wake-triggered ingress.",
                detail: "Failure visibility only; this shell fails closed when foreground wake capture state is structurally insufficient to populate the already-live adapter capture bundle requirements."
            )
            return
        }

        let deviceTurnSequence = nextDeviceTurnSequence()
        transcriptPreview = boundedTranscript
        pendingRequest = WakeTriggeredVoiceTurnRequestState(
            id: "desktop_wake_turn_request_\(deviceTurnSequence)",
            deviceTurnSequence: deviceTurnSequence,
            transcript: boundedTranscript,
            byteCount: boundedTranscript.utf8.count,
            wakeTriggerPhrase: wakeTriggerPhrase,
            audioCaptureRefState: audioCaptureRefState
        )
        listenerState = .wakeRequestStaged
        completeStoppedCaptureSession()
    }

    private func endCaptureInput() {
        if audioEngine.isRunning {
            audioEngine.stop()
        }

        if hasInputTap {
            audioEngine.inputNode.removeTap(onBus: 0)
            hasInputTap = false
        }

    }

    private func teardownRecognitionSession() {
        endCaptureInput()
        activeCaptureContext = nil
        teardownLocalWakeRecognitionSession()
    }

    private func nextDeviceTurnSequence() -> UInt64 {
        let epochNowNS = desktopEpochNowNS()
        let nextSequence = Swift.max(epochNowNS, lastGeneratedDeviceTurnSequence &+ 1)
        lastGeneratedDeviceTurnSequence = nextSequence
        return nextSequence
    }

    private func completeStoppedCaptureSession() {
        activeCaptureContext = nil
        teardownLocalWakeRecognitionSession()
    }

    private func teardownLocalWakeRecognitionSession() {
        localWakeRecognitionRequest?.endAudio()
        localWakeRecognitionTask?.cancel()
        localWakeRecognitionRequest = nil
        localWakeRecognitionTask = nil
        localWakeAudioConverter = nil
        localWakeOutputFormat = nil
        localWakePartialTranscript = ""
        localWakeCommittedTranscript = ""
        localWakeSpeechStartedNS = nil
        localWakeFirstDeltaNS = nil
        localWakeFirstAudioFrameLogged = false
        localWakeCandidateToken = nil
        localWakeCandidateFirstNS = nil
        localWakeCandidateObservationCount = 0
        audioEvidenceQueue.sync {
            audioEvidenceAccumulator = DesktopAudioEvidenceAccumulator()
        }
    }

    private func recordFailure(id: String, title: String, summary: String, detail: String) {
        failedRequest = InterruptContinuityResponseFailureState(
            id: id,
            title: title,
            summary: summary,
            detail: detail
        )
    }

    private func refreshPermissionState() {
        microphonePermission = Self.currentMicrophonePermission()
        transcriptionPermission = Self.currentTranscriptionPermission()
    }

    private func requestMicrophonePermissionIfNeeded(completion: @escaping (Bool) -> Void) {
        switch Self.currentMicrophonePermission() {
        case .granted:
            completion(true)
        case .denied, .restricted, .unavailable:
            completion(false)
        case .notRequested:
            AVCaptureDevice.requestAccess(for: .audio) { granted in
                completion(granted)
            }
        }
    }

    private func requestTranscriptionPermissionIfNeeded(completion: @escaping (Bool) -> Void) {
        switch Self.currentTranscriptionPermission() {
        case .granted:
            completion(true)
        case .denied, .restricted, .unavailable:
            completion(false)
        case .notRequested:
            SFSpeechRecognizer.requestAuthorization { status in
                completion(status == .authorized)
            }
        }
    }

    private static func currentMicrophonePermission() -> VoicePermissionState {
        switch AVCaptureDevice.authorizationStatus(for: .audio) {
        case .authorized:
            return .granted
        case .denied:
            return .denied
        case .restricted:
            return .restricted
        case .notDetermined:
            return .notRequested
        @unknown default:
            return .unavailable
        }
    }

    private static func currentTranscriptionPermission() -> VoicePermissionState {
        switch SFSpeechRecognizer.authorizationStatus() {
        case .authorized:
            return .granted
        case .denied:
            return .denied
        case .restricted:
            return .restricted
        case .notDetermined:
            return .notRequested
        @unknown default:
            return .unavailable
        }
    }

    private static func preferredLocale() -> Locale {
        if let identifier = Locale.preferredLanguages.first {
            return Locale(identifier: identifier)
        }

        return Locale(identifier: "en-US")
    }

    private static func makeCaptureSessionTransportContext(
        evidenceContext: DesktopAudioEvidenceContext
    ) -> CaptureSessionTransportContext {
        let tStartNS = Swift.max(DispatchTime.now().uptimeNanoseconds, 1)
        let selectedMic = boundedAudioCaptureToken(
            AVCaptureDevice.default(for: .audio)?.localizedName,
            fallback: "desktop_mic_default"
        )
        let selectedSpeaker = boundedAudioCaptureToken(
            nil,
            fallback: "desktop_speaker_default"
        )
        let localeTag = boundedAudioCaptureLocaleTag(
            Locale.preferredLanguages.first
        )

        return CaptureSessionTransportContext(
            streamID: tStartNS,
            preRollBufferID: Swift.max(tStartNS / 1_000_000, 1),
            tStartNS: tStartNS,
            localeTag: localeTag,
            deviceRoute: resolvedDesktopAudioDeviceRouteLabel(
                selectedMic: selectedMic,
                selectedSpeaker: selectedSpeaker
            ),
            selectedMic: selectedMic,
            selectedSpeaker: selectedSpeaker,
            evidenceContext: evidenceContext
        )
    }

    private func preparedAudioCaptureRefState(
        captureStopNS: UInt64,
        detectionText: String,
        detectionConfidenceBP: UInt16
    ) -> DesktopVoiceTurnAudioCaptureRefState? {
        guard let activeCaptureContext else {
            return nil
        }

        let tStartNS = Swift.max(activeCaptureContext.tStartNS, 1)
        let tEndNS = Swift.max(captureStopNS, tStartNS &+ 1)
        let tCandidateStartNS = Swift.max(tStartNS, tEndNS &- min(320_000_000, tEndNS &- tStartNS))

        guard tEndNS > tStartNS, tCandidateStartNS >= tStartNS else {
            return nil
        }

        let finalTranscriptPresent = !localWakeCommittedTranscript.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
            || !detectionText.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
        let partialTranscriptPresent = !localWakePartialTranscript.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
            || !transcriptPreview.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
        let evidenceSnapshot = audioEvidenceQueue.sync {
            audioEvidenceAccumulator.snapshot(
                captureStartNS: tStartNS,
                captureEndNS: tEndNS,
                finalTranscript: detectionText,
                finalTranscriptPresent: finalTranscriptPresent,
                partialTranscriptPresent: partialTranscriptPresent,
                speechStartNS: localWakeSpeechStartedNS
                    ?? localWakeFirstDeltaNS,
                evidenceContext: activeCaptureContext.evidenceContext
            )
        }

        desktopAppendRuntimeBridgeDebugLog(
            "desktop wake audio evidence class=\(evidenceSnapshot.evidenceClass.rawValue) tts_active=\(evidenceSnapshot.ttsPlaybackActive) stream_gap=\(evidenceSnapshot.streamGapDetected) capture_degraded=\(evidenceSnapshot.captureDegraded) clipping_ratio_bp=\(evidenceSnapshot.clippingRatioBP) buffers=\(evidenceSnapshot.audioBufferCount) audible_ms=\(evidenceSnapshot.audibleAudioDurationMS) speech_like_ms=\(evidenceSnapshot.speechLikeAudioDurationMS) speech_like_buffers=\(evidenceSnapshot.speechLikeBufferCount) impulsive_noise_buffers=\(evidenceSnapshot.impulsiveNoiseBufferCount)"
        )

        return DesktopVoiceTurnAudioCaptureRefState(
            streamID: activeCaptureContext.streamID,
            preRollBufferID: activeCaptureContext.preRollBufferID,
            tStartNS: tStartNS,
            tEndNS: tEndNS,
            tCandidateStartNS: tCandidateStartNS,
            tConfirmedNS: tEndNS,
            localeTag: activeCaptureContext.localeTag,
            deviceRoute: activeCaptureContext.deviceRoute,
            selectedMic: activeCaptureContext.selectedMic,
            selectedSpeaker: activeCaptureContext.selectedSpeaker,
            ttsPlaybackActive: evidenceSnapshot.ttsPlaybackActive,
            detectionText: detectionText,
            detectionConfidenceBP: detectionConfidenceBP,
            vadConfidenceBP: evidenceSnapshot.vadConfidenceBP,
            acousticConfidenceBP: evidenceSnapshot.acousticConfidenceBP,
            prosodyConfidenceBP: evidenceSnapshot.prosodyConfidenceBP,
            speechLikenessBP: evidenceSnapshot.speechLikenessBP,
            echoSafeConfidenceBP: evidenceSnapshot.echoSafeConfidenceBP,
            nearfieldConfidenceBP: evidenceSnapshot.nearfieldConfidenceBP,
            captureDegraded: evidenceSnapshot.captureDegraded,
            streamGapDetected: evidenceSnapshot.streamGapDetected,
            aecUnstable: evidenceSnapshot.aecUnstable,
            deviceChanged: false,
            snrDBMilli: evidenceSnapshot.snrDBMilli,
            clippingRatioBP: evidenceSnapshot.clippingRatioBP,
            echoDelayMSMilli: evidenceSnapshot.echoDelayMSMilli,
            packetLossBP: 0,
            doubleTalkBP: evidenceSnapshot.doubleTalkBP,
            erleDBMilli: evidenceSnapshot.erleDBMilli,
            deviceFailures24H: 0,
            deviceRecoveries24H: 0,
            deviceMeanRecoveryMS: 100,
            deviceReliabilityBP: 9_900,
            timingJitterMSMilli: evidenceSnapshot.timingJitterMSMilli,
            timingDriftPPMMilli: 2_000,
            timingBufferDepthMSMilli: 1_250_000,
            timingUnderruns: 0,
            timingOverruns: 0
        )
    }
}

private enum DesktopRecoveryDisplayState: String, Equatable {
    case recovering = "RECOVERING"
    case degradedRecovery = "DEGRADED_RECOVERY"
    case quarantinedLocalState = "QUARANTINED_LOCAL_STATE"
}

private enum DesktopInterruptDisplayState: String, Equatable {
    case interruptVisible = "INTERRUPT_VISIBLE"
}

private func resolvedRecoveryDisplayState(
    recoveryMode: CanonicalRecoveryMode?,
    reconciliationDecision: CanonicalReconciliationDecision?
) -> DesktopRecoveryDisplayState? {
    if recoveryMode == .quarantinedLocalState || reconciliationDecision == .quarantineLocalState {
        return .quarantinedLocalState
    }

    switch recoveryMode {
    case .recovering:
        return .recovering
    case .degradedRecovery:
        return .degradedRecovery
    default:
        return nil
    }
}

private func resolvedInterruptDisplayState(
    interruptSubjectRelation: CanonicalInterruptSubjectRelation?,
    interruptContinuityOutcome: CanonicalInterruptContinuityOutcome?,
    interruptResumePolicy: CanonicalInterruptResumePolicy?
) -> DesktopInterruptDisplayState? {
    if interruptSubjectRelation == .uncertain {
        return .interruptVisible
    }

    if interruptContinuityOutcome == .switchTopicThenReturnCheck {
        return .interruptVisible
    }

    if interruptResumePolicy == .resumeLater {
        return .interruptVisible
    }

    return nil
}

private func recoveryPostureRowsForVisibleSession(
    sessionState: String,
    sessionID: String,
    recoveryMode: CanonicalRecoveryMode?,
    reconciliationDecision: CanonicalReconciliationDecision?
) -> [(label: String, value: String)] {
    var rows: [(label: String, value: String)] = [
        ("session_state", sessionState),
        ("session_id", sessionID),
    ]

    if let recoveryMode {
        rows.append(("recovery_mode", recoveryMode.rawValue))
    }

    if let reconciliationDecision {
        rows.append(("reconciliation_decision", reconciliationDecision.rawValue))
    }

    return rows
}

private struct DesktopSessionHeaderContext: Equatable {
    let sessionState: String
    let sessionID: String
    let sessionAttachOutcome: String
    let recoveryMode: CanonicalRecoveryMode?
    let reconciliationDecision: CanonicalReconciliationDecision?

    init(
        sessionState: String,
        sessionID: String,
        sessionAttachOutcome: String,
        recoveryMode: CanonicalRecoveryMode? = nil,
        reconciliationDecision: CanonicalReconciliationDecision? = nil
    ) {
        self.sessionState = sessionState
        self.sessionID = sessionID
        self.sessionAttachOutcome = sessionAttachOutcome
        self.recoveryMode = recoveryMode
        self.reconciliationDecision = reconciliationDecision
    }

    init?(url: URL) {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false) else {
            return nil
        }

        let queryItems = components.queryItems ?? []
        guard
            let sessionState = boundedHint(
                firstQueryValue(in: queryItems, name: "session_state")
            ),
            let sessionID = boundedHint(
                firstQueryValue(in: queryItems, name: "session_id")
            ),
            let sessionAttachOutcome = canonicalSessionAttachOutcome(
                firstQueryValue(in: queryItems, name: "session_attach_outcome")
            )
        else {
            return nil
        }

        self.sessionState = sessionState
        self.sessionID = sessionID
        self.sessionAttachOutcome = sessionAttachOutcome
        self.recoveryMode = CanonicalRecoveryMode.parse(
            firstQueryValue(in: queryItems, name: "recovery_mode")
        )
        self.reconciliationDecision = CanonicalReconciliationDecision.parse(
            firstQueryValue(in: queryItems, name: "reconciliation_decision")
        )
    }
}

