    init(
        stableID: String? = nil,
        speaker: String,
        posture: String,
        body: String,
        detail: String,
        sourceSurface: String
    ) {
        self.speaker = speaker
        self.posture = posture
        self.body = body
        self.detail = detail
        self.sourceSurface = sourceSurface
        self.stableID = stableID
            ?? [
                speaker,
                posture,
                body,
                detail,
                sourceSurface,
            ].joined(separator: "::")
    }

