            onboardingStatus ?? "onboarding_status_not_provided",
            requiredVerificationGates.joined(separator: "|"),
        ].joined(separator: "::")
    }
}

struct DesktopEmployeeSenderVerifyCommitPromptState: Identifiable, Equatable {
    let onboardingSessionID: String
