    @State private var desktopVoiceAnswerPresentationStartedNS: UInt64?
    @State private var desktopMeetingRecordingUnavailableAlertIsPresented: Bool = false
    @State private var desktopSearchRequestFailedRequest: InterruptContinuityResponseFailureState?
    @State private var desktopToolRequestFailedRequest: InterruptContinuityResponseFailureState?
    @State private var desktopLastGeneratedTypedTurnSequence: UInt64 = 0
    @State private var lastStagedWakeTriggeredVoiceTurnRequestState: WakeTriggeredVoiceTurnRequestState?
    @State private var desktopWakeTriggeredDispatchInFlightRequestID: String?
    @State private var desktopWakeAutoStartAttemptedPromptID: String?
    @State private var desktopWakeAutoStartSuppressedPromptID: String?
    @State private var desktopPresentedSecondaryPanel: DesktopShellSecondaryPanel?
    @State private var desktopAccountMenuIsPresented: Bool = false
    @AppStorage("selene.desktop.controlledWake.enabled")
    private var desktopControlledWakeEnabled: Bool = false
    private let maxDesktopTypedTurnBytes = 16_384
    // Match the audio-evidence echo-risk window so post-wake capture can arm promptly
    // without bypassing the committed transcript self-echo gate.
    private let desktopOpenAITtsSelfEchoTailReleaseDelay: TimeInterval = 0.15
    private let desktopStage6IdleCloseDelayNS: UInt64 = 30_000_000_000
    private let desktopConversationBottomAnchorID = "desktop_conversation_bottom_anchor"

    var body: some View {
        Group {
            if let operationalConversationShellState = desktopOperationalConversationShellState {
                desktopOperationalConversationShell(operationalConversationShellState)
            } else {
                desktopEvidenceFirstOperationalShell
            }
        }
        .padding(.leading, 0)
        .padding(.vertical, 24)
        .frame(minWidth: 680, minHeight: 520, alignment: .topLeading)
        .background(Color(nsColor: .windowBackgroundColor))
        .sheet(item: $desktopPresentedSecondaryPanel) { panel in
            if let operationalConversationShellState = desktopOperationalConversationShellState {
                desktopOperationalSecondaryPanelSheet(panel, state: operationalConversationShellState)
            } else {
                desktopEvidenceFirstSecondaryPanelSheet(panel)
            }
        }
        .sheet(
            isPresented: Binding(
                get: { desktopSidebarRenameConversationKey != nil },
                set: { isPresented in
                    if !isPresented {
                        desktopSidebarRenameConversationKey = nil
                        desktopSidebarRenameDraft = ""
                    }
                }
            )
        ) {
            desktopSidebarRenameSheet
        }
        .task(id: desktopAvailabilityStatusSnapshot.id) {
            synchronizeDesktopAvailabilityStatus()
        }
        .task(id: explicitVoiceController.pendingRequest?.id) {
            await dispatchPreparedExplicitVoiceRequestIfNeeded()
            await synchronizeDesktopWakeListenerLifecycleState()
        }
        .task(id: explicitVoiceController.failedRequestSequence) {
            if explicitVoiceController.failedRequest?.id == "failed_realtime_transcription_unsafe_audio_evidence"
                || explicitVoiceController.failedRequest?.id == "failed_explicit_voice_unsafe_audio_evidence" {
                desktopAppendRuntimeBridgeDebugLog(
                    "desktop unsafe voice evidence rejected rearm=evidence_gated_duplex"
                )
                desktopAttemptResumeComposerVoiceModeAfterUnsafeEvidenceRejection()
            }
            desktopAttemptResumeComposerVoiceModeAfterTransientRealtimeFailureIfNeeded(
                explicitVoiceController.failedRequest?.id
            )
            await synchronizeDesktopWakeListenerLifecycleState()
        }
        .onReceive(desktopWakeListenerController.$pendingRequest) { pendingRequest in
            desktopAppendRuntimeBridgeDebugLog(
                "desktop wake pending subscriber observed pending=\(pendingRequest != nil)"
            )
            guard let pendingRequest,
                  desktopWakeListenerController.listenerState != .dispatching,
                  lastStagedWakeTriggeredVoiceTurnRequestState?.id != pendingRequest.id else {
                return
            }

            Task { @MainActor in
                await dispatchPreparedWakeTriggeredVoiceRequestIfNeeded()
                await synchronizeDesktopWakeListenerLifecycleState()
            }
        }
        .onReceive(desktopWakeListenerController.$listenerState) { listenerState in
            desktopAppendRuntimeBridgeDebugLog(
                "desktop wake listener state subscriber observed state=\(listenerState.rawValue)"
            )
            synchronizeDesktopAvailabilityStatus()
            Task { @MainActor in
                await recoverDesktopWakeListenerAfterTransientFailureIfNeeded()
                await synchronizeDesktopWakeListenerLifecycleState()
            }
        }
        .task(id: desktopTypedTurnPendingRequest?.id) {
            await dispatchPreparedTypedTurnRequestIfNeeded()
            await synchronizeDesktopWakeListenerLifecycleState()
        }
        .task(id: desktopOnboardingEntryContext?.id) {
            await openInviteLinkAndStartOnboardingIfNeeded()
        }
        .task(id: desktopOnboardingContinuePromptSeedID) {
            await fetchOnboardingContinuePromptIfNeeded()
        }
        .task(id: desktopPairingCompletionPromptState?.id) {
            synchronizeDesktopPairingCompletionReadyTimeHandoffState()
        }
        .task(id: desktopWakeProfileAvailabilityPromptState?.id) {
            synchronizeDesktopWakeProfileAvailabilityRuntimeOutcomeState()
        }
        .task(id: desktopWakeListenerPromptState?.id) {
            await synchronizeDesktopWakeListenerLifecycleState()
        }
        .task(id: explicitVoiceController.isListening) {
            synchronizeDesktopAvailabilityStatus()
            await synchronizeDesktopWakeListenerLifecycleState()
        }
        .task(id: explicitVoiceController.pendingRequest?.id) {
            await synchronizeDesktopWakeListenerLifecycleState()
        }
        .task(id: desktopOperationalConversationShellState?.id) {
            await synchronizeDesktopWakeListenerLifecycleState()
            await synchronizeDesktopSessionRecentListRuntimeOutcomeState()
            await synchronizeDesktopSessionPostureEvidenceRuntimeOutcomeState()
        }
        .task(id: desktopSessionAttachRuntimeOutcomeState?.id) {
            await synchronizeDesktopSessionRecentListRuntimeOutcomeState()
        }
        .task(id: desktopSessionMultiPostureResumeRuntimeOutcomeState?.id) {
            await synchronizeDesktopSessionRecentListRuntimeOutcomeState()
        }
        .task(id: desktopSessionMultiPostureEntryRuntimeOutcomeState?.id) {
            await synchronizeDesktopSessionRecentListRuntimeOutcomeState()
        }
        .task(id: desktopSessionRecentListRuntimeOutcomeState?.id) {
            await synchronizeDesktopSessionPostureEvidenceRuntimeOutcomeState()
        }
        .task(id: desktopSelectedRecentSessionID) {
            await synchronizeDesktopSessionPostureEvidenceRuntimeOutcomeState()
        }
        .task(id: scenePhase) {
            if scenePhase != .active {
                desktopHandleScreenVisibilityChangedWhilePreservingVoicePosture(
                    reason: "scene_phase_not_active"
                )
            }
            synchronizeDesktopAvailabilityStatus()
            await synchronizeDesktopWakeListenerLifecycleState()
        }
        .onReceive(NotificationCenter.default.publisher(for: NSApplication.didHideNotification)) { _ in
            desktopHandleScreenVisibilityChangedWhilePreservingVoicePosture(reason: "app_hidden")
            synchronizeDesktopAvailabilityStatus()
            Task { @MainActor in
                await synchronizeDesktopWakeListenerLifecycleState()
            }
        }
        .onReceive(NotificationCenter.default.publisher(for: NSWindow.didMiniaturizeNotification)) { _ in
            desktopHandleScreenVisibilityChangedWhilePreservingVoicePosture(reason: "window_miniaturized")
            synchronizeDesktopAvailabilityStatus()
            Task { @MainActor in
                await synchronizeDesktopWakeListenerLifecycleState()
            }
        }
        .onReceive(desktopAuthoritativeReplyPlaybackController.$playbackState) { playbackState in
            desktopAuthoritativeReplyPlaybackState = playbackState
            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) desktop openai tts playback phase=\(playbackState.phase.rawValue)"
            )
            updateDesktopOpenAITtsPlaybackEvidenceClock(playbackState)
            synchronizeDesktopAvailabilityStatus()
            if playbackState.phase != .speaking,
               playbackState.phase != .requesting,
               (desktopOpenAITtsSelfEchoGateActive
                    || desktopComposerVoiceModeAwaitingReplyPlaybackCompletion) {
                releaseDesktopOpenAITtsSelfEchoGateAfterCooldown(reason: "playback_state_\(playbackState.phase.rawValue)")
            }
        }
        .onDisappear {
            explicitVoiceController.haltCaptureSession()
            desktopWakeListenerController.haltCaptureSession()
            desktopCanonicalRuntimeBridge.stopManagedAdapter()
            desktopAuthoritativeReplyPlaybackController.reset()
            desktopDockIconPulseController.clearAvailabilityStatus()
        }
        .onOpenURL { url in
            if let context = DesktopOnboardingEntryContext(url: url) {
                if desktopOnboardingEntryContext?.id != context.id {
                    desktopInviteOpenRuntimeOutcomeState = nil
                    desktopOnboardingContinueRuntimeOutcomeState = nil
                    desktopPlatformSetupReceiptRuntimeOutcomeState = nil
                    desktopTermsAcceptRuntimeOutcomeState = nil
                    desktopEmployeePhotoCaptureSendRuntimeOutcomeState = nil
                    desktopEmployeeSenderVerifyCommitRuntimeOutcomeState = nil
                    desktopPrimaryDeviceConfirmRuntimeOutcomeState = nil
                    desktopVoiceEnrollRuntimeOutcomeState = nil
                    desktopWakeEnrollStartDraftRuntimeOutcomeState = nil
                    desktopWakeEnrollSampleCommitRuntimeOutcomeState = nil
                    desktopWakeEnrollCompleteCommitRuntimeOutcomeState = nil
                    desktopEmoPersonaLockRuntimeOutcomeState = nil
                    desktopAccessProvisionCommitRuntimeOutcomeState = nil
                    desktopCompleteCommitRuntimeOutcomeState = nil
                    desktopPairingCompletionCommitRuntimeOutcomeState = nil
                    desktopReadyTimeHandoffState = nil
                    desktopWakeProfileAvailabilityRuntimeOutcomeState = nil
                    desktopOnboardingContinueFieldInput = ""
                    desktopEmployeePhotoCaptureSendPhotoBlobRefInput = ""
                    desktopEmployeeSenderVerifyCommitSelectedDecision = "CONFIRM"
                }
                desktopOnboardingEntryContext = context
            }

            if let context = DesktopSessionActiveVisibleContext(url: url) {
                clearInterruptResponseState()
                latestSessionActiveVisibleContext = context
                latestSessionSoftClosedVisibleContext = nil
                latestSessionSuspendedVisibleContext = nil

                if let sessionAttachOutcome = context.sessionAttachOutcome {
                    let headerContext = DesktopSessionHeaderContext(
                        sessionState: context.sessionState,
                        sessionID: context.sessionID,
                        sessionAttachOutcome: sessionAttachOutcome,
                        recoveryMode: context.recoveryMode,
                        reconciliationDecision: context.reconciliationDecision
                    )
                    latestSessionHeaderContext = headerContext
                    recordObservedSessionSurface(.sessionHeader(headerContext))
                } else if latestSessionHeaderContext?.sessionID != context.sessionID {
                    latestSessionHeaderContext = nil
                }

                recordObservedSessionSurface(.sessionActive(context))

                return
            }

            if let context = DesktopSessionSoftClosedVisibleContext(url: url) {
                clearInterruptResponseState()
                latestSessionSoftClosedVisibleContext = context
                latestSessionActiveVisibleContext = nil
                latestSessionSuspendedVisibleContext = nil

                if latestSessionHeaderContext?.sessionID != context.sessionID {
                    latestSessionHeaderContext = nil
                }

                recordObservedSessionSurface(.sessionSoftClosed(context))

                return
            }

            if let context = DesktopSessionSuspendedVisibleContext(url: url) {
                clearInterruptResponseState()
                latestSessionSuspendedVisibleContext = context
                latestSessionActiveVisibleContext = nil
                latestSessionSoftClosedVisibleContext = nil

                if latestSessionHeaderContext?.sessionID != context.sessionID {
                    latestSessionHeaderContext = nil
                }

                recordObservedSessionSurface(.sessionSuspended(context))

                return
            }

            if let context = DesktopSessionHeaderContext(url: url) {
                clearInterruptResponseState()
                latestSessionHeaderContext = context
                latestSessionActiveVisibleContext = nil
                latestSessionSoftClosedVisibleContext = nil
                latestSessionSuspendedVisibleContext = nil
                recordObservedSessionSurface(.sessionHeader(context))
            }
        }
    }

    private var desktopEvidenceFirstOperationalShell: some View {
        desktopChatShellLayout {
            if let preReadyConversationPrimaryPaneState = desktopPreReadyConversationPrimaryPaneState {
                desktopOperationalConversationMainPane(preReadyConversationPrimaryPaneState)
            } else {
                desktopEvidenceFirstConversationPane
            }
        }
    }

    private var desktopSidebarHistorySurfaces: [DesktopObservedSessionSurface] {
        var surfaces: [DesktopObservedSessionSurface] = []

        if let currentDominantObservedSessionSurface {
            surfaces.append(currentDominantObservedSessionSurface)
        }

        for surface in observedSessionSurfaces where !surfaces.contains(where: { $0.id == surface.id }) {
            surfaces.append(surface)
        }

        return surfaces
    }

    private var desktopAllSidebarHistoryItems: [DesktopSidebarConversationItem] {
        var items: [DesktopSidebarConversationItem] = []

        for surface in desktopSidebarHistorySurfaces {
            let conversationKey = desktopConversationHistoryKey(for: surface)
            if !items.contains(where: { $0.conversationKey == conversationKey }) {
                items.append(
                    DesktopSidebarConversationItem(
                        conversationKey: conversationKey,
                        surface: surface
                    )
                )
            }
        }

        for historyEntry in desktopPersistedConversationTimelineHistory {
            if !items.contains(where: { $0.conversationKey == historyEntry.conversationKey }) {
                items.append(
                    DesktopSidebarConversationItem(
                        conversationKey: historyEntry.conversationKey,
                        surface: nil
                    )
                )
            }
        }

        let visibleItems = items.filter { item in
            let conversationKey = item.conversationKey
            let metadata = desktopSidebarConversationMetadata[conversationKey] ?? .init()

            guard !metadata.isArchived, !metadata.isDeleted else {
                return false
            }
            
            return true
        }

        return visibleItems.sorted { lhs, rhs in
            let lhsKey = lhs.conversationKey
            let rhsKey = rhs.conversationKey
            let lhsMetadata = desktopSidebarConversationMetadata[lhsKey] ?? .init()
            let rhsMetadata = desktopSidebarConversationMetadata[rhsKey] ?? .init()

            if lhsMetadata.isPinned != rhsMetadata.isPinned {
                return lhsMetadata.isPinned
            }

            return items.firstIndex(where: { $0.conversationKey == lhs.conversationKey }) ?? 0
                < items.firstIndex(where: { $0.conversationKey == rhs.conversationKey }) ?? 0
        }
    }

    private var desktopVisibleSidebarHistoryItems: [DesktopSidebarConversationItem] {
        let trimmedQuery = desktopSidebarSearchQuery
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .localizedLowercase

        guard !trimmedQuery.isEmpty else {
            return desktopAllSidebarHistoryItems
        }

        return desktopAllSidebarHistoryItems.filter { item in
            let title = desktopSidebarHistoryTitle(for: item).localizedLowercase
            let preview = desktopSidebarHistoryPreview(for: item).localizedLowercase
            return title.contains(trimmedQuery) || preview.contains(trimmedQuery)
        }
    }

    private var desktopSidebarSearchResults: [DesktopSidebarConversationItem] {
        let trimmedQuery = desktopSidebarSearchQuery
            .trimmingCharacters(in: .whitespacesAndNewlines)

        guard !trimmedQuery.isEmpty else {
            return []
        }

        return desktopVisibleSidebarHistoryItems
    }

    private func desktopConversationHistoryKey(for surface: DesktopObservedSessionSurface) -> String {
        switch surface {
        case .sessionHeader(let context):
            return "session::\(context.sessionID)"
        case .sessionActive(let context):
            return "session::\(context.sessionID)"
        case .sessionSoftClosed(let context):
            return "session::\(context.sessionID)"
        case .sessionSuspended(let context):
            return "session::\(context.sessionID)"
        }
    }

    private func desktopPersistedTimelineEntries(
        forConversationKey conversationKey: String
    ) -> [DesktopConversationTimelineEntryState] {
        desktopPersistedConversationTimelineHistory
            .filter { $0.conversationKey == conversationKey }
            .map(\.entry)
    }

    private func desktopSidebarAutoTitle(for conversationKey: String) -> String? {
        desktopPersistedTimelineEntries(forConversationKey: conversationKey)
            .first(where: \.isUserAuthored)?
            .body
            .replacingOccurrences(of: "\n", with: " ")
            .trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private func desktopSidebarLatestPreview(for conversationKey: String) -> String? {
        desktopPersistedTimelineEntries(forConversationKey: conversationKey)
            .last?
            .body
            .replacingOccurrences(of: "\n", with: " ")
            .trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private func desktopSidebarMetadata(for conversationKey: String) -> DesktopSidebarConversationMetadata {
        desktopSidebarConversationMetadata[conversationKey] ?? .init()
    }

    private func desktopSetSidebarMetadata(
        for conversationKey: String,
        mutate: (inout DesktopSidebarConversationMetadata) -> Void
    ) {
        var metadata = desktopSidebarConversationMetadata[conversationKey] ?? .init()
        mutate(&metadata)
        desktopSidebarConversationMetadata[conversationKey] = metadata
    }

    private func desktopStartSidebarRename(for item: DesktopSidebarConversationItem) {
        let conversationKey = item.conversationKey
        desktopSidebarRenameConversationKey = conversationKey
        desktopSidebarRenameDraft = desktopSidebarHistoryTitle(for: item)
    }

    private func desktopCommitSidebarRename() {
        guard let conversationKey = desktopSidebarRenameConversationKey else {
            return
        }

        let trimmedTitle = desktopSidebarRenameDraft.trimmingCharacters(in: .whitespacesAndNewlines)
        desktopSetSidebarMetadata(for: conversationKey) { metadata in
            metadata.customTitle = trimmedTitle.isEmpty ? nil : trimmedTitle
        }
        desktopSidebarRenameConversationKey = nil
        desktopSidebarRenameDraft = ""
    }

    private func desktopArchiveSidebarConversation(_ item: DesktopSidebarConversationItem) {
        let conversationKey = item.conversationKey
        desktopSetSidebarMetadata(for: conversationKey) { metadata in
            metadata.isArchived = true
        }

        if foregroundObservedSessionSurface?.id == item.surface?.id {
            selectedObservedSessionSurfaceID = currentDominantObservedSessionSurface?.id
        }

        if desktopSelectedPersistedConversationKey == conversationKey {
            desktopSelectedPersistedConversationKey = nil
        }

        if desktopDraftConversationKey == conversationKey {
            desktopDraftConversationKey = nil
        }
    }

    private func desktopDeleteSidebarConversation(_ item: DesktopSidebarConversationItem) {
        let conversationKey = item.conversationKey
        desktopSetSidebarMetadata(for: conversationKey) { metadata in
            metadata.isDeleted = true
        }
        desktopPersistedConversationTimelineHistory.removeAll { $0.conversationKey == conversationKey }

        if foregroundObservedSessionSurface?.id == item.surface?.id {
            selectedObservedSessionSurfaceID = currentDominantObservedSessionSurface?.id
        }

        if desktopSelectedPersistedConversationKey == conversationKey {
            desktopSelectedPersistedConversationKey = nil
        }

        if desktopDraftConversationKey == conversationKey {
            desktopDraftConversationKey = nil
        }
    }

    private func desktopResetLocalConversationForApprovedNewSession() {
        desktopTypedTurnDraft = ""
        desktopTypedTurnPendingRequest = nil
        desktopTypedTurnDispatchInFlightRequestID = nil
        desktopTypedTurnFailedRequest = nil
        desktopSubmittedUserContinuityPreviewState = nil
        desktopCanonicalRuntimeOutcomeState = nil
        desktopAuthoritativeReplyRenderState = nil
        desktopAuthoritativeReplyProvenanceRenderState = nil
        desktopComposerAttachmentSelections = []
        desktopVoiceConversationThreadKey = "desktop_continuous_voice::\(UUID().uuidString)"
        desktopDraftConversationKey = "conversation::draft::\(UUID().uuidString)"
        desktopSelectedPersistedConversationKey = nil
        selectedObservedSessionSurfaceID = nil
        desktopSelectedRecentSessionID = nil
        desktopSidebarSearchQuery = ""
        desktopSidebarSearchIsVisible = false
        explicitVoiceController.discardCurrentVoiceTurn()
    }

    private func desktopStartNewChatFromSidebar() {
        let command = "new conversation"

        switch stageDesktopTypedTurnRequest(
            trimmedDraft: command,
            origin: .newConversationControl
        ) {
        case .none:
            desktopAppendRuntimeBridgeDebugLog(
                "new conversation control staged id=\(desktopTypedTurnPendingRequest?.id ?? "missing")"
            )
            Task { @MainActor in
                await dispatchPreparedTypedTurnRequestIfNeeded()
                await synchronizeDesktopWakeListenerLifecycleState()
            }
        case .emptyDraft:
            return
        case .byteLimit:
            return
        case .pendingRequestActive:
            desktopTypedTurnFailedRequest = InterruptContinuityResponseFailureState(
                id: "failed_new_conversation_control_pending_request",
                title: "Failed new conversation request",
                summary: "The new conversation request could not be produced while another bounded request is already awaiting authoritative response.",
                detail: "The shell does not create a local session boundary while canonical runtime transport is busy."
            )
        case .otherForegroundRequestActive:
            desktopTypedTurnFailedRequest = InterruptContinuityResponseFailureState(
                id: "failed_new_conversation_control_voice_request_active",
                title: "Failed new conversation request",
                summary: "The new conversation request could not be produced while another foreground voice capture or voice-turn dispatch posture was still active.",
                detail: "The shell stays single-request only and does not merge a local session boundary with voice capture or bypass canonical runtime sequencing."
            )
        }
    }

