                    desktopSettingsPanel
                }
            )
        case .liveVoiceProof:
            return AnyView(
                desktopSecondaryPanelSheetContainer(
                    title: "Live Voice E2E Proof",
                    detail: "A bounded native Desktop proof surface for runtime-authoritative live wake and Voice ID posture."
