    private func scheduleDesktopStage6IdleCloseCheckAfterValidEngagement(reason: String) {
        clearDesktopSessionSleepModeIfNeeded(reason: "valid_engagement_\(reason)")
        let deadlineNS = DispatchTime.now().uptimeNanoseconds &+ desktopStage6IdleCloseDelayNS
        scheduleDesktopStage6IdleCloseCheck(deadlineNS: deadlineNS, reason: reason)
    }

    private func clearDesktopSessionSleepModeIfNeeded(reason: String) {
        guard desktopSessionSleepModeActive else {
            return
        }

        desktopSessionSleepModeActive = false
        desktopAppendRuntimeBridgeDebugLog(
            "\(desktopTraceClockFields()) desktop session sleep mode cleared reason=\(boundedFailureLogToken(reason)) authority=valid_committed_engagement"
        )
    }

    private func markDesktopSessionSleepModeActive(
        requestID: String,
        action: DesktopSessionLifecycleAction,
        reason: String
    ) {
        desktopSessionSleepModeActive = true
        desktopAppendRuntimeBridgeDebugLog(
            "\(desktopTraceClockFields()) desktop session sleep mode active id=\(requestID) reason=\(boundedFailureLogToken(reason)) canonical_intent=\(boundedFailureLogToken(action.canonicalIntent)) action=\(boundedFailureLogToken(action.action)) authority=\(boundedFailureLogToken(action.source)) local_wake_ready_required=true"
        )
    }

    private func scheduleDesktopStage6IdleCloseCheck(deadlineNS: UInt64, reason: String) {
        desktopStage6IdleCloseGeneration &+= 1
        desktopStage6IdleCloseDeadlineNS = deadlineNS
        let generation = desktopStage6IdleCloseGeneration
        let boundedReason = boundedFailureLogToken(reason)
        let nowNS = DispatchTime.now().uptimeNanoseconds
        let delayNS = deadlineNS > nowNS ? deadlineNS - nowNS : 0
        desktopAppendRuntimeBridgeDebugLog(
            "\(desktopTraceClockFields()) desktop stage6 idle close check scheduled reason=\(boundedReason) generation=\(generation) delay_ms=\(delayNS / 1_000_000) desktop_decides_session=false ph1l_authority=true"
        )

        Task { @MainActor in
            try? await Task.sleep(nanoseconds: delayNS)
            guard desktopStage6IdleCloseGeneration == generation,
                  desktopStage6IdleCloseDeadlineNS == deadlineNS else {
                desktopAppendRuntimeBridgeDebugLog(
                    "\(desktopTraceClockFields()) desktop stage6 idle close check skipped reason=stale_generation generation=\(generation)"
                )
                return
            }

            await runDesktopStage6IdleCloseCheck(generation: generation, reason: boundedReason)
        }
    }

    private func scheduleDesktopStage6IdleCloseRetryCheck(
        generation: UInt64,
        reason: String
    ) {
        let boundedReason = boundedFailureLogToken(reason)
        Task { @MainActor in
            try? await Task.sleep(nanoseconds: 1_000_000_000)
            guard desktopStage6IdleCloseGeneration == generation else {
                return
            }

            await runDesktopStage6IdleCloseCheck(generation: generation, reason: boundedReason)
        }
    }

    @discardableResult
    private func suspendDesktopStage6IdleCloseCheck(reason: String) -> UInt64? {
        let existingDeadlineNS = desktopStage6IdleCloseDeadlineNS
        guard existingDeadlineNS != nil else {
            return nil
        }

        desktopStage6IdleCloseGeneration &+= 1
        desktopStage6IdleCloseDeadlineNS = nil
        desktopAppendRuntimeBridgeDebugLog(
            "\(desktopTraceClockFields()) desktop stage6 idle close check suspended reason=\(boundedFailureLogToken(reason)) generation=\(desktopStage6IdleCloseGeneration)"
        )
        return existingDeadlineNS
    }

    private func restoreDesktopStage6IdleCloseCheck(
        deadlineNS: UInt64?,
        reason: String
    ) {
        guard let deadlineNS else {
            return
        }

        scheduleDesktopStage6IdleCloseCheck(deadlineNS: deadlineNS, reason: reason)
    }

    private func cancelDesktopStage6IdleCloseCheck(reason: String) {
        guard desktopStage6IdleCloseDeadlineNS != nil else {
            return
        }

        desktopStage6IdleCloseGeneration &+= 1
        desktopStage6IdleCloseDeadlineNS = nil
        desktopAppendRuntimeBridgeDebugLog(
            "\(desktopTraceClockFields()) desktop stage6 idle close check cancelled reason=\(boundedFailureLogToken(reason)) generation=\(desktopStage6IdleCloseGeneration)"
        )
    }

    @MainActor
    private func runDesktopStage6IdleCloseCheck(generation: UInt64, reason: String) async {
        guard desktopStage6IdleCloseGeneration == generation else {
            return
        }

        do {
            let ingressContext = try desktopCanonicalRuntimeBridge
                .desktopSessionIdleCloseCheckRequestBuilder(
                    ttsPlaybackActive: desktopAuthoritativeReplyPlaybackState.phase == .speaking
                        || desktopAuthoritativeReplyPlaybackState.phase == .requesting
                )
            let outcomeState = await desktopCanonicalRuntimeBridge
                .submitDesktopSessionIdleCloseCheck(ingressContext)
            guard desktopStage6IdleCloseGeneration == generation else {
                return
            }

            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) desktop stage6 idle close check outcome=\(outcomeState.outcome ?? "not_provided") reason=\(outcomeState.detail) generation=\(generation) source=\(boundedFailureLogToken(reason))"
            )

            if executeApprovedSessionLifecycleActionIfPresent(
                outcomeState,
                requestID: ingressContext.requestID,
                source: "stage6_idle_close_check"
            ) != nil {
                desktopStage6IdleCloseDeadlineNS = nil
                await synchronizeDesktopWakeListenerLifecycleState()
                return
            }

            if outcomeState.outcome == "SESSION_IDLE_STILL_ACTIVE" {
                scheduleDesktopStage6IdleCloseRetryCheck(
                    generation: generation,
                    reason: "stage6_idle_close_check_retry"
                )
            } else {
                desktopStage6IdleCloseDeadlineNS = nil
            }
        } catch {
            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) desktop stage6 idle close check failed reason=\(boundedFailureLogToken(error.localizedDescription)) source=\(boundedFailureLogToken(reason))"
            )
        }
    }

    private func desktopAttemptResumeComposerVoiceMode(
        stage6IdleCloseReason: String? = nil
    ) {
        if let stage6IdleCloseReason {
            scheduleDesktopStage6IdleCloseCheckAfterValidEngagement(reason: stage6IdleCloseReason)
        }

        guard desktopComposerVoiceModeEnabled,
              !explicitVoiceController.isListening,
              explicitVoiceController.pendingRequest == nil,
              desktopTypedTurnPendingRequest == nil,
              !desktopRealtimeTranscriptionStartInFlight,
              desktopAuthoritativeReplyPlaybackState.phase != .speaking,
              !desktopOpenAITtsSelfEchoGateActive,
              !desktopWakeListenerController.listenerState.isActiveForMicrophone,
              desktopWakeListenerController.listenerState != .dispatching,
              desktopWakeListenerController.pendingRequest == nil,
              lastStagedWakeTriggeredVoiceTurnRequestState == nil else {
            return
        }

        requestDesktopTypedTurnComposerFocus(reason: "composer_voice_mode_resume")
        startDesktopExplicitVoiceTurn()
    }

    private func desktopRealtimeTranscriptionSessionIsUsable(
        _ session: DesktopRealtimeTranscriptionSessionState
    ) -> Bool {
        guard !session.clientSecret.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty,
              !session.websocketURL.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else {
            return false
        }

        guard let expiresAt = session.expiresAt else {
            return true
        }

        let nowSeconds = desktopEpochNowNS() / 1_000_000_000
        return expiresAt > nowSeconds &+ 5
    }

    private func desktopPreparedRealtimeTranscriptionSessionIfUsable()
        -> DesktopRealtimeTranscriptionSessionState? {
        guard let preparedSession = desktopPreparedRealtimeTranscriptionSession,
              desktopRealtimeTranscriptionSessionIsUsable(preparedSession) else {
            desktopPreparedRealtimeTranscriptionSession = nil
            explicitVoiceController.discardPreparedRealtimeTransportIfIdle()
            return nil
        }

        desktopPreparedRealtimeTranscriptionSession = nil
        return preparedSession
    }

    private func cancelDesktopRealtimeTranscriptionPrepareIfNeeded(reason: String) {
        desktopRealtimeTranscriptionPrepareGeneration &+= 1
        desktopRealtimeTranscriptionPrepareInFlight = false
        if desktopPreparedRealtimeTranscriptionSession != nil {
            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) desktop realtime transcription prewarm cleared reason=\(boundedFailureLogToken(reason))"
            )
        }
        desktopPreparedRealtimeTranscriptionSession = nil
        explicitVoiceController.discardPreparedRealtimeTransportIfIdle()
    }

    private func prepareDesktopRealtimeTranscriptionSessionIfNeeded(reason: String) {
        let featureFlagEnabled = DesktopRealtimeTranscriptionFeatureFlag.isEnabled
        guard featureFlagEnabled else {
            return
        }

        if let preparedSession = desktopPreparedRealtimeTranscriptionSession,
           desktopRealtimeTranscriptionSessionIsUsable(preparedSession) {
            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) desktop realtime transcription prewarm skipped reason=already_ready request=\(preparedSession.requestID)"
            )
            return
        }

        guard !desktopRealtimeTranscriptionPrepareInFlight,
              !desktopRealtimeTranscriptionStartInFlight,
              !explicitVoiceController.isListening else {
            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) desktop realtime transcription prewarm skipped reason=busy requested_reason=\(boundedFailureLogToken(reason))"
            )
            return
        }

        desktopPreparedRealtimeTranscriptionSession = nil
        desktopRealtimeTranscriptionPrepareGeneration &+= 1
        let prepareGeneration = desktopRealtimeTranscriptionPrepareGeneration
        desktopRealtimeTranscriptionPrepareInFlight = true
        desktopAppendRuntimeBridgeDebugLog(
            "\(desktopTraceClockFields()) desktop realtime transcription prewarm start reason=\(boundedFailureLogToken(reason))"
        )

        Task { @MainActor in
            defer {
                if desktopRealtimeTranscriptionPrepareGeneration == prepareGeneration {
                    desktopRealtimeTranscriptionPrepareInFlight = false
                }
            }

            do {
                let session = try await desktopCanonicalRuntimeBridge
                    .createDesktopRealtimeTranscriptionSession(
                        featureFlagName: DesktopRealtimeTranscriptionFeatureFlag.name,
                        featureFlagEnabled: true
                    )
                guard desktopRealtimeTranscriptionPrepareGeneration == prepareGeneration else {
                    desktopAppendRuntimeBridgeDebugLog(
                        "\(desktopTraceClockFields()) desktop realtime transcription prewarm stale result discarded request=\(session.requestID)"
                    )
                    return
                }

                desktopPreparedRealtimeTranscriptionSession = session
                desktopAppendRuntimeBridgeDebugLog(
                    "\(desktopTraceClockFields()) desktop realtime transcription prewarm ready request=\(session.requestID) endpoint=\(session.endpoint) model=\(session.transcriptionModel) language_hint_policy=\(session.languageHintPolicy)"
                )
                explicitVoiceController.prepareRealtimeTranscriptionTransport(session: session)
                desktopAttemptResumeComposerVoiceMode()
            } catch {
                guard desktopRealtimeTranscriptionPrepareGeneration == prepareGeneration else {
                    desktopAppendRuntimeBridgeDebugLog(
                        "\(desktopTraceClockFields()) desktop realtime transcription prewarm failure absorbed reason=stale_generation"
                    )
                    return
                }

                desktopPreparedRealtimeTranscriptionSession = nil
                desktopAppendRuntimeBridgeDebugLog(
                    "\(desktopTraceClockFields()) desktop realtime transcription prewarm unavailable reason=token_mint_failure redacted=true requested_reason=\(boundedFailureLogToken(reason))"
                )
                scheduleDesktopComposerVoiceModeResumeAfterPrewarmFailureIfNeeded(reason: reason)
            }
        }
    }

    private func scheduleDesktopComposerVoiceModeResumeAfterPrewarmFailureIfNeeded(reason: String) {
        let boundedReason = boundedFailureLogToken(reason)
        let isPostReplyRearm = boundedReason.hasPrefix("post_wake_instruction")
            || boundedReason.hasPrefix("post_answer")
        guard isPostReplyRearm else {
            return
        }

        Task { @MainActor in
            try? await Task.sleep(nanoseconds: 650_000_000)
            guard desktopComposerVoiceModeEnabled,
                  !explicitVoiceController.isListening,
                  explicitVoiceController.pendingRequest == nil,
                  desktopAuthoritativeReplyPlaybackState.phase != .speaking,
                  !desktopOpenAITtsSelfEchoGateActive else {
                desktopAppendRuntimeBridgeDebugLog(
                    "\(desktopTraceClockFields()) desktop realtime transcription prewarm recovery skipped reason=\(boundedReason)"
                )
                return
            }

            desktopComposerVoiceModeAwaitingReplyPlaybackCompletion = false
            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) desktop realtime transcription prewarm recovery resume reason=\(boundedReason)"
            )
            desktopAttemptResumeComposerVoiceMode()
        }
    }

    private func desktopAttemptResumeComposerVoiceModeAfterUnsafeEvidenceRejection() {
        guard desktopAuthoritativeReplyPlaybackState.phase != .speaking,
              !desktopOpenAITtsSelfEchoGateActive else {
            return
        }

        desktopAppendRuntimeBridgeDebugLog(
            "desktop unsafe voice evidence rearm immediate reason=post_tts_echo_tail_guard_remains_preview_only"
        )
        desktopAttemptResumeComposerVoiceMode()
    }

    private func desktopAttemptResumeComposerVoiceModeAfterTransientRealtimeFailureIfNeeded(
        _ failureID: String?
    ) {
        guard let failureID,
              desktopComposerVoiceModeEnabled,
              [
                  "failed_realtime_transcription_connection",
                  "failed_realtime_transcription_empty_transcript",
                  "failed_realtime_transcription_provider_transcription",
                  "failed_realtime_transcription_provider_error",
                  "failed_realtime_transcription_timeout",
                  "failed_realtime_transcription_session_duration",
              ].contains(failureID) else {
            return
        }

        Task { @MainActor in
            try? await Task.sleep(nanoseconds: 250_000_000)
            guard explicitVoiceController.failedRequest?.id == failureID,
                  desktopComposerVoiceModeEnabled,
                  !explicitVoiceController.isListening,
                  explicitVoiceController.pendingRequest == nil,
                  desktopAuthoritativeReplyPlaybackState.phase != .speaking,
                  !desktopOpenAITtsSelfEchoGateActive else {
                return
            }

            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) desktop realtime transcription transient failure rearm reason=\(boundedFailureLogToken(failureID))"
            )
            desktopAttemptResumeComposerVoiceMode()
        }
    }

