    @MainActor
    private func executeApprovedScreenLifecycleActionIfPresent(
        _ outcomeState: DesktopCanonicalRuntimeOutcomeState,
        requestID: String,
        transcript: String,
        source: String
    ) -> DesktopScreenLifecycleAction? {
        guard let lifecycleAction = outcomeState.screenLifecycleAction else {
            return nil
        }

        guard (lifecycleAction.canonicalIntent == "SCREEN_SHOW" && lifecycleAction.action == "show")
            || (lifecycleAction.canonicalIntent == "SCREEN_HIDE" && lifecycleAction.action == "hide") else {
            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) desktop lifecycle action rejected reason=invalid_runtime_packet id=\(requestID) canonical_intent=\(boundedFailureLogToken(lifecycleAction.canonicalIntent)) action=\(boundedFailureLogToken(lifecycleAction.action))"
            )
            return nil
        }

        desktopAppendRuntimeBridgeDebugLog(
            "\(desktopTraceClockFields()) desktop lifecycle action executing id=\(requestID) source=\(boundedFailureLogToken(source)) canonical_intent=\(lifecycleAction.canonicalIntent) action=\(lifecycleAction.action) authority=\(boundedFailureLogToken(lifecycleAction.source)) evidence=\(boundedFailureLogToken(lifecycleAction.evidence))"
        )
        desktopAuthoritativeReplyRenderState = nil
        desktopAuthoritativeReplyProvenanceRenderState = nil
        desktopAuthoritativeReplyPlaybackController.reset()
        desktopAuthoritativeReplyPlaybackState = .idle
        desktopSubmittedUserContinuityPreviewState = nil
        desktopComposerVoiceModeAwaitingReplyPlaybackCompletion = false
        clearComposerDraftIfItOnlyMirrorsVoiceTranscript(transcript)
        let voiceRearmExpected =
            source != "typed" || desktopTypedTurnShouldResumeComposerVoiceModeAfterReply
        if voiceRearmExpected {
            desktopScreenLifecycleVoiceRearmTransitionInFlight = true
        }
        NotificationCenter.default.post(
            name: .seleneDesktopScreenLifecycleAction,
            object: nil,
            userInfo: [
                "action": lifecycleAction.action,
                "canonical_intent": lifecycleAction.canonicalIntent,
                "source": lifecycleAction.source,
                "evidence": lifecycleAction.evidence,
            ]
        )
        return lifecycleAction
    }

    @MainActor
    private func resumeDesktopVoiceModeAfterApprovedScreenLifecycleAction(
        _ lifecycleAction: DesktopScreenLifecycleAction,
        requestID: String,
        source: String
    ) async {
        desktopAppendRuntimeBridgeDebugLog(
            "\(desktopTraceClockFields()) desktop lifecycle post-action rearm mode=active_instruction_listening id=\(requestID) source=\(boundedFailureLogToken(source)) canonical_intent=\(boundedFailureLogToken(lifecycleAction.canonicalIntent))"
        )
        defer {
            desktopScreenLifecycleVoiceRearmTransitionInFlight = false
        }
        desktopPostWakeInstructionListeningAuthorized = true
        desktopComposerVoiceModeEnabled = true
        desktopComposerVoiceModeAwaitingReplyPlaybackCompletion = false
        desktopWakeAutoStartAttemptedPromptID = nil
        desktopWakeAutoStartSuppressedPromptID = nil
        if lifecycleAction.canonicalIntent == "SCREEN_SHOW" {
            requestDesktopTypedTurnComposerFocus(reason: "screen_lifecycle_show_voice_rearm")
        } else {
            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) desktop composer focus skipped reason=screen_lifecycle_hide_voice_rearm"
            )
        }

        let wakeDispatchInFlight = desktopWakeListenerController.listenerState == .dispatching
        if desktopWakeListenerController.listenerState.isActiveForMicrophone
            || desktopWakeListenerController.pendingRequest != nil
            || lastStagedWakeTriggeredVoiceTurnRequestState != nil {
            desktopWakeListenerController.haltCaptureSession()
            if !wakeDispatchInFlight {
                desktopWakeListenerController.clearPendingPreparedWakeTurn()
                lastStagedWakeTriggeredVoiceTurnRequestState = nil
            }
        }

        startDesktopExplicitVoiceTurn()
    }

    @MainActor
    private func executeApprovedSessionLifecycleActionIfPresent(
        _ outcomeState: DesktopCanonicalRuntimeOutcomeState,
        requestID: String,
        source: String
    ) -> DesktopSessionLifecycleAction? {
        guard let sessionAction = outcomeState.sessionLifecycleAction else {
            return nil
        }

        let validCloseSeal =
            sessionAction.canonicalIntent == "SESSION_CLOSE_SEAL"
            && sessionAction.action == "close_seal"
        let validNewSession =
            sessionAction.canonicalIntent == "SESSION_NEW"
            && sessionAction.action == "new_session"
        guard validCloseSeal || validNewSession else {
            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) desktop session lifecycle action rejected reason=invalid_runtime_packet id=\(requestID) canonical_intent=\(boundedFailureLogToken(sessionAction.canonicalIntent)) action=\(boundedFailureLogToken(sessionAction.action))"
            )
            return nil
        }

        desktopAppendRuntimeBridgeDebugLog(
            "\(desktopTraceClockFields()) desktop session lifecycle action executing id=\(requestID) source=\(boundedFailureLogToken(source)) canonical_intent=\(sessionAction.canonicalIntent) action=\(sessionAction.action) authority=\(boundedFailureLogToken(sessionAction.source)) evidence=\(boundedFailureLogToken(sessionAction.evidence))"
        )
        cancelDesktopStage6IdleCloseCheck(reason: "session_lifecycle_action")
        desktopAuthoritativeReplyRenderState = nil
        desktopAuthoritativeReplyProvenanceRenderState = nil
        desktopAuthoritativeReplyPlaybackController.reset()
        desktopAuthoritativeReplyPlaybackState = .idle
        desktopSubmittedUserContinuityPreviewState = nil
        desktopTypedTurnShouldResumeComposerVoiceModeAfterReply = false
        desktopComposerVoiceModeAwaitingReplyPlaybackCompletion = false
        desktopDeactivateComposerVoiceMode(
            preserveTranscriptPreview: false,
            clearPostWakeAuthorization: true
        )

        if validCloseSeal {
            markDesktopSessionSleepModeActive(
                requestID: requestID,
                action: sessionAction,
                reason: source
            )
            NotificationCenter.default.post(
                name: .seleneDesktopScreenLifecycleAction,
                object: nil,
                userInfo: [
                    "action": "hide",
                    "canonical_intent": sessionAction.canonicalIntent,
                    "source": sessionAction.source,
                    "evidence": sessionAction.evidence,
                ]
            )
        }

        if validNewSession {
            clearDesktopSessionSleepModeIfNeeded(reason: "approved_new_session")
            desktopResetLocalConversationForApprovedNewSession()
        }

        return sessionAction
    }

    private func startDesktopComposerVoiceTurn() {
        let wakeDispatchInFlight = desktopWakeListenerController.listenerState == .dispatching
        desktopWakeListenerController.haltCaptureSession()
        if !wakeDispatchInFlight {
            desktopWakeListenerController.clearPendingPreparedWakeTurn()
            lastStagedWakeTriggeredVoiceTurnRequestState = nil
        }
        desktopCanonicalRuntimeOutcomeState = nil
        desktopAuthoritativeReplyRenderState = nil
        desktopAuthoritativeReplyProvenanceRenderState = nil
        cancelOpenAITtsPlaybackForNewTurn(reason: "new_explicit_voice_turn_started")
        startDesktopExplicitVoiceTurn()
    }

    private func stopDesktopComposerVoiceTurnAndSend() {
        guard !desktopRealtimeTranscriptionStartInFlight else {
            cancelDesktopRealtimeTranscriptionStartIfNeeded()
            return
        }

        let visibleVoiceTranscript = explicitVoiceController.transcriptPreview
            .trimmingCharacters(in: .whitespacesAndNewlines)
        explicitVoiceController.stopCaptureAndPrepareVoiceTurn()
        clearComposerDraftIfItOnlyMirrorsVoiceTranscript(visibleVoiceTranscript)
    }

    private func startDesktopExplicitVoiceTurn() {
        let featureFlagEnabled = DesktopRealtimeTranscriptionFeatureFlag.isEnabled
        desktopAppendRuntimeBridgeDebugLog(
            "\(desktopTraceClockFields()) desktop realtime transcription flag name=\(DesktopRealtimeTranscriptionFeatureFlag.name) enabled=\(featureFlagEnabled)"
        )
        guard featureFlagEnabled else {
            desktopAppendRuntimeBridgeDebugLog(
                "desktop realtime transcription unavailable reason=feature_flag_off local_stt_fallback=false"
            )
            explicitVoiceController.startExplicitVoiceTurn()
            return
        }

        if let preparedSession = desktopPreparedRealtimeTranscriptionSessionIfUsable() {
            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) desktop realtime transcription prewarm consumed request=\(preparedSession.requestID)"
            )
            explicitVoiceController.startRealtimeTranscriptionVoiceTurn(
                session: preparedSession,
                evidenceContext: desktopCurrentAudioEvidenceContext()
            )
            return
        }

        if desktopRealtimeTranscriptionPrepareInFlight {
            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) desktop realtime transcription start deferred reason=prewarm_in_flight"
            )
            return
        }

        guard !desktopRealtimeTranscriptionStartInFlight else {
            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) desktop realtime transcription start skipped reason=start_in_flight"
            )
            return
        }

        desktopRealtimeTranscriptionStartGeneration &+= 1
        let startGeneration = desktopRealtimeTranscriptionStartGeneration
        desktopRealtimeTranscriptionStartInFlight = true
        desktopAppendRuntimeBridgeDebugLog(
            "\(desktopTraceClockFields()) desktop realtime transcription token mint start reason=foreground_capture_start"
        )
        Task { @MainActor in
            defer {
                if desktopRealtimeTranscriptionStartGeneration == startGeneration {
                    desktopRealtimeTranscriptionStartInFlight = false
                }
            }

            do {
                let session = try await desktopCanonicalRuntimeBridge
                    .createDesktopRealtimeTranscriptionSession(
                        featureFlagName: DesktopRealtimeTranscriptionFeatureFlag.name,
                        featureFlagEnabled: true
                    )
                desktopAppendRuntimeBridgeDebugLog(
                    "\(desktopTraceClockFields()) desktop realtime transcription token mint ok request=\(session.requestID) endpoint=\(session.endpoint) model=\(session.transcriptionModel) language_hint_policy=\(session.languageHintPolicy)"
                )
                guard desktopRealtimeTranscriptionStartGeneration == startGeneration,
                      desktopRealtimeTranscriptionStartInFlight else {
                    desktopAppendRuntimeBridgeDebugLog(
                        "\(desktopTraceClockFields()) desktop realtime transcription start cancelled before capture"
                    )
                    return
                }
                explicitVoiceController.startRealtimeTranscriptionVoiceTurn(
                    session: session,
                    evidenceContext: desktopCurrentAudioEvidenceContext()
                )
            } catch {
                guard desktopRealtimeTranscriptionStartGeneration == startGeneration,
                      desktopRealtimeTranscriptionStartInFlight else {
                    desktopAppendRuntimeBridgeDebugLog(
                        "\(desktopTraceClockFields()) desktop realtime transcription start cancellation absorbed token_mint_failure"
                    )
                    return
                }
                desktopAppendRuntimeBridgeDebugLog(
                    "\(desktopTraceClockFields()) desktop realtime transcription unavailable reason=token_mint_failure redacted=true local_stt_fallback=false"
                )
                explicitVoiceController.startExplicitVoiceTurn()
            }
        }
    }

    private func cancelDesktopRealtimeTranscriptionStartIfNeeded() {
        cancelDesktopRealtimeTranscriptionPrepareIfNeeded(reason: "foreground_start_cancelled")
        guard desktopRealtimeTranscriptionStartInFlight else {
            return
        }

        desktopRealtimeTranscriptionStartGeneration &+= 1
        desktopRealtimeTranscriptionStartInFlight = false
        desktopAppendRuntimeBridgeDebugLog(
            "\(desktopTraceClockFields()) desktop realtime transcription start cancelled by user before capture"
        )
    }

    private func clearComposerDraftIfItOnlyMirrorsVoiceTranscript(_ transcript: String) {
        let normalizedTranscript = transcript.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalizedTranscript.isEmpty,
              desktopTypedTurnDraft.trimmingCharacters(in: .whitespacesAndNewlines) == normalizedTranscript else {
            return
        }

        desktopTypedTurnDraft = ""
    }

    private func toggleDesktopComposerVoiceMode() {
        if desktopComposerVoiceModeEnabled {
            desktopDeactivateComposerVoiceMode(preserveTranscriptPreview: true)
        } else {
            desktopActivateComposerVoiceMode()
        }
    }

