        HStack(alignment: .top, spacing: 0) {
            Spacer(minLength: 116)

            Text(body)
                .font(.system(size: 16, weight: .regular))
                .lineSpacing(3)
                .textSelection(.enabled)
                .foregroundStyle(.primary)
                .padding(.horizontal, 18)
                .padding(.vertical, 13)
                .background(Color(nsColor: NSColor(srgbRed: 0.946, green: 0.946, blue: 0.938, alpha: 1.0)))
                .clipShape(RoundedRectangle(cornerRadius: 18, style: .continuous))
                .frame(maxWidth: 560, alignment: .trailing)
                .fixedSize(horizontal: false, vertical: true)
        }
        .frame(maxWidth: .infinity, alignment: .trailing)
    }

    private func desktopConversationSeleneOpenResponse(
        _ entry: DesktopConversationTimelineEntryState
    ) -> some View {
        VStack(alignment: .leading, spacing: 12) {
            if desktopConversationShouldAttachAuthoritativeReplyArtifacts(to: entry),
               let completionTimingLabel = desktopAuthoritativeReplyRenderState?.completionTimingLabel {
                Text(completionTimingLabel)
                    .font(.system(size: 13, weight: .regular))
                    .foregroundStyle(Color.secondary.opacity(0.72))
            }

            desktopConversationStructuredResponseText(entry.body)

            if desktopConversationShouldAttachAuthoritativeReplyArtifacts(to: entry),
               let sourceChips = desktopAuthoritativeReplyProvenanceRenderState?.sourceChips,
               !sourceChips.isEmpty {
                desktopCompactSourceChipGrid(sourceChips)
            }
        }
        .frame(maxWidth: 760, alignment: .leading)
        .padding(.vertical, 6)
        .frame(maxWidth: .infinity, alignment: .leading)
    }

    private func desktopConversationStructuredResponseText(_ body: String) -> some View {
        let blocks = desktopConversationDisplayBlocks(from: body)

        return VStack(alignment: .leading, spacing: 10) {
            ForEach(Array(blocks.enumerated()), id: \.offset) { _, block in
                desktopConversationDisplayBlockView(block)
            }
        }
        .textSelection(.enabled)
    }

    @ViewBuilder
    private func desktopConversationDisplayBlockView(
        _ block: DesktopConversationDisplayBlock
    ) -> some View {
        switch block.kind {
        case .heading(let level):
            desktopConversationMarkdownText(block.text)
                .font(.system(size: level <= 1 ? 23 : 19, weight: .semibold))
                .lineSpacing(4)
                .frame(maxWidth: .infinity, alignment: .leading)

        case .paragraph:
            desktopConversationMarkdownText(block.text)
                .font(.system(size: 16, weight: .regular))
                .lineSpacing(4)
                .frame(maxWidth: .infinity, alignment: .leading)

        case .bullet:
            HStack(alignment: .firstTextBaseline, spacing: 9) {
                Text("•")
                    .font(.system(size: 16, weight: .semibold))
                    .foregroundStyle(Color.primary.opacity(0.72))

                desktopConversationMarkdownText(block.text)
                    .font(.system(size: 16, weight: .regular))
                    .lineSpacing(4)
                    .frame(maxWidth: .infinity, alignment: .leading)
            }

        case .numbered(let prefix):
            HStack(alignment: .firstTextBaseline, spacing: 9) {
                Text(prefix)
                    .font(.system(size: 16, weight: .semibold))
                    .foregroundStyle(Color.primary.opacity(0.72))
                    .frame(minWidth: 26, alignment: .trailing)

                desktopConversationMarkdownText(block.text)
                    .font(.system(size: 16, weight: .regular))
                    .lineSpacing(4)
                    .frame(maxWidth: .infinity, alignment: .leading)
            }
        }
    }

    private func desktopConversationMarkdownText(_ text: String) -> Text {
        if let attributedText = try? AttributedString(markdown: text) {
            return Text(attributedText)
        }

        return Text(text)
    }

    private func desktopConversationDisplayBlocks(
        from body: String
    ) -> [DesktopConversationDisplayBlock] {
        let normalizedBody = body.replacingOccurrences(of: "\r\n", with: "\n")
        var blocks: [DesktopConversationDisplayBlock] = []
        var pendingParagraphLines: [String] = []

        func flushParagraph() {
            let paragraph = pendingParagraphLines
                .joined(separator: "\n")
                .trimmingCharacters(in: .whitespacesAndNewlines)
            pendingParagraphLines.removeAll()
            guard !paragraph.isEmpty else {
                return
            }

            blocks.append(
                DesktopConversationDisplayBlock(kind: .paragraph, text: paragraph)
            )
        }

        for rawLine in normalizedBody.split(separator: "\n", omittingEmptySubsequences: false) {
            let line = String(rawLine)
            let trimmedLine = line.trimmingCharacters(in: .whitespacesAndNewlines)

            guard !trimmedLine.isEmpty else {
                flushParagraph()
                continue
            }

            if let heading = desktopConversationMarkdownHeading(from: trimmedLine) {
                flushParagraph()
                blocks.append(
                    DesktopConversationDisplayBlock(
                        kind: .heading(level: heading.level),
                        text: heading.text
                    )
                )
                continue
            }

            if let bullet = desktopConversationMarkdownBullet(from: trimmedLine) {
                flushParagraph()
                blocks.append(
                    DesktopConversationDisplayBlock(kind: .bullet, text: bullet)
                )
                continue
            }

            if let numbered = desktopConversationMarkdownNumberedLine(from: trimmedLine) {
                flushParagraph()
                blocks.append(
                    DesktopConversationDisplayBlock(
                        kind: .numbered(prefix: numbered.prefix),
                        text: numbered.text
                    )
                )
                continue
            }

            pendingParagraphLines.append(line)
        }

        flushParagraph()
        if blocks.isEmpty {
            return [
                DesktopConversationDisplayBlock(
                    kind: .paragraph,
                    text: body.trimmingCharacters(in: .whitespacesAndNewlines)
                ),
            ]
        }

        return blocks
    }

    private func desktopConversationMarkdownHeading(
        from trimmedLine: String
    ) -> (level: Int, text: String)? {
        let markerCount = trimmedLine.prefix { $0 == "#" }.count
        guard markerCount > 0, markerCount <= 3 else {
            return nil
        }

        let remainder = trimmedLine.dropFirst(markerCount)
        guard remainder.first == " " else {
            return nil
        }

        let text = remainder.dropFirst()
            .trimmingCharacters(in: .whitespacesAndNewlines)
        guard !text.isEmpty else {
            return nil
        }

        return (markerCount, text)
    }

    private func desktopConversationMarkdownBullet(
        from trimmedLine: String
    ) -> String? {
        for marker in ["- ", "* ", "• "] where trimmedLine.hasPrefix(marker) {
            let text = String(trimmedLine.dropFirst(marker.count))
                .trimmingCharacters(in: .whitespacesAndNewlines)
            return text.isEmpty ? nil : text
        }

        return nil
    }

    private func desktopConversationMarkdownNumberedLine(
        from trimmedLine: String
    ) -> (prefix: String, text: String)? {
        let digitPrefix = trimmedLine.prefix { $0.isNumber }
        guard !digitPrefix.isEmpty else {
            return nil
        }

        let remainder = trimmedLine.dropFirst(digitPrefix.count)
        guard let separator = remainder.first,
              separator == "." || separator == ")",
              remainder.dropFirst().first == " " else {
            return nil
        }

        let text = remainder.dropFirst(2)
            .trimmingCharacters(in: .whitespacesAndNewlines)
        guard !text.isEmpty else {
            return nil
        }

        return ("\(digitPrefix)\(separator)", text)
    }

    private var desktopConversationInlineThinkingPlaceholder: some View {
        DesktopInlineThinkingShimmerText(label: desktopConversationInlineProgressLabel)
        .padding(.vertical, 6)
        .frame(maxWidth: 760, alignment: .leading)
        .frame(maxWidth: .infinity, alignment: .leading)
    }

    private func desktopConversationShouldShowInlineThinking(
        for state: DesktopConversationPrimaryPaneState
    ) -> Bool {
        guard desktopForegroundSelectionShowsCurrentDominantSurface,
              state.dominantPosture != "SESSION_SUSPENDED_VISIBLE",
              state.dominantPosture != "QUARANTINED_LOCAL_STATE" else {
            return false
        }

        let hasFinalAnswerText = desktopAuthoritativeReplyRenderState?.authoritativeResponseText?
            .trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false
        guard !hasFinalAnswerText,
              !desktopConversationTimelineHasSeleneResponseAfterLatestUserTurn(state.timelineEntries) else {
            return false
        }

        return desktopCanonicalRuntimeOutcomeState?.phase == .dispatching
            || desktopTypedTurnDispatchInFlightRequestID != nil
            || desktopWakeTriggeredDispatchInFlightRequestID != nil
            || (desktopVoiceAnswerPresentationPendingRequestID != nil
                && desktopAuthoritativeReplyPlaybackState.phase == .requesting)
            || (desktopTypedTurnPendingRequest != nil && state.timelineEntries.contains(where: \.isUserAuthored))
    }

    private func desktopConversationTimelineHasSeleneResponseAfterLatestUserTurn(
        _ timelineEntries: [DesktopConversationTimelineEntryState]
    ) -> Bool {
        var foundSeleneResponse = false

        for entry in timelineEntries.reversed() {
            if entry.isUserAuthored {
                return foundSeleneResponse
            }

            if entry.body.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false {
                foundSeleneResponse = true
            }
        }

        return foundSeleneResponse
    }

    private func desktopConversationShouldSuppressDedicatedAuthoritativeReplyTextEntry(
        _ timelineEntries: [DesktopConversationTimelineEntryState],
        authoritativeResponseText: String
    ) -> Bool {
        let normalizedAuthoritativeResponseText = desktopConversationNormalizedSubmittedUserText(
            authoritativeResponseText
        )
        guard !normalizedAuthoritativeResponseText.isEmpty else {
            return false
        }

        return timelineEntries.contains { entry in
            let normalizedEntryBody = desktopConversationNormalizedSubmittedUserText(entry.body)
            guard !normalizedEntryBody.isEmpty,
                  normalizedEntryBody == normalizedAuthoritativeResponseText
                    || normalizedEntryBody.contains(normalizedAuthoritativeResponseText)
                    || normalizedAuthoritativeResponseText.contains(normalizedEntryBody) else {
                return false
            }

            return entry.posture == "authoritative_reply_text"
                || entry.posture == "current_selene_turn_text"
                || entry.posture == "archived_selene_turn_text"
        }
    }

    private func desktopConversationNormalizedSubmittedUserText(_ text: String) -> String {
        text.split(whereSeparator: { $0.isWhitespace }).joined(separator: " ")
    }

    private func desktopConversationTimelineContainsSubmittedUserText(
        _ timelineEntries: [DesktopConversationTimelineEntryState],
        candidateText: String
    ) -> Bool {
        let normalizedCandidateText = desktopConversationNormalizedSubmittedUserText(candidateText)
        guard !normalizedCandidateText.isEmpty else {
            return false
        }

        return timelineEntries.contains { entry in
            guard entry.isUserAuthored,
                  desktopConversationNormalizedSubmittedUserText(entry.body) == normalizedCandidateText else {
                return false
            }

            return entry.posture == "current_user_turn_text"
                || entry.posture == "archived_user_turn_text"
                || entry.posture == "typed_turn_submitted_continuity"
                || entry.posture == "explicit_voice_submitted_continuity"
                || entry.sourceSurface == "SESSION_ACTIVE_VISIBLE"
                || entry.sourceSurface == "SESSION_SOFT_CLOSED_VISIBLE"
                || entry.sourceSurface == "KEYBOARD_TYPED_TURN_SUBMITTED"
                || entry.sourceSurface == "EXPLICIT_VOICE_SUBMITTED"
        }
    }

    private func desktopConversationTimelineEntryIsTransientSubmittedUserText(
        _ entry: DesktopConversationTimelineEntryState
    ) -> Bool {
        entry.posture == "current_user_turn_text"
            || entry.posture == "archived_user_turn_text"
            || entry.posture == "typed_turn_submitted_continuity"
            || entry.posture == "explicit_voice_submitted_continuity"
            || entry.posture == "explicit_voice_live_preview"
            || entry.posture == "wake_voice_live_preview"
            || entry.posture == "explicit_voice_pending_preview"
            || entry.posture == "wake_voice_pending_preview"
            || entry.posture == "typed_turn_pending_preview"
            || entry.sourceSurface == "SESSION_ACTIVE_VISIBLE"
            || entry.sourceSurface == "SESSION_SOFT_CLOSED_VISIBLE"
            || entry.sourceSurface == "KEYBOARD_TYPED_TURN_SUBMITTED"
            || entry.sourceSurface == "EXPLICIT_VOICE_SUBMITTED"
            || entry.sourceSurface == "EXPLICIT_VOICE_LISTENING"
            || entry.sourceSurface == "WAKE_TRIGGERED_VOICE_LISTENING"
            || entry.sourceSurface == "EXPLICIT_VOICE_PENDING"
            || entry.sourceSurface == "WAKE_TRIGGERED_VOICE_PENDING"
    }

    private func desktopConversationTimelineEntriesSuppressingDuplicateTransientUserText(
        _ timelineEntries: [DesktopConversationTimelineEntryState]
    ) -> [DesktopConversationTimelineEntryState] {
        var visibleUserTexts = Set<String>()
        var filteredEntries: [DesktopConversationTimelineEntryState] = []

        for entry in timelineEntries {
            let normalizedBody = desktopConversationNormalizedSubmittedUserText(entry.body)
            if entry.isUserAuthored,
               !normalizedBody.isEmpty,
               desktopConversationTimelineEntryIsTransientSubmittedUserText(entry),
               visibleUserTexts.contains(normalizedBody) {
                continue
            }

            filteredEntries.append(entry)

            if entry.isUserAuthored, !normalizedBody.isEmpty {
                visibleUserTexts.insert(normalizedBody)
            }
        }

        return filteredEntries
    }

    private func desktopConversationTimelineEntriesRenderSameTurn(
        _ lhs: DesktopConversationTimelineEntryState,
        _ rhs: DesktopConversationTimelineEntryState
    ) -> Bool {
        guard lhs.speaker == rhs.speaker else {
            return false
        }

        let lhsBody = desktopConversationNormalizedSubmittedUserText(lhs.body)
        let rhsBody = desktopConversationNormalizedSubmittedUserText(rhs.body)
        guard !lhsBody.isEmpty, lhsBody == rhsBody else {
            return false
        }

        if lhs.isUserAuthored {
            return desktopConversationTimelineEntryIsTransientSubmittedUserText(lhs)
                || desktopConversationTimelineEntryIsTransientSubmittedUserText(rhs)
        }

        return desktopConversationTimelineEntryIsSessionReplyText(lhs)
            || desktopConversationTimelineEntryIsSessionReplyText(rhs)
    }

    private func desktopConversationTimelineEntryIsSessionReplyText(
        _ entry: DesktopConversationTimelineEntryState
    ) -> Bool {
        entry.posture == "current_selene_turn_text"
            || entry.posture == "archived_selene_turn_text"
            || entry.sourceSurface == "SESSION_ACTIVE_VISIBLE"
            || entry.sourceSurface == "SESSION_SOFT_CLOSED_VISIBLE"
    }

    private func desktopConversationShouldSuppressSupportRailArchivedRecentSliceTranscript() -> Bool {
        guard desktopReadyTimeHandoffIsActive,
              foregroundSessionSuspendedVisibleContext == nil,
              activeRecoveryDisplayState != .quarantinedLocalState,
              foregroundSessionSoftClosedVisibleContext != nil,
              let timelineEntries = desktopOperationalConversationShellState?.primaryPaneState.timelineEntries else {
            return false
        }

        return timelineEntries.contains(where: { $0.posture == "archived_user_turn_text" })
            && timelineEntries.contains(where: { $0.posture == "archived_selene_turn_text" })
    }

    private func desktopConversationShouldSuppressSupportRailCurrentSessionTranscript() -> Bool {
        guard desktopReadyTimeHandoffIsActive,
              foregroundSessionSuspendedVisibleContext == nil,
              activeRecoveryDisplayState != .quarantinedLocalState,
              foregroundSessionActiveVisibleContext != nil,
              let timelineEntries = desktopOperationalConversationShellState?.primaryPaneState.timelineEntries else {
            return false
        }

        return timelineEntries.contains(where: { $0.posture == "current_user_turn_text" })
            && timelineEntries.contains(where: { $0.posture == "current_selene_turn_text" })
    }

    private func desktopConversationShouldAttachAuthoritativeReplyArtifacts(
        to entry: DesktopConversationTimelineEntryState
    ) -> Bool {
        guard let authoritativeResponseText = desktopAuthoritativeReplyRenderState?.authoritativeResponseText?
            .trimmingCharacters(in: .whitespacesAndNewlines),
            !authoritativeResponseText.isEmpty else {
            return false
        }

        let normalizedEntryBody = entry.body.trimmingCharacters(in: .whitespacesAndNewlines)
        return entry.posture == "authoritative_reply_text"
            || (entry.posture == "current_selene_turn_text"
                && normalizedEntryBody == authoritativeResponseText)
            || (entry.posture == "archived_selene_turn_text"
                && normalizedEntryBody == authoritativeResponseText)
    }

