    private func playAuthoritativeReply() {
        Task { @MainActor in
            await playCurrentAuthoritativeReply()
        }
    }

    @MainActor
    private func playRuntimeAuthoritativeReply(
        outcomeState: DesktopCanonicalRuntimeOutcomeState,
        revealAuthoritativeReplyForVoicePlayback: (() -> Void)? = nil
    ) async -> Bool {
        guard let authoritativeTTSOutputText = outcomeState.authoritativeTTSOutputText?
            .trimmingCharacters(in: .whitespacesAndNewlines),
              !authoritativeTTSOutputText.isEmpty else {
            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) desktop openai tts skipped reason=runtime_tts_text_empty request=\(outcomeState.requestID)"
            )
            return false
        }

        return await playAuthoritativeReplyViaOpenAITTS(
            authoritativeResponseText: authoritativeTTSOutputText,
            sessionID: outcomeState.sessionID,
            turnID: outcomeState.turnID,
            runtimeRequestID: outcomeState.requestID,
            revealAuthoritativeReplyForVoicePlayback: revealAuthoritativeReplyForVoicePlayback
        )
    }

    @MainActor
    private func playCurrentAuthoritativeReply() async {
        guard let authoritativeResponseText = desktopAuthoritativeReplyRenderState?.authoritativeResponseText?
            .trimmingCharacters(in: .whitespacesAndNewlines),
              !authoritativeResponseText.isEmpty else {
            desktopAuthoritativeReplyPlaybackState = desktopAuthoritativeReplyPlaybackController
                .failClosedWithoutNativePlayback(
                    authoritativeResponseText: desktopAuthoritativeReplyRenderState?.authoritativeResponseText,
                    fallbackReason: "missing_completed_runtime_outcome_for_openai_tts"
                )
            return
        }

        await playManualAuthoritativeReply(authoritativeResponseText)
    }

    @MainActor
    private func playManualAuthoritativeReply(_ authoritativeResponseText: String) async {
        let trimmedAuthoritativeResponseText = authoritativeResponseText
            .trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmedAuthoritativeResponseText.isEmpty else {
            return
        }

        _ = await playAuthoritativeReplyViaOpenAITTS(
            authoritativeResponseText: trimmedAuthoritativeResponseText,
            sessionID: nil,
            turnID: nil,
            runtimeRequestID: "desktop_manual_openai_tts_replay_\(UUID().uuidString)"
        )
    }

    @MainActor
    private func playAuthoritativeReplyViaOpenAITTS(
        authoritativeResponseText: String,
        sessionID: String?,
        turnID: String?,
        runtimeRequestID: String?,
        revealAuthoritativeReplyForVoicePlayback: (() -> Void)? = nil
    ) async -> Bool {
        guard !authoritativeResponseText.isEmpty else {
            return false
        }
        desktopOpenAITtsPlaybackReferenceText = authoritativeResponseText

        guard DesktopOpenAITtsFeatureFlag.isEnabled else {
            desktopOpenAITtsPlaybackGeneration &+= 1
            desktopAppendRuntimeBridgeDebugLog(
                "desktop openai tts unavailable reason=feature_flag_off native_macos_tts=false fallback_attempted=false"
            )
            revealAuthoritativeReplyForVoicePlayback?()
            desktopAuthoritativeReplyPlaybackState = desktopAuthoritativeReplyPlaybackController
                .failClosedWithoutNativePlayback(
                    authoritativeResponseText: authoritativeResponseText,
                    fallbackReason: "feature_flag_off"
                )
            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) desktop openai tts failed_closed phase=\(desktopAuthoritativeReplyPlaybackState.phase.rawValue) reason=feature_flag_off native_macos_tts=false fallback_counted_as_success=false"
            )
            releaseDesktopOpenAITtsSelfEchoGateAfterCooldown(reason: "openai_tts_feature_flag_off")
            return false
        }

        desktopOpenAITtsPlaybackGeneration &+= 1
        let playbackGeneration = desktopOpenAITtsPlaybackGeneration
        let answerTextSHA256 = desktopSessionSHA256Hex(Data(authoritativeResponseText.utf8))
        let ttsRequestStartedNS = Swift.max(DispatchTime.now().uptimeNanoseconds, 1)
        let token = DesktopOpenAITtsPlaybackToken(
            ttsRequestID: nil,
            sessionID: sessionID,
            turnID: turnID,
            runtimeRequestID: runtimeRequestID,
            answerTextSHA256: answerTextSHA256
        )
        desktopAuthoritativeReplyPlaybackState = desktopAuthoritativeReplyPlaybackController
            .prepareOpenAITTS(authoritativeResponseText: authoritativeResponseText, token: token)
        desktopAppendRuntimeBridgeDebugLog(
            "\(desktopTraceClockFields()) desktop openai tts state=TTS_REQUESTING runtime_thinking=false tts_request_pending=true answer_ready=true tts_provider_id=\(DesktopVoiceProviderLane.ttsProviderID) endpoint=\(desktopCanonicalRuntimeBridge.desktopOpenAITtsSpeechEndpoint) answer_text_sha256=\(answerTextSHA256)"
        )
        rearmDesktopVoiceModeWhileOpenAITtsIsPendingIfNeeded()

        do {
            let speechState = try await desktopCanonicalRuntimeBridge.createDesktopOpenAITtsSpeech(
                responseText: authoritativeResponseText,
                sessionID: sessionID,
                turnID: turnID,
                runtimeRequestID: runtimeRequestID,
                featureFlagName: DesktopOpenAITtsFeatureFlag.name,
                featureFlagEnabled: true,
                voice: nil,
                format: "mp3"
            )
            guard desktopOpenAITtsPlaybackGeneration == playbackGeneration else {
                desktopAppendRuntimeBridgeDebugLog(
                    "desktop openai tts stale audio discarded reason=newer_turn_started audio_sha256=\(speechState.audioSHA256)"
                )
                releaseDesktopOpenAITtsSelfEchoGateAfterCooldown(reason: "stale_audio_discarded")
                return false
            }
            let ttsReadyNS = Swift.max(DispatchTime.now().uptimeNanoseconds, 1)
            let ttsLatencyMS = ttsReadyNS > ttsRequestStartedNS
                ? (ttsReadyNS - ttsRequestStartedNS) / 1_000_000
                : 0
            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) desktop openai tts state=TTS_READY latency_ms=\(ttsLatencyMS) tts_provider_id=\(DesktopVoiceProviderLane.ttsProviderID) model=\(speechState.model) voice=\(speechState.voice) answer_text_sha256=\(speechState.answerTextSHA256) audio_sha256=\(speechState.audioSHA256) audio_byte_len=\(speechState.audioByteLen) ai_voice_disclosure=\(speechState.aiVoiceDisclosure)"
            )
            beginDesktopOpenAITtsSelfEchoGate(reason: "openai_tts_playback_start")
            pauseDesktopVoiceCaptureForOpenAITtsPlaybackIfNeeded()
            desktopAuthoritativeReplyPlaybackState = desktopAuthoritativeReplyPlaybackController
                .playOpenAITTS(speechState, expectedToken: token)
            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) desktop openai tts state=PLAYING_OPENAI playback_started=\(desktopAuthoritativeReplyPlaybackState.phase == .speaking) tts_provider_id=\(DesktopVoiceProviderLane.ttsProviderID) fallback_used=false request=\(speechState.requestID)"
            )
            if desktopAuthoritativeReplyPlaybackState.phase == .speaking {
                revealAuthoritativeReplyForVoicePlayback?()
            } else {
                releaseDesktopOpenAITtsSelfEchoGateAfterCooldown(reason: "playback_not_started")
            }
            return desktopAuthoritativeReplyPlaybackState.phase == .speaking
        } catch let ttsFailure as DesktopOpenAITtsSpeechFailure {
            guard desktopOpenAITtsPlaybackGeneration == playbackGeneration else {
                desktopAppendRuntimeBridgeDebugLog(
                    "desktop openai tts request failure absorbed reason=newer_turn_started"
                )
                releaseDesktopOpenAITtsSelfEchoGateAfterCooldown(reason: "request_failure_absorbed")
                return false
            }
            let ttsFailedNS = Swift.max(DispatchTime.now().uptimeNanoseconds, 1)
            let ttsLatencyMS = ttsFailedNS > ttsRequestStartedNS
                ? (ttsFailedNS - ttsRequestStartedNS) / 1_000_000
                : 0
            let fallbackReason = boundedFailureLogToken(ttsFailure.reason)
            desktopAppendRuntimeBridgeDebugLog(
                "desktop openai tts unavailable latency_ms=\(ttsLatencyMS) reason=\(fallbackReason) runtime_fallback_allowed=\(ttsFailure.fallbackAllowed)"
            )
            revealAuthoritativeReplyForVoicePlayback?()
            desktopAuthoritativeReplyPlaybackState = desktopAuthoritativeReplyPlaybackController
                .failClosedWithoutNativePlayback(
                    authoritativeResponseText: authoritativeResponseText,
                    fallbackReason: fallbackReason
                )
            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) desktop openai tts failed_closed phase=\(desktopAuthoritativeReplyPlaybackState.phase.rawValue) reason=\(fallbackReason) runtime_fallback_allowed=false native_macos_tts=false fallback_counted_as_success=false"
            )
            releaseDesktopOpenAITtsSelfEchoGateAfterCooldown(reason: "openai_tts_request_failed")
            return false
        } catch {
            guard desktopOpenAITtsPlaybackGeneration == playbackGeneration else {
                desktopAppendRuntimeBridgeDebugLog(
                    "desktop openai tts request failure absorbed reason=newer_turn_started"
                )
                releaseDesktopOpenAITtsSelfEchoGateAfterCooldown(reason: "request_failure_absorbed")
                return false
            }
            let ttsFailedNS = Swift.max(DispatchTime.now().uptimeNanoseconds, 1)
            let ttsLatencyMS = ttsFailedNS > ttsRequestStartedNS
                ? (ttsFailedNS - ttsRequestStartedNS) / 1_000_000
                : 0
            let fallbackReason = boundedFailureLogToken(error.localizedDescription)
            desktopAppendRuntimeBridgeDebugLog(
                "desktop openai tts unavailable latency_ms=\(ttsLatencyMS) reason=\(fallbackReason) runtime_fallback_allowed=false"
            )
            revealAuthoritativeReplyForVoicePlayback?()
            desktopAuthoritativeReplyPlaybackState = desktopAuthoritativeReplyPlaybackController
                .failClosedWithoutNativePlayback(
                    authoritativeResponseText: authoritativeResponseText,
                    fallbackReason: fallbackReason
                )
            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) desktop openai tts failed_closed phase=\(desktopAuthoritativeReplyPlaybackState.phase.rawValue) reason=\(fallbackReason) runtime_fallback_allowed=false native_macos_tts=false fallback_counted_as_success=false"
            )
            releaseDesktopOpenAITtsSelfEchoGateAfterCooldown(reason: "openai_tts_request_failed")
            return false
        }
    }

    private func desktopCurrentAudioEvidenceContext() -> DesktopAudioEvidenceContext {
        DesktopAudioEvidenceContext(
            ttsPlaybackActiveAtCaptureStart: desktopAuthoritativeReplyPlaybackState.phase == .speaking,
            ttsPlaybackStartedNS: desktopOpenAITtsPlaybackMostRecentStartedNS,
            lastTtsPlaybackEndedNS: desktopOpenAITtsPlaybackLastEndedNS,
            ttsPlaybackReferenceText: desktopOpenAITtsPlaybackReferenceText
        )
    }

    private func updateDesktopOpenAITtsPlaybackEvidenceClock(
        _ playbackState: DesktopAuthoritativeReplyPlaybackState
    ) {
        let nowNS = Swift.max(DispatchTime.now().uptimeNanoseconds, 1)
        if playbackState.phase == .speaking {
            if desktopOpenAITtsPlaybackActiveSinceNS == nil {
                desktopOpenAITtsPlaybackActiveSinceNS = nowNS
                desktopOpenAITtsPlaybackMostRecentStartedNS = nowNS
            }
            explicitVoiceController.updateActiveAudioEvidenceContext(desktopCurrentAudioEvidenceContext())
            desktopWakeListenerController.updateActiveAudioEvidenceContext(desktopCurrentAudioEvidenceContext())
            return
        }

        if desktopOpenAITtsPlaybackActiveSinceNS != nil {
            desktopOpenAITtsPlaybackLastEndedNS = nowNS
            desktopOpenAITtsPlaybackActiveSinceNS = nil
        }
        explicitVoiceController.updateActiveAudioEvidenceContext(desktopCurrentAudioEvidenceContext())
        desktopWakeListenerController.updateActiveAudioEvidenceContext(desktopCurrentAudioEvidenceContext())
    }

    private func rearmDesktopVoiceModeWhileOpenAITtsIsPendingIfNeeded() {
        guard desktopComposerVoiceModeEnabled
                || desktopPostWakeInstructionListeningAuthorized
                || desktopComposerVoiceModeAwaitingReplyPlaybackCompletion else {
            return
        }

        desktopComposerVoiceModeEnabled = true
        desktopComposerVoiceModeAwaitingReplyPlaybackCompletion = true
        desktopAppendRuntimeBridgeDebugLog(
            "\(desktopTraceClockFields()) desktop voice rearm prewarm_only reason=answer_text_ready_audio_pending active_capture_waits_for_playback_end"
        )
        prepareDesktopRealtimeTranscriptionSessionIfNeeded(
            reason: "openai_tts_request_pending_voice_rearm"
        )
    }

    private func pauseDesktopVoiceCaptureForOpenAITtsPlaybackIfNeeded() {
        let shouldResumeAfterPlayback =
            desktopComposerVoiceModeEnabled
            || desktopPostWakeInstructionListeningAuthorized
            || desktopComposerVoiceModeAwaitingReplyPlaybackCompletion
            || explicitVoiceController.isListening
            || desktopRealtimeTranscriptionStartInFlight
            || desktopRealtimeTranscriptionPrepareInFlight

        guard shouldResumeAfterPlayback else {
            return
        }

        desktopComposerVoiceModeEnabled = true
        desktopComposerVoiceModeAwaitingReplyPlaybackCompletion = true
        if desktopRealtimeTranscriptionStartInFlight || explicitVoiceController.isListening {
            cancelDesktopRealtimeTranscriptionStartIfNeeded()
        } else if desktopRealtimeTranscriptionPrepareInFlight
                    || desktopPreparedRealtimeTranscriptionSession != nil {
            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) desktop voice prewarm preserved reason=openai_tts_playback_self_echo_guard active_audio_stream=false"
            )
        }
        if explicitVoiceController.isListening {
            explicitVoiceController.discardCurrentVoiceTurn()
        }

        let wakeDispatchInFlight = desktopWakeListenerController.listenerState == .dispatching
        if desktopWakeListenerController.listenerState.isActiveForMicrophone
            || desktopWakeListenerController.pendingRequest != nil
            || lastStagedWakeTriggeredVoiceTurnRequestState != nil {
            desktopWakeListenerController.haltCaptureSession()
            if !wakeDispatchInFlight {
                desktopWakeListenerController.clearPendingPreparedWakeTurn()
                lastStagedWakeTriggeredVoiceTurnRequestState = nil
            }
        }

        desktopAppendRuntimeBridgeDebugLog(
            "\(desktopTraceClockFields()) desktop voice capture paused reason=openai_tts_playback_self_echo_guard rearm_after_playback=true"
        )
    }

    private func beginDesktopOpenAITtsSelfEchoGate(reason: String) {
        desktopOpenAITtsSelfEchoGateGeneration &+= 1
        desktopOpenAITtsSelfEchoGateActive = true
        desktopAppendRuntimeBridgeDebugLog(
            "\(desktopTraceClockFields()) desktop voice self echo gate active=true reason=\(boundedFailureLogToken(reason)) capture_mode=evidence_gated_duplex"
        )
    }

    private func releaseDesktopOpenAITtsSelfEchoGateAfterCooldown(reason: String) {
        desktopOpenAITtsSelfEchoGateGeneration &+= 1
        let releaseGeneration = desktopOpenAITtsSelfEchoGateGeneration
        guard desktopAuthoritativeReplyPlaybackState.phase != .speaking,
              desktopAuthoritativeReplyPlaybackState.phase != .requesting else {
            return
        }

        desktopAppendRuntimeBridgeDebugLog(
            "\(desktopTraceClockFields()) desktop voice self echo gate release scheduled reason=\(boundedFailureLogToken(reason)) release=post_tts_echo_tail_guard delay_ms=\(Int(desktopOpenAITtsSelfEchoTailReleaseDelay * 1_000))"
        )

        let shouldScheduleIdleCloseAfterPlaybackRearm =
            desktopComposerVoiceModeAwaitingReplyPlaybackCompletion

        if desktopComposerVoiceModeAwaitingReplyPlaybackCompletion || desktopComposerVoiceModeEnabled {
            desktopComposerVoiceModeAwaitingReplyPlaybackCompletion = false
            desktopTypedTurnShouldResumeComposerVoiceModeAfterReply = false
            if desktopOpenAITtsSelfEchoGateActive {
                desktopAppendRuntimeBridgeDebugLog(
                    "\(desktopTraceClockFields()) desktop voice composer rearm pending reason=post_tts_echo_tail_guard"
                )
            } else {
                desktopAppendRuntimeBridgeDebugLog(
                    "\(desktopTraceClockFields()) desktop voice composer rearm immediate reason=no_active_tts_echo_gate"
                )
                desktopAttemptResumeComposerVoiceMode(
                    stage6IdleCloseReason: shouldScheduleIdleCloseAfterPlaybackRearm
                        ? "post_tts_playback_rearm"
                        : nil
                )
            }
        }

        DispatchQueue.main.asyncAfter(deadline: .now() + desktopOpenAITtsSelfEchoTailReleaseDelay) {
            guard desktopOpenAITtsSelfEchoGateGeneration == releaseGeneration,
                  desktopAuthoritativeReplyPlaybackState.phase != .speaking,
                  desktopAuthoritativeReplyPlaybackState.phase != .requesting else {
                return
            }

            desktopOpenAITtsSelfEchoGateActive = false
            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) desktop voice self echo gate active=false reason=\(boundedFailureLogToken(reason)) release=post_tts_echo_tail_guard"
            )
            Task { @MainActor in
                await synchronizeDesktopWakeListenerLifecycleState()
            }

            guard desktopComposerVoiceModeEnabled,
                  !explicitVoiceController.isListening,
                  explicitVoiceController.pendingRequest == nil,
                  desktopAuthoritativeReplyPlaybackState.phase != .speaking,
                  desktopAuthoritativeReplyPlaybackState.phase != .requesting else {
                return
            }

            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) desktop voice composer rearm after_echo_gate_release reason=\(boundedFailureLogToken(reason))"
            )
            desktopAttemptResumeComposerVoiceMode(
                stage6IdleCloseReason: shouldScheduleIdleCloseAfterPlaybackRearm
                    ? "post_tts_echo_gate_rearm"
                    : nil
            )
        }
    }

    private func cancelOpenAITtsPlaybackForNewTurn(reason: String) {
        desktopOpenAITtsPlaybackGeneration &+= 1
        desktopOpenAITtsSelfEchoGateGeneration &+= 1
        desktopOpenAITtsSelfEchoGateActive = false
        desktopComposerVoiceModeAwaitingReplyPlaybackCompletion = false
        desktopAppendRuntimeBridgeDebugLog(
            "desktop openai tts playback cancelled reason=\(boundedFailureLogToken(reason))"
        )
        updateDesktopOpenAITtsPlaybackEvidenceClock(.idle)
        desktopAuthoritativeReplyPlaybackController.reset()
        desktopAuthoritativeReplyPlaybackState = .idle
    }

    private func stopAuthoritativeReplyPlayback() {
        desktopOpenAITtsPlaybackGeneration &+= 1
        desktopAuthoritativeReplyPlaybackState = desktopAuthoritativeReplyPlaybackController.stop()
        releaseDesktopOpenAITtsSelfEchoGateAfterCooldown(reason: "manual_stop")
    }

