    @MainActor
    private func dispatchPreparedExplicitVoiceRequestIfNeeded() async {
        guard let pendingRequest = explicitVoiceController.pendingRequest else {
            return
        }

        let conversationKey = desktopForegroundConversationHistoryKey
        var shouldAwaitVoiceModeReplyPlaybackCompletion = false
        var suspendedStage6IdleCloseDeadlineNS: UInt64?

        do {
            if let wakePrefixMatch = boundedWakePrefixMatch(
                in: pendingRequest.transcript,
                wakeTriggerPhrase: "Selene"
            ),
                wakePrefixMatch.transcriptRemainder
                    .trimmingCharacters(in: .whitespacesAndNewlines)
                    .isEmpty {
                await handleLifecycleOnlyWakeFromExplicitCapture(
                    requestID: pendingRequest.id,
                    transcript: pendingRequest.transcript
                )
                return
            }

            if desktopWakeListenerController.stageWakeTriggeredVoiceTurnFromExplicitCapture(
                transcript: pendingRequest.transcript,
                audioCaptureRefState: pendingRequest.audioCaptureRefState
            ) {
                desktopAppendRuntimeBridgeDebugLog(
                    "\(desktopTraceClockFields()) explicit voice wake transcript routed_to=wake_triggered_bridge id=\(pendingRequest.id)"
                )
                clearComposerDraftIfItOnlyMirrorsVoiceTranscript(pendingRequest.transcript)
                await dispatchPreparedWakeTriggeredVoiceRequestIfNeeded()
                explicitVoiceController.clearPendingPreparedVoiceTurn()
                return
            }

            let ingressContext = try desktopCanonicalRuntimeBridge.desktopExplicitVoiceIngressRequestBuilder(
                pendingRequest,
                threadKey: desktopForegroundVoiceTurnMatchingSelectedThreadKey,
                authorityStatePolicyContextRef: desktopForegroundVoiceTurnActiveAuthorityPolicyContextRef,
                projectID: desktopForegroundVoiceTurnSelectedProjectID,
                pinnedContextRefs: desktopForegroundVoiceTurnSelectedPinnedContextRefs
            )
            suspendedStage6IdleCloseDeadlineNS = suspendDesktopStage6IdleCloseCheck(
                reason: "potential_explicit_voice_engagement"
            )
            desktopCanonicalRuntimeOutcomeState = .dispatching(
                preparedRequestID: ingressContext.preparedRequestID,
                endpoint: ingressContext.endpoint,
                requestID: ingressContext.requestID
            )
            desktopAuthoritativeReplyRenderState = nil
            desktopAuthoritativeReplyProvenanceRenderState = nil
            cancelOpenAITtsPlaybackForNewTurn(reason: "explicit_voice_runtime_dispatch_started")
            desktopBeginVoiceAnswerPresentationTiming(requestID: pendingRequest.id)

            let outcomeState = await desktopCanonicalRuntimeBridge.dispatchPreparedExplicitVoiceRequest(ingressContext)
            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) explicit voice dispatch outcome id=\(pendingRequest.id) phase=\(outcomeState.phase.rawValue) next_move=\(outcomeState.nextMove ?? "not_provided") reason=\(outcomeState.reasonCode ?? "not_provided")"
            )
            guard explicitVoiceController.pendingRequest?.id == pendingRequest.id else {
                desktopClearVoiceAnswerPresentationTiming(requestID: pendingRequest.id)
                return
            }

            desktopCanonicalRuntimeOutcomeState = outcomeState
            let runtimeIgnoredUnsafeVoiceTranscript =
                desktopRuntimeIgnoredUnsafeVoiceTranscript(outcomeState)
            if let screenLifecycleAction = executeApprovedScreenLifecycleActionIfPresent(
                outcomeState,
                requestID: pendingRequest.id,
                transcript: pendingRequest.transcript,
                source: "explicit_voice"
            ) {
                restoreDesktopStage6IdleCloseCheck(
                    deadlineNS: suspendedStage6IdleCloseDeadlineNS,
                    reason: "screen_lifecycle_does_not_reset_session_idle"
                )
                desktopClearVoiceAnswerPresentationTiming(requestID: pendingRequest.id)
                explicitVoiceController.clearPendingPreparedVoiceTurn()
                await resumeDesktopVoiceModeAfterApprovedScreenLifecycleAction(
                    screenLifecycleAction,
                    requestID: pendingRequest.id,
                    source: "explicit_voice"
                )
                return
            }
            if executeApprovedSessionLifecycleActionIfPresent(
                outcomeState,
                requestID: pendingRequest.id,
                source: "explicit_voice"
            ) != nil {
                desktopClearVoiceAnswerPresentationTiming(requestID: pendingRequest.id)
                explicitVoiceController.clearPendingPreparedVoiceTurn()
                await synchronizeDesktopWakeListenerLifecycleState()
                return
            }
            if !runtimeIgnoredUnsafeVoiceTranscript {
                desktopSubmittedUserContinuityPreviewState = DesktopSubmittedUserContinuityPreviewState(
                    requestID: pendingRequest.id,
                    inputMode: .explicitVoice,
                    text: pendingRequest.transcript
                )
                desktopPersistSubmittedUserContinuityIfNeeded(
                    requestID: pendingRequest.id,
                    inputMode: .explicitVoice,
                    text: pendingRequest.transcript,
                    conversationKey: conversationKey
                )
            }
            desktopSubmittedUserContinuityPreviewState = nil
            if outcomeState.phase == .completed {
                if runtimeIgnoredUnsafeVoiceTranscript {
                    desktopAuthoritativeReplyRenderState = nil
                    desktopAuthoritativeReplyProvenanceRenderState = nil
                    desktopClearVoiceAnswerPresentationTiming(requestID: pendingRequest.id)
                    explicitVoiceController.clearTransientTranscriptPreview()
                    restoreDesktopStage6IdleCloseCheck(
                        deadlineNS: suspendedStage6IdleCloseDeadlineNS,
                        reason: "unsafe_voice_transcript_does_not_reset_session_idle"
                    )
                } else {
                    if outcomeState.authoritativeResponseText?
                        .trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false {
                        let revealAuthoritativeReplyForVoicePlayback = {
                            desktopRevealAuthoritativeReply(
                                outcomeState: outcomeState,
                                requestID: pendingRequest.id,
                                conversationKey: conversationKey,
                                missingReplySummary: "The canonical runtime completed without reply text for this bounded explicit voice turn.",
                                presentReplySummary: "Read-only canonical reply text from the completed runtime dispatch is now visible here while the shell remains explicitly non-authoritative.",
                                missingProvenanceSummary: "The canonical runtime completed without provenance for this bounded explicit voice turn.",
                                presentProvenanceSummary: "Read-only canonical provenance from the completed runtime dispatch is now visible here while the shell remains explicitly non-authoritative.",
                                completionTimingLabel: desktopVoiceAnswerThoughtDurationLabel(
                                    requestID: pendingRequest.id
                                )
                            )
                            desktopClearVoiceAnswerPresentationTiming(requestID: pendingRequest.id)
                        }
                        _ = await playRuntimeAuthoritativeReply(
                            outcomeState: outcomeState,
                            revealAuthoritativeReplyForVoicePlayback: revealAuthoritativeReplyForVoicePlayback
                        )
                        shouldAwaitVoiceModeReplyPlaybackCompletion =
                            desktopComposerVoiceModeEnabled
                            && desktopAuthoritativeReplyPlaybackState.phase == .speaking
                    } else {
                        desktopClearVoiceAnswerPresentationTiming(requestID: pendingRequest.id)
                        desktopPersistMissingReplyMessageIfNeeded(
                            requestID: pendingRequest.id,
                            inputMode: .explicitVoice,
                            conversationKey: conversationKey
                        )
                    }
                }
            } else {
                desktopAuthoritativeReplyRenderState = nil
                desktopAuthoritativeReplyProvenanceRenderState = nil
                desktopClearVoiceAnswerPresentationTiming(requestID: pendingRequest.id)
                desktopPersistRuntimeFailureReplyIfNeeded(
                    requestID: pendingRequest.id,
                    summary: outcomeState.summary,
                    reasonCode: outcomeState.reasonCode,
                    failureClass: outcomeState.failureClass,
                    detail: outcomeState.detail,
                    conversationKey: conversationKey
                )
            }
            clearComposerDraftIfItOnlyMirrorsVoiceTranscript(pendingRequest.transcript)
            explicitVoiceController.clearPendingPreparedVoiceTurn()
            if shouldAwaitVoiceModeReplyPlaybackCompletion {
                desktopComposerVoiceModeAwaitingReplyPlaybackCompletion = true
                prepareDesktopRealtimeTranscriptionSessionIfNeeded(
                    reason: "post_answer_await_tts_idle"
                )
                desktopAppendRuntimeBridgeDebugLog(
                    "\(desktopTraceClockFields()) desktop composer voice rearm deferred reason=await_tts_idle next_move=\(outcomeState.nextMove ?? "not_provided")"
                )
            } else {
                desktopComposerVoiceModeAwaitingReplyPlaybackCompletion = false
                desktopAttemptResumeComposerVoiceMode(
                    stage6IdleCloseReason: runtimeIgnoredUnsafeVoiceTranscript
                        ? nil
                        : "post_answer_explicit_voice_rearm"
                )
            }
        } catch {
            restoreDesktopStage6IdleCloseCheck(
                deadlineNS: suspendedStage6IdleCloseDeadlineNS,
                reason: "explicit_voice_bridge_failure_does_not_reset_session_idle"
            )
            desktopCanonicalRuntimeOutcomeState = .failed(
                preparedRequestID: pendingRequest.id,
                endpoint: desktopCanonicalRuntimeBridge.voiceTurnEndpoint,
                requestID: "unavailable",
                summary: "The canonical runtime bridge could not stage the bounded explicit voice request for dispatch.",
                detail: error.localizedDescription,
                reasonCode: "desktop_runtime_bridge_failure",
                failureClass: "RetryableRuntime"
            )
            desktopAuthoritativeReplyRenderState = nil
            desktopAuthoritativeReplyProvenanceRenderState = nil
            desktopClearVoiceAnswerPresentationTiming(requestID: pendingRequest.id)
            cancelOpenAITtsPlaybackForNewTurn(reason: "explicit_voice_runtime_dispatch_failed")
            desktopSubmittedUserContinuityPreviewState = DesktopSubmittedUserContinuityPreviewState(
                requestID: pendingRequest.id,
                inputMode: .explicitVoice,
                text: pendingRequest.transcript
            )
            desktopPersistSubmittedUserContinuityIfNeeded(
                requestID: pendingRequest.id,
                inputMode: .explicitVoice,
                text: pendingRequest.transcript,
                conversationKey: conversationKey
            )
            desktopSubmittedUserContinuityPreviewState = nil
            desktopPersistRuntimeFailureReplyIfNeeded(
                requestID: pendingRequest.id,
                summary: "The canonical runtime bridge could not deliver the bounded explicit voice request.",
                reasonCode: "desktop_runtime_bridge_failure",
                failureClass: "RetryableRuntime",
                detail: error.localizedDescription,
                conversationKey: conversationKey
            )
            clearComposerDraftIfItOnlyMirrorsVoiceTranscript(pendingRequest.transcript)
            explicitVoiceController.clearPendingPreparedVoiceTurn()
            desktopAttemptResumeComposerVoiceMode()
        }
    }

    @MainActor
    private func dispatchPreparedWakeTriggeredVoiceRequestIfNeeded() async {
        guard let pendingRequest = desktopWakeListenerController.pendingRequest else {
            return
        }
        guard desktopWakeTriggeredDispatchInFlightRequestID != pendingRequest.id else {
            return
        }

        desktopWakeTriggeredDispatchInFlightRequestID = pendingRequest.id
        defer {
            if desktopWakeTriggeredDispatchInFlightRequestID == pendingRequest.id {
                desktopWakeTriggeredDispatchInFlightRequestID = nil
            }
        }

        let conversationKey = desktopForegroundConversationHistoryKey
        var suspendedStage6IdleCloseDeadlineNS: UInt64?

        do {
            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) wake dispatch start id=\(pendingRequest.id)"
            )
            let ingressContext = try desktopCanonicalRuntimeBridge
                .desktopWakeTriggeredVoiceIngressRequestBuilder(
                    pendingRequest,
                    threadKey: desktopForegroundVoiceTurnMatchingSelectedThreadKey,
                    authorityStatePolicyContextRef: desktopForegroundVoiceTurnActiveAuthorityPolicyContextRef,
                    projectID: desktopForegroundVoiceTurnSelectedProjectID,
                    pinnedContextRefs: desktopForegroundVoiceTurnSelectedPinnedContextRefs
                )
            suspendedStage6IdleCloseDeadlineNS = suspendDesktopStage6IdleCloseCheck(
                reason: "potential_wake_triggered_voice_engagement"
            )
            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) wake dispatch built ingress id=\(pendingRequest.id) endpoint=\(ingressContext.endpoint)"
            )
            lastStagedWakeTriggeredVoiceTurnRequestState = pendingRequest
            desktopWakeListenerController.markDispatching()
            desktopCanonicalRuntimeOutcomeState = .dispatchingWake(
                preparedRequestID: ingressContext.preparedRequestID,
                endpoint: ingressContext.endpoint,
                requestID: ingressContext.requestID
            )
            desktopAuthoritativeReplyRenderState = nil
            desktopAuthoritativeReplyProvenanceRenderState = nil
            desktopAuthoritativeReplyPlaybackController.reset()
            desktopAuthoritativeReplyPlaybackState = .idle
            if let pendingVoiceAnswerRequestID = desktopVoiceAnswerPresentationPendingRequestID {
                desktopClearVoiceAnswerPresentationTiming(requestID: pendingVoiceAnswerRequestID)
            }
            desktopBeginVoiceAnswerPresentationTiming(requestID: pendingRequest.id)

            let outcomeState = await desktopCanonicalRuntimeBridge
                .dispatchPreparedWakeTriggeredVoiceRequest(ingressContext)
            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) wake dispatch outcome id=\(pendingRequest.id) phase=\(outcomeState.phase.rawValue) next_move=\(outcomeState.nextMove ?? "not_provided") reason=\(outcomeState.reasonCode ?? "not_provided")"
            )
            guard desktopWakeListenerController.pendingRequest?.id == pendingRequest.id else {
                desktopClearVoiceAnswerPresentationTiming(requestID: pendingRequest.id)
                return
            }

            let runtimeIgnoredUnsafeVoiceTranscript =
                desktopRuntimeIgnoredUnsafeVoiceTranscript(outcomeState)
            let wakeAcceptedListeningWindow =
                outcomeState.phase == .completed
                && outcomeState.nextMove == "listening_window_open"
            let shouldStartPostWakeInstructionListening =
                wakeAcceptedListeningWindow
                && (
                    pendingRequest.transcript.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
                    || runtimeIgnoredUnsafeVoiceTranscript
                )
            desktopCanonicalRuntimeOutcomeState = outcomeState
            if let screenLifecycleAction = executeApprovedScreenLifecycleActionIfPresent(
                outcomeState,
                requestID: pendingRequest.id,
                transcript: pendingRequest.transcript,
                source: "wake_triggered_voice"
            ) {
                restoreDesktopStage6IdleCloseCheck(
                    deadlineNS: suspendedStage6IdleCloseDeadlineNS,
                    reason: "screen_lifecycle_does_not_reset_session_idle"
                )
                desktopClearVoiceAnswerPresentationTiming(requestID: pendingRequest.id)
                desktopWakeListenerController.clearPendingPreparedWakeTurn()
                lastStagedWakeTriggeredVoiceTurnRequestState = nil
                await resumeDesktopVoiceModeAfterApprovedScreenLifecycleAction(
                    screenLifecycleAction,
                    requestID: pendingRequest.id,
                    source: "wake_triggered_voice"
                )
                return
            }
            if executeApprovedSessionLifecycleActionIfPresent(
                outcomeState,
                requestID: pendingRequest.id,
                source: "wake_triggered_voice"
            ) != nil {
                desktopClearVoiceAnswerPresentationTiming(requestID: pendingRequest.id)
                desktopWakeListenerController.clearPendingPreparedWakeTurn()
                lastStagedWakeTriggeredVoiceTurnRequestState = nil
                await synchronizeDesktopWakeListenerLifecycleState()
                return
            }
            if !runtimeIgnoredUnsafeVoiceTranscript {
                desktopPersistSubmittedUserContinuityIfNeeded(
                    requestID: pendingRequest.id,
                    inputMode: .explicitVoice,
                    text: pendingRequest.transcript,
                    conversationKey: conversationKey
                )
            }
            if outcomeState.phase == .completed {
                if runtimeIgnoredUnsafeVoiceTranscript {
                    desktopAuthoritativeReplyRenderState = nil
                    desktopAuthoritativeReplyProvenanceRenderState = nil
                    desktopClearVoiceAnswerPresentationTiming(requestID: pendingRequest.id)
                    restoreDesktopStage6IdleCloseCheck(
                        deadlineNS: suspendedStage6IdleCloseDeadlineNS,
                        reason: "unsafe_wake_transcript_does_not_reset_session_idle"
                    )
                } else {
                    if outcomeState.authoritativeResponseText?
                        .trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false {
                        let revealAuthoritativeReplyForVoicePlayback = {
                            desktopRevealAuthoritativeReply(
                                outcomeState: outcomeState,
                                requestID: pendingRequest.id,
                                conversationKey: conversationKey,
                                missingReplySummary: "The canonical runtime completed without reply text for this bounded wake-triggered voice turn.",
                                presentReplySummary: "Read-only canonical reply text from the completed wake-triggered runtime dispatch is now visible here while the shell remains explicitly non-authoritative.",
                                missingProvenanceSummary: "The canonical runtime completed without provenance for this bounded wake-triggered voice turn.",
                                presentProvenanceSummary: "Read-only canonical provenance from the completed wake-triggered runtime dispatch is now visible here while the shell remains explicitly non-authoritative.",
                                completionTimingLabel: desktopVoiceAnswerThoughtDurationLabel(
                                    requestID: pendingRequest.id
                                )
                            )
                            desktopClearVoiceAnswerPresentationTiming(requestID: pendingRequest.id)
                        }
                        _ = await playRuntimeAuthoritativeReply(
                            outcomeState: outcomeState,
                            revealAuthoritativeReplyForVoicePlayback: revealAuthoritativeReplyForVoicePlayback
                        )
                    } else {
                        desktopClearVoiceAnswerPresentationTiming(requestID: pendingRequest.id)
                    }
                }
            } else {
                desktopAuthoritativeReplyRenderState = nil
                desktopAuthoritativeReplyProvenanceRenderState = nil
                desktopClearVoiceAnswerPresentationTiming(requestID: pendingRequest.id)
                desktopPersistRuntimeFailureReplyIfNeeded(
                    requestID: pendingRequest.id,
                    summary: outcomeState.summary,
                    reasonCode: outcomeState.reasonCode,
                    failureClass: outcomeState.failureClass,
                    detail: outcomeState.detail,
                    conversationKey: conversationKey
                )
            }
            desktopWakeListenerController.clearPendingPreparedWakeTurn()
            lastStagedWakeTriggeredVoiceTurnRequestState = nil
            if shouldStartPostWakeInstructionListening {
                startPostWakeInstructionListeningAfterGreeting()
            } else if !wakeAcceptedListeningWindow
                        && pendingRequest.transcript
                            .trimmingCharacters(in: .whitespacesAndNewlines)
                            .isEmpty {
                desktopAppendRuntimeBridgeDebugLog(
                    "\(desktopTraceClockFields()) desktop post-wake instruction listening blocked reason=ph1w_wake_not_accepted phase=\(outcomeState.phase.rawValue) next_move=\(outcomeState.nextMove ?? "not_provided") runtime_reason=\(outcomeState.reasonCode ?? "not_provided")"
                )
            } else if outcomeState.phase == .completed,
                      !runtimeIgnoredUnsafeVoiceTranscript {
                desktopComposerVoiceModeEnabled = true
                if desktopAuthoritativeReplyPlaybackState.phase == .speaking {
                    desktopComposerVoiceModeAwaitingReplyPlaybackCompletion = true
                    prepareDesktopRealtimeTranscriptionSessionIfNeeded(
                        reason: "post_answer_wake_voice_await_tts_idle"
                    )
                } else {
                    desktopComposerVoiceModeAwaitingReplyPlaybackCompletion = false
                    desktopAttemptResumeComposerVoiceMode(
                        stage6IdleCloseReason: "post_answer_wake_voice_rearm"
                    )
                }
            }
        } catch {
            restoreDesktopStage6IdleCloseCheck(
                deadlineNS: suspendedStage6IdleCloseDeadlineNS,
                reason: "wake_triggered_bridge_failure_does_not_reset_session_idle"
            )
            desktopAppendRuntimeBridgeDebugLog(
                "wake dispatch catch id=\(pendingRequest.id) error=\(error.localizedDescription)"
            )
            desktopCanonicalRuntimeOutcomeState = .failedWake(
                preparedRequestID: pendingRequest.id,
                endpoint: desktopCanonicalRuntimeBridge.voiceTurnEndpoint,
                requestID: "unavailable",
                summary: "The canonical runtime bridge could not stage the bounded wake-triggered voice request for dispatch.",
                detail: error.localizedDescription,
                reasonCode: "desktop_runtime_bridge_failure",
                failureClass: "RetryableRuntime"
            )
            desktopAuthoritativeReplyRenderState = nil
            desktopAuthoritativeReplyProvenanceRenderState = nil
            desktopAuthoritativeReplyPlaybackController.reset()
            desktopAuthoritativeReplyPlaybackState = .idle
            desktopClearVoiceAnswerPresentationTiming(requestID: pendingRequest.id)
            desktopWakeListenerController.clearPendingPreparedWakeTurn()
            lastStagedWakeTriggeredVoiceTurnRequestState = nil
            desktopAppendRuntimeBridgeDebugLog(
                "\(desktopTraceClockFields()) desktop post-wake instruction listening blocked reason=wake_dispatch_error_no_ph1w_acceptance"
            )
        }
    }

    @MainActor
    private func handleLifecycleOnlyWakeFromExplicitCapture(
        requestID: String,
        transcript: String
    ) async {
        desktopAppendRuntimeBridgeDebugLog(
            "\(desktopTraceClockFields()) explicit voice bare wake consumed_as=lifecycle_only id=\(requestID)"
        )
        desktopAppendRuntimeBridgeDebugLog(
            "\(desktopTraceClockFields()) explicit voice bare wake silent_rearm=true id=\(requestID)"
