        switch stageDesktopTypedTurnRequest(
            trimmedDraft: trimmedDraft,
            origin: .toolRequestCard
        ) {
        case .none:
            desktopToolRequestDraft = ""
        case .emptyDraft:
            return
        case .byteLimit:
            desktopToolRequestFailedRequest = InterruptContinuityResponseFailureState(
